/* =========================
   VOICE DURATION CAP (60s after speech-start)
========================= */

/**
 * Clear any pending voice-duration timer. Always safe to call; no-op if
 * the timer was never armed.
 */
function clearVoiceMaxDurationTimer() {
  if (voiceMaxDurationTimerId != null) {
    try { clearTimeout(voiceMaxDurationTimerId); } catch (_) {}
    voiceMaxDurationTimerId = null;
  }
  voiceSpeechStartedAt = 0;
}

/**
 * Arm the 60s post-speech-start cap exactly once per utterance. Safe to
 * call from every spot where `hasSpoken` flips to true (browser ASR
 * partial / MediaRecorder VAD speech-frame); subsequent calls during the
 * same utterance are no-ops.
 *
 * When the timer fires it gracefully stops whichever recorder is alive:
 *   - For browser SpeechRecognition continuous: lets the current partial
 *     turn finalize via the normal end-of-utterance scheduling so a
 *     substantive transcript is not lost. If there is no transcript yet,
 *     just stops the recognizer and shows the duration bubble.
 *   - For MediaRecorder: calls `.stop()` which routes through the normal
 *     `handleUtterance` upload path, then shows the bubble.
 *
 * The fallback bubble appears at most once per ~5s to avoid duplicates
 * when both paths happen to be alive.
 */
function armVoiceMaxDurationTimer(reason) {
  if (voiceMaxDurationTimerId != null) return; // already armed
  voiceSpeechStartedAt = Date.now();
  const ms = Math.max(
    5000,
    Number(VERA_SAFETY_LIMITS.voiceMaxDurationAfterSpeechSec) * 1000
  );
  try {
    console.info("[voice_speech_started]", {
      reason: String(reason || "first_partial"),
      max_duration_sec: VERA_SAFETY_LIMITS.voiceMaxDurationAfterSpeechSec
    });
  } catch (_) {}
  voiceMaxDurationTimerId = setTimeout(() => {
    voiceMaxDurationTimerId = null;
    handleVoiceMaxDurationLimit();
  }, ms);
}

function handleVoiceMaxDurationLimit() {
  const now = Date.now();
  // Burst guard — only one fallback per 5s even if both pipes trip.
  if (now - voiceMaxDurationLastFiredAt < 5000) return;
  voiceMaxDurationLastFiredAt = now;
  try {
    console.warn("[voice_duration_limit]", {
      reason: "voice_duration_limit",
      mode: isVeraWorkModeOn?.() ? "work_mode" : "non_work",
      feature: "voice",
      max_duration_sec: VERA_SAFETY_LIMITS.voiceMaxDurationAfterSpeechSec
    });
  } catch (_) {}

  // 1) Try to stop the Web Speech recognizer cleanly, preserving any
  //    accumulated transcript so the normal /infer flow can still run.
  let webStopped = false;
  try {
    if (typeof mainBrowserRecognition !== "undefined" && mainBrowserRecognition) {
      try { mainBrowserRecognition.stop(); } catch (_) {
        try { mainBrowserRecognition.abort(); } catch (_) {}
      }
      webStopped = true;
    }
  } catch (_) {}

  // 2) Stop active MediaRecorder so its `onstop` fires `handleUtterance`.
  let mediaStopped = false;
  try {
    if (typeof mediaRecorder !== "undefined" && mediaRecorder &&
        mediaRecorder.state === "recording") {
      try { mediaRecorder.stop(); } catch (_) {}
      mediaStopped = true;
    }
  } catch (_) {}

  // 3) Reset wave / listening UI so the strip cannot appear stuck.
  try {
    listening = false;
    processing = false;
    waveState = "idle";
    if (typeof updateMuteInputButton === "function") updateMuteInputButton();
    setStatus("Ready", "idle");
  } catch (_) {}

  /* 4) Bubble — keep wording exactly to spec; voice + work-mode both show
        this in the conversation strip (not inside the reasoning panel).
        Skip if no recorder was actually stopped: the recording session
        must have ended cleanly while the timer was still scheduled (e.g.
        normal silence-stop landed milliseconds before the cap fired). */
  if (webStopped || mediaStopped) {
    veraShowCapabilityFailureBubble(
      "voice_duration_limit",
      VERA_SAFETY_LIMITS.messages.voiceDurationLimit,
      { minIntervalMs: 5000 }
    );
  }
  clearVoiceMaxDurationTimer();
}

let listening = false;
let processing = false;
let rafId = null;
/** `startListening` no-speech watchdog; must be cleared when switching to PTT or the new recorder gets stopped. */
let speechWaitTimeoutId = null;
let interruptSpeechFrames = 0;
let interruptSpeechStart = 0;
/** Ms of speechLike time accumulated from RAF deltas (gaps do not add). */
let interruptSpeechAccumMs = 0;
let lastInterruptDetectTime = 0;
let interruptLastSpeechLikeTime = 0;
/** Snapshot from detectInterrupt when interruptSpeech() fires (for server interrupt_debug). */
let lastInterruptProbe = null;
/** Last frame where speechLike was true (same as trigger frame when interrupt fires). */
let lastInterruptSpeechLikeSnapshot = null;
/** Throttled VAD samples for mobile interrupt debug panel. */
let lastMobileVadSampleLogAt = 0;
const MOBILE_VAD_SAMPLE_INTERVAL_MS = 220;
const INTERRUPT_VAD_LOG_MAX = 200;
let interruptVadLogLines = [];
let pttRecording = false;
let inputMuted = false;
let suppressNextUtterance = false;

/** Web Speech API (main + interrupt + post-interrupt); mutually exclusive instances. */
let mainBrowserRecognition = null;
let mainBrowserSilenceTimer = null;
let mainBrowserFinalTranscript = "";
/** @type {HTMLElement | null} */
let mainBrowserLiveBubble = null;
/** Translucent live preview during TTS interrupt detection (browser ASR); promoted to main live bubble on interrupt. */
/** @type {HTMLElement | null} */
let interruptDetectionBubbleEl = null;

let interruptDetectRecognition = null;
let interruptBrowserDetectActive = false;
let postInterruptRecognition = null;
let interruptPartialAccumMs = 0;
let interruptPartialLastChangeAt = 0;
let interruptPartialLastText = "";
let interruptPartialRafTime = 0;
/** "main" continuous/PTT vs "interrupt" post-barge-in utterance — controls silence-timer finalize. */
let mainBrowserFinalizeKind = "main";
let mainBrowserLastInterim = "";
let mainBrowserAsrTurnSeq = 0;
/* interruptBargeInLatched → moved to voice/interruption.js (Stage 6, 2026-05-27). */
/** If interrupt-detect SR never emits onresult while TTS plays, abort so heuristic fallback can run. */
let interruptDetectNoResultWatchdogTimer = null;

/* Fast VAD barge-in state (vadFastStopArmed, vadFastStopFiredAt,
 * vadFastStopTtsStoppedAt, vadFastStopAsrFinalAt, vadFastStopTtsId)
 * → moved to voice/interruption.js (Stage 6, 2026-05-27). */

/* logBargeInLatencyDebug → moved to utils/logging.js (Stage 3, 2026-05-27). */

/* =========================================================================
 *  INTERRUPTION / BARGE-IN DEBUG + TIMING + CANCEL-SOURCE
 *  → moved to voice/interruption.js (Stage 6, 2026-05-27).
 *
 *  Moved bindings:
 *    const _veraInterruptDebugLastAt,
 *    let _veraTtsCancelSource, let _veraInterruptDelayTrace,
 *    let _veraInterruptAttemptSeq,
 *    let interruptBargeInLatched (moved from its earlier siting),
 *    let vadFastStopArmed / vadFastStopFiredAt / vadFastStopTtsStoppedAt
 *      / vadFastStopAsrFinalAt / vadFastStopTtsId,
 *    function isVeraInterruptDebugEnabled,
 *    function logVeraInterruptDebug,
 *    function _newInterruptAttemptId,
 *    function _resetInterruptDelayTrace,
 *    function _ensureInterruptDelayTrace,
 *    function _recordInterruptTimingPoint,
 *    function _flushInterruptDelayTrace,
 *    function _logVoiceStateTransition,
 *    function _logTtsCancelSourceTrace,
 *    function resetVadFastStopState,
 *    function fastStopTtsOnVadOnly,
 *    function interruptTranscriptNewTtsId,
 *    function interruptSpeech.
 *
 *  RAF gap tracker, news-panel render flag, and per-NDJSON debug context
 *  remain here because they are written by hot-path code outside the
 *  interruption layer (detectInterrupt RAF loop and the news panel
 *  renderer). The moved trace helpers still read them at call time
 *  through the shared classic-script global lexical environment.
 * ========================================================================= */

/** RAF gap tracker for detectInterrupt — flags main-thread stalls that
 *  would prevent VAD from firing in time (news panel render is the usual
 *  suspect on long news responses). */
let _veraInterruptRafLastAt = 0;

/* News-panel render timing flag `_veraNewsPanelRenderInFlight` moved to
 * news/newsPanel.js (Stage 10, 2026-05-27). Still read here as a bare
 * identifier through the shared classic-script global lexical env
 * (`duringNewsRender` in interrupt-debug log payloads). */

/** Per-NDJSON correlation context for chunk-level debug. Populated by
 *  runNdjsonTtsPlayback when the `meta` line is parsed; cleared on
 *  `done` or cancellation. Read by playTtsUrlSequenceIncremental's
 *  checkpoint logs so chunk events can be tied back to news vs normal. */
let _veraCurrentTtsDebugContext = null;

/* ---------------------------------------------------------------------
 * Tab-local voice-runtime diagnostics — see debug/voiceDebug.js
 *
 * The two DevTools commands `window.dumpVeraVoiceState()` and
 * `window.resetVeraVoiceRuntimeState()` were extracted during the
 * stabilization-stage modularization pass (2026-05-27, Stage 4).
 * They still attach themselves to `window` and still read/mutate the
 * same app.js `let`-declared bindings (`mainTtsPlaybackActive`,
 * `interruptBargeInLatched`, `_veraTtsCancelSource`, …) through the
 * shared classic-script global lexical environment at CALL time.
 * debug/voiceDebug.js is loaded AFTER app.js in index.html.
 * ------------------------------------------------------------------- */
/* dumpVeraVoiceState + resetVeraVoiceRuntimeState IIFE body → moved to
 * debug/voiceDebug.js (Stage 4, 2026-05-27). */

/* =========================================================================
 *  BARGE-IN DEBUG OVERLAY (dev-only diagnostic UI)
 *
 *  Goal: make voice-interruption gating visible in real time so we can see
 *  whether the bug is "VAD didn't fire", "barge-in gate blocked", "TTS
 *  cancel never fired", or "cancel fired but queued audio kept playing".
 *
 *  Enable:
 *    window.VERA_DEBUG_BARGE_IN_UI = true        // session-only
 *    localStorage.setItem("vera_debug_barge_in_ui", "1")  // persisted
 *    window.toggleBargeInDebugUi(true|false)     // imperative
 *
 *  Snapshot:
 *    window.copyBargeInDebugSnapshot()           // copies JSON to clipboard
 *
 *  The overlay is hidden when both the window flag and the localStorage flag
 *  are off, so normal users never see it. It piggybacks on existing
 *  logVeraInterruptDebug + logInterruptTranscriptDebug calls — no extra
 *  instrumentation is added to barge-in hot paths.
 * ========================================================================= */
const _veraBargeInDebug = {
  /* Cached enabled flag — flipped by the polling tick / toggle so hot-path
   * event capture is a single boolean check. */
  enabled: false,

  /* Ring buffer of the last few interruption-related events. */
  events: [],
  maxEvents: 14,

  /* Latched timestamps for the cancel-delay summary line. */
  ttsStartedAt: 0,
  lastSpeechDetectedAt: 0,
  lastTtsCancelCalledAt: 0,
  lastInterruptEntryAt: 0,
  lastEarlyReturnReason: null,
  lastCancelSource: null,

  /* Last render-blocking timings (filled when news_panel_render_end /
   * interrupt_raf_gap fire). */
  lastNewsRenderDurationMs: 0,
  lastRafGapMs: 0,

  /* DOM + render loop. */
  containerEl: null,
  bodyEl: null,
  renderIntervalId: null,
  pollIntervalId: null,
};

function _bargeInDebugUiEnabled() {
  try {
    if (typeof window !== "undefined" && window.VERA_DEBUG_BARGE_IN_UI === true) return true;
  } catch (_) {}
  try {
    if (typeof localStorage !== "undefined" && localStorage.getItem("vera_debug_barge_in_ui") === "1") return true;
  } catch (_) {}
  /* Cleanup-pass additive gate: anyone in unified dev mode also sees the
   * overlay. Pre-existing per-feature flags above keep working unchanged. */
  try {
    if (typeof isVeraDevMode === "function" && isVeraDevMode()) return true;
  } catch (_) {}
  return false;
}

/** Hot-path event capture. Called from logVeraInterruptDebug and
 *  logInterruptTranscriptDebug *before* any gating, so timeline events are
 *  recorded whenever the debug overlay is on (independent of
 *  VERA_DEBUG_INTERRUPT). */
function _bargeInDebugCaptureEvent(eventName, payload) {
  if (!_veraBargeInDebug.enabled) return;
  try {
    const nowMs = performance.now();
    const name = String(eventName || "event");
    const p = payload && typeof payload === "object" ? payload : { value: payload };

    if (name === "tts_start") _veraBargeInDebug.ttsStartedAt = nowMs;
    if (name === "speech_detected") _veraBargeInDebug.lastSpeechDetectedAt = nowMs;
    if (name === "tts_cancel_called") {
      _veraBargeInDebug.lastTtsCancelCalledAt = nowMs;
      if (p?.source) _veraBargeInDebug.lastCancelSource = p.source;
    }
    if (name === "interrupt_speech_entry") {
      if (p?.outcome === "early_return") {
        _veraBargeInDebug.lastEarlyReturnReason = p?.reasonIfReturn || "early_return";
      } else if (p?.outcome === "proceed_cancel_tts") {
        _veraBargeInDebug.lastInterruptEntryAt = nowMs;
        _veraBargeInDebug.lastEarlyReturnReason = null;
      }
    }
    if (name === "news_panel_render_end" && Number.isFinite(p?.durationMs)) {
      _veraBargeInDebug.lastNewsRenderDurationMs = Number(p.durationMs);
    }
    if (name === "interrupt_raf_gap" && Number.isFinite(p?.gapMs)) {
      _veraBargeInDebug.lastRafGapMs = Number(p.gapMs);
    }

    const sinceTtsStartMs =
      _veraBargeInDebug.ttsStartedAt > 0
        ? Number((nowMs - _veraBargeInDebug.ttsStartedAt).toFixed(1))
        : null;

    _veraBargeInDebug.events.push({
      event: name,
      perfNow: Number(nowMs.toFixed(1)),
      sinceTtsStartMs,
      payload: p,
    });
    if (_veraBargeInDebug.events.length > _veraBargeInDebug.maxEvents) {
      _veraBargeInDebug.events.shift();
    }
  } catch (_) {}
}

function _bargeInDebugBuildState() {
  const base =
    typeof window !== "undefined" && typeof window.dumpVeraVoiceState === "function"
      ? window.dumpVeraVoiceState({ silent: true })
      : {};
  const extras = base?.extras || {};

  const ttsPlaying = Boolean(
    base.mainTtsPlaybackActive ||
      (base.activeMainTtsBufferSourcesCount || 0) > 0 ||
      (typeof isAssistantTtsPlaying === "function" && isAssistantTtsPlaying())
  );
  const useBrowserAsr = base.browserAsrPreferred === true;
  const recorderReady =
    Boolean(base.interruptRecording) ||
    extras.interruptDetectRecognitionPresent === true;
  const continuous = base.continuousListeningEnabled === true;
  const micActive = extras.micStreamActive === true;
  const vadArmed = base.vadFastStopArmed === true;
  const latched = extras.interruptBargeInLatched === true;
  const audioCtxState = extras.audioCtxState || null;

  /* Reflect the *actual* gate logic. Order matters — first failing gate wins
   * so the displayed reason matches what the runtime would reject on. */
  let allowed = true;
  let reason = "allowed";
  if (!continuous) {
    allowed = false;
    reason = "not_continuous";
  } else if (!ttsPlaying) {
    allowed = false;
    reason = "no_tts_playing";
  } else if (extras.appHidden === true) {
    allowed = false;
    reason = "app_hidden_or_throttled";
  } else if (!micActive) {
    allowed = false;
    reason = "mic_stream_inactive";
  } else if (audioCtxState && audioCtxState !== "running") {
    allowed = false;
    reason = `audio_ctx_${audioCtxState}`;
  } else if (latched) {
    allowed = false;
    reason = "already_latched";
  } else if (!vadArmed) {
    allowed = false;
    reason = "vad_not_armed";
  } else if (!useBrowserAsr && !recorderReady) {
    /* The suspected single-ASR bug gate — gets surfaced verbatim. */
    allowed = false;
    reason = "interrupt_recording_false_single_asr";
  } else if (useBrowserAsr && extras.interruptDetectRecognitionPresent !== true) {
    allowed = false;
    reason = "interrupt_detect_recognition_missing";
  }

  const speechAt = _veraBargeInDebug.lastSpeechDetectedAt;
  const cancelAt = _veraBargeInDebug.lastTtsCancelCalledAt;
  const cancelDelayMs =
    speechAt > 0 && cancelAt >= speechAt
      ? Number((cancelAt - speechAt).toFixed(1))
      : null;

  return {
    timestamp: new Date().toISOString(),
    bargeIn: {
      allowed,
      reason,
      vadArmed,
      latched,
      useBrowserAsr,
      continuous,
      micActive,
      ttsPlaying,
      recorderReady,
    },
    voice: {
      asrMode: base.asrMode,
      listeningMode: base.listeningMode,
      micState: base.micState,
      inputMuted: base.inputMuted,
      workModeOn: base.workModeOn,
      workModeMuteEnabled: base.workModeMuteEnabled,
    },
    tts: {
      playing: ttsPlaying,
      mainTtsPlaybackActive: base.mainTtsPlaybackActive,
      bufferSources: base.activeMainTtsBufferSourcesCount,
      ndjsonReaderPresent: base.activeNdjsonBodyReaderPresent,
      ttsId: base.currentTtsId,
      token: base.mainTtsPlaybackToken,
    },
    vad: {
      armed: vadArmed,
      speechFrames: extras.interruptSpeechFrames,
      speechAccumMs: extras.interruptSpeechAccumMs,
      partialAccumMs: extras.interruptPartialAccumMs,
      partialLastText: extras.interruptPartialLastText,
      sinceTtsStartMs:
        _veraBargeInDebug.ttsStartedAt > 0
          ? Number((performance.now() - _veraBargeInDebug.ttsStartedAt).toFixed(0))
          : null,
    },
    capture: {
      interruptRecording: base.interruptRecording,
      prearmRecorderState: base.interruptPrearmRecorderState,
      detectRecognitionPresent: extras.interruptDetectRecognitionPresent,
      mainBrowserRecognitionPresent: extras.mainBrowserRecognitionPresent,
      browserAsrPermanentlyDisabled: extras.browserAsrPermanentlyDisabled,
    },
    cancel: {
      lastSpeechDetectedPerfNow: speechAt > 0 ? Number(speechAt.toFixed(1)) : null,
      lastTtsCancelCalledPerfNow: cancelAt > 0 ? Number(cancelAt.toFixed(1)) : null,
      cancelDelayMs,
      lastInterruptEntryPerfNow:
        _veraBargeInDebug.lastInterruptEntryAt > 0
          ? Number(_veraBargeInDebug.lastInterruptEntryAt.toFixed(1))
          : null,
      lastEarlyReturnReason: _veraBargeInDebug.lastEarlyReturnReason,
      lastCancelSource:
        _veraBargeInDebug.lastCancelSource ||
        (typeof _veraTtsCancelSource !== "undefined" ? _veraTtsCancelSource : null) ||
        null,
    },
    newsRender: {
      duringNewsRender: extras.duringNewsRender,
      lastNewsRenderDurationMs: _veraBargeInDebug.lastNewsRenderDurationMs,
      lastRafGapMs: _veraBargeInDebug.lastRafGapMs,
      appHidden: extras.appHidden,
      appVisibilityState: extras.appVisibilityState,
      audioCtxState,
    },
    events: _veraBargeInDebug.events.slice().reverse(),
    underlyingDump: base,
  };
}

function _bargeInDebugPositionOverlay() {
  if (!_veraBargeInDebug.containerEl) return;
  /* Anchor to the left of the active record/mic button when one is
   * mounted (VERA + BMO modes). Fallback to fixed bottom-right corner. */
  let anchor = null;
  try {
    const candidates = ["vera-record", "bmo-record"];
    for (const id of candidates) {
      const btn = document.getElementById(id);
      if (!btn) continue;
      const rect = btn.getBoundingClientRect();
      if (rect.width > 0 && rect.height > 0) {
        anchor = { el: btn, rect };
        break;
      }
    }
  } catch (_) {}

  const el = _veraBargeInDebug.containerEl;
  el.style.position = "fixed";
  el.style.left = "auto";
  if (anchor) {
    const overlayW = el.offsetWidth || 320;
    const leftPx = Math.max(8, anchor.rect.left - overlayW - 12);
    const topPx = Math.max(8, anchor.rect.top - el.offsetHeight + anchor.rect.height);
    el.style.left = `${leftPx}px`;
    el.style.top = `${topPx}px`;
    el.style.right = "auto";
    el.style.bottom = "auto";
  } else {
    el.style.right = "16px";
    el.style.bottom = "16px";
    el.style.top = "auto";
  }
}

function _bargeInDebugMount() {
  if (typeof document === "undefined") return;
  if (!_bargeInDebugUiEnabled()) return;
  if (_veraBargeInDebug.containerEl && _veraBargeInDebug.containerEl.isConnected) return;

  const el = document.createElement("div");
  el.id = "vera-barge-in-debug-overlay";
  el.setAttribute("data-vera-dev-overlay", "barge-in");
  el.style.cssText = [
    "position:fixed",
    "right:16px",
    "bottom:16px",
    "width:320px",
    "max-height:70vh",
    "overflow:auto",
    "background:rgba(8,12,18,0.96)",
    "color:#d8e1ea",
    "font:11px/1.4 ui-monospace,SFMono-Regular,Menlo,Consolas,monospace",
    "border:1px solid rgba(120,135,160,0.4)",
    "border-radius:8px",
    "padding:8px 10px 10px 10px",
    "z-index:2147483646",
    "box-shadow:0 4px 14px rgba(0,0,0,0.4)",
    "pointer-events:auto",
    "user-select:text",
  ].join(";");
  el.innerHTML =
    '<div data-bd-header style="display:flex;align-items:center;justify-content:space-between;margin:-2px -2px 6px;gap:6px;">' +
    '  <strong style="font-size:11px;letter-spacing:.04em;color:#79c8ff;">BARGE-IN DEBUG <span style="color:#666;font-weight:400;">(dev)</span></strong>' +
    '  <span style="display:flex;gap:4px;">' +
    '    <button data-bd-copy  type="button" title="Copy snapshot to clipboard" style="background:#1a2433;color:#cfe;border:1px solid #325;padding:2px 6px;border-radius:4px;font:11px/1 inherit;cursor:pointer;">Copy</button>' +
    '    <button data-bd-reset type="button" title="Dev reset of voice runtime state" style="background:#3a1a1a;color:#fcc;border:1px solid #532;padding:2px 6px;border-radius:4px;font:11px/1 inherit;cursor:pointer;">Reset</button>' +
    '    <button data-bd-close type="button" title="Hide overlay" style="background:transparent;color:#9aa;border:1px solid #555;padding:2px 6px;border-radius:4px;font:11px/1 inherit;cursor:pointer;">×</button>' +
    '  </span>' +
    '</div>' +
    '<div data-bd-body></div>';
  document.body.appendChild(el);
  _veraBargeInDebug.containerEl = el;
  _veraBargeInDebug.bodyEl = el.querySelector("[data-bd-body]");

  el.querySelector("[data-bd-copy]").addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    try { window.copyBargeInDebugSnapshot(); } catch (_) {}
  });
  el.querySelector("[data-bd-reset]").addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (typeof window.resetVeraVoiceRuntimeState === "function") {
      try {
        window.resetVeraVoiceRuntimeState({ source: "barge_in_debug_overlay" });
      } catch (_) {}
    } else {
      try { console.warn("[barge_in_debug] resetVeraVoiceRuntimeState not available"); } catch (_) {}
    }
  });
  el.querySelector("[data-bd-close]").addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    /* Closing the overlay disables the flag so it doesn't re-mount on the
     * next polling tick. The user can re-enable with toggleBargeInDebugUi(true). */
    try { window.VERA_DEBUG_BARGE_IN_UI = false; } catch (_) {}
    safeRemoveLocalStorage("vera_debug_barge_in_ui");
    _bargeInDebugUnmount();
  });

  if (_veraBargeInDebug.renderIntervalId == null) {
    _veraBargeInDebug.renderIntervalId = setInterval(() => {
      if (!_bargeInDebugUiEnabled()) {
        _bargeInDebugUnmount();
        return;
      }
      _bargeInDebugRender();
    }, 200);
  }
  _bargeInDebugRender();
}

function _bargeInDebugUnmount() {
  if (_veraBargeInDebug.renderIntervalId != null) {
    try { clearInterval(_veraBargeInDebug.renderIntervalId); } catch (_) {}
    _veraBargeInDebug.renderIntervalId = null;
  }
  if (_veraBargeInDebug.containerEl && _veraBargeInDebug.containerEl.parentNode) {
    try { _veraBargeInDebug.containerEl.parentNode.removeChild(_veraBargeInDebug.containerEl); } catch (_) {}
  }
  _veraBargeInDebug.containerEl = null;
  _veraBargeInDebug.bodyEl = null;
}

function _bargeInDebugEscapeHtml(s) {
  if (s == null) return "";
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function _bargeInDebugRender() {
  if (!_veraBargeInDebug.bodyEl) return;
  let s;
  try { s = _bargeInDebugBuildState(); } catch (_) { return; }

  const colAllowed = s.bargeIn.allowed ? "#7fe39a" : "#ff6b6b";
  const colTts = s.tts.playing ? "#7fe39a" : "#9aa";
  const sentinelRed = s.tts.mainTtsPlaybackActive && (s.tts.bufferSources || 0) === 0;
  const colSentinel = sentinelRed ? "#ff6b6b" : "#9aa";

  /* Cancel-delay color: green if cancel fired within 80 ms of speech detect,
   * yellow up to 250 ms, red beyond that or if no cancel after a recent
   * speech_detected. */
  let colCancel = "#9aa";
  let cancelText = "—";
  if (s.cancel.cancelDelayMs != null) {
    cancelText = `${s.cancel.cancelDelayMs}ms`;
    if (s.cancel.cancelDelayMs <= 80) colCancel = "#7fe39a";
    else if (s.cancel.cancelDelayMs <= 250) colCancel = "#f3d36b";
    else colCancel = "#ff6b6b";
  } else if (
    s.cancel.lastSpeechDetectedPerfNow != null &&
    s.tts.playing &&
    performance.now() - s.cancel.lastSpeechDetectedPerfNow > 200
  ) {
    colCancel = "#ff6b6b";
    cancelText = "none (TTS still playing)";
  }

  /* VAD color: green if armed + speech accum > 0, yellow if accumulating but
   * threshold not yet passed (rough proxy: speechAccumMs > 0 but no
   * speech_detected this turn). */
  let colVad = "#9aa";
  if (s.vad.armed) {
    if ((s.vad.speechAccumMs || 0) > 0) colVad = "#f3d36b";
    else colVad = "#7fe39a";
  } else {
    /* If TTS is playing but VAD is not armed, that's actually a red flag —
     * caller would be blocked. */
    colVad = s.tts.playing ? "#ff6b6b" : "#9aa";
  }

  const esc = _bargeInDebugEscapeHtml;
  const eventsHtml = s.events.slice(0, 10).map((ev) => {
    const sinceTts =
      ev.sinceTtsStartMs != null ? `+${Math.round(ev.sinceTtsStartMs)}ms` : "—";
    const extras = [];
    if (ev.payload?.outcome) extras.push(`outcome=${ev.payload.outcome}`);
    if (ev.payload?.reasonIfReturn) extras.push(`reason=${ev.payload.reasonIfReturn}`);
    if (ev.payload?.event) extras.push(`event=${ev.payload.event}`);
    if (ev.payload?.source) extras.push(`src=${ev.payload.source}`);
    if (Number.isFinite(ev.payload?.durationMs)) extras.push(`dur=${Math.round(ev.payload.durationMs)}ms`);
    if (Number.isFinite(ev.payload?.gapMs)) extras.push(`gap=${Math.round(ev.payload.gapMs)}ms`);
    if (ev.payload?.gatePath) extras.push(`gate=${ev.payload.gatePath}`);
    const extraStr = extras.length
      ? ` <span style="color:#9aa;">${esc(extras.join(" "))}</span>`
      : "";
    return (
      `<div style="display:flex;gap:6px;line-height:1.35;">` +
      `<span style="color:#79c8ff;min-width:64px;font-variant-numeric:tabular-nums;">${esc(sinceTts)}</span>` +
      `<span style="color:#d8e1ea;">${esc(ev.event)}${extraStr}</span>` +
      `</div>`
    );
  }).join("");

  const ttsIdShort = s.tts.ttsId ? String(s.tts.ttsId).slice(0, 22) : "—";
  const tokShort = s.tts.token == null ? "—" : String(s.tts.token);

  _veraBargeInDebug.bodyEl.innerHTML =
    '<div style="display:grid;grid-template-columns:auto 1fr;gap:2px 8px;">' +
      `<div style="color:#9aa;">ASR</div><div>${esc(s.voice.asrMode || "?")} <span style="color:#9aa;">(${esc(s.voice.listeningMode || "?")})</span></div>` +
      `<div style="color:#9aa;">Mic</div><div>${esc(s.voice.micState || "?")}${s.voice.inputMuted ? ' <span style="color:#f3d36b;">(muted)</span>' : ""}</div>` +
      `<div style="color:#9aa;">TTS</div><div style="color:${colTts};">${s.tts.playing ? "playing" : "idle"} <span style="color:#9aa;">srcs=${esc(s.tts.bufferSources ?? "?")} rdr=${s.tts.ndjsonReaderPresent ? "y" : "n"}</span></div>` +
      `<div style="color:#9aa;">Ids</div><div style="color:#9aa;font-size:10px;">tts=${esc(ttsIdShort)} tok=${esc(tokShort)}</div>` +
      `<div style="color:#9aa;">Sentinel</div><div style="color:${colSentinel};">${s.tts.mainTtsPlaybackActive ? "active" : "inactive"}${sentinelRed ? ' <span style="color:#ff6b6b;">(no tracked srcs!)</span>' : ""}</div>` +
      `<div style="color:#9aa;">Barge-in</div><div style="color:${colAllowed};font-weight:600;">${s.bargeIn.allowed ? "ALLOWED" : "BLOCKED"} <span style="color:#9aa;font-weight:400;">(${esc(s.bargeIn.reason)})</span></div>` +
      `<div style="color:#9aa;">VAD</div><div style="color:${colVad};">armed=${s.vad.armed ? "y" : "n"} speech=${esc(s.vad.speechAccumMs ?? 0)}ms partial=${esc(s.vad.partialAccumMs ?? 0)}ms</div>` +
      `<div style="color:#9aa;">Frames</div><div>frames=${esc(s.vad.speechFrames ?? 0)} sinceTts=${esc(s.vad.sinceTtsStartMs ?? "—")}ms</div>` +
      `<div style="color:#9aa;">Capture</div><div>recIntr=${s.capture.interruptRecording ? "y" : "n"} prearm=${esc(s.capture.prearmRecorderState ?? "—")} detect=${s.capture.detectRecognitionPresent ? "y" : "n"}</div>` +
      `<div style="color:#9aa;">Cancel</div><div style="color:${colCancel};">delay=${esc(cancelText)} <span style="color:#9aa;">early=${esc(s.cancel.lastEarlyReturnReason ?? "—")} src=${esc(s.cancel.lastCancelSource ?? "—")}</span></div>` +
      `<div style="color:#9aa;">Render</div><div>news=${s.newsRender.duringNewsRender ? "y" : "n"} hidden=${s.newsRender.appHidden ? "y" : "n"} actx=${esc(s.newsRender.audioCtxState ?? "—")} nrDur=${esc(Math.round(s.newsRender.lastNewsRenderDurationMs || 0))}ms rafGap=${esc(Math.round(s.newsRender.lastRafGapMs || 0))}ms</div>` +
    '</div>' +
    '<div style="margin-top:6px;border-top:1px solid rgba(120,135,160,0.25);padding-top:5px;">' +
      '<div style="color:#9aa;margin-bottom:2px;">Events (most recent first):</div>' +
      (eventsHtml || '<div style="color:#666;">(no events yet — start a TTS turn and speak over it)</div>') +
    '</div>';

  /* Re-anchor after layout changes (mic button position can shift between
   * VERA and BMO modes or when the side panel opens). */
  try { _bargeInDebugPositionOverlay(); } catch (_) {}
}

function _bargeInDebugBuildSnapshot() {
  let snap = null;
  try { snap = _bargeInDebugBuildState(); } catch (_) {}
  return snap;
}

if (typeof window !== "undefined") {
  try {
    window.VERA_DEBUG_BARGE_IN_UI = _bargeInDebugUiEnabled();
  } catch (_) {}

  /* Imperative toggle — flips both the in-memory flag and the localStorage
   * persistence, then mounts/unmounts immediately. */
  window.toggleBargeInDebugUi = function toggleBargeInDebugUi(force) {
    const next = typeof force === "boolean" ? force : !_bargeInDebugUiEnabled();
    try { window.VERA_DEBUG_BARGE_IN_UI = next; } catch (_) {}
    if (next) safeSetLocalStorage("vera_debug_barge_in_ui", "1");
    else safeRemoveLocalStorage("vera_debug_barge_in_ui");
    _veraBargeInDebug.enabled = next;
    if (next) {
      if (typeof document !== "undefined" && document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", _bargeInDebugMount, { once: true });
      } else {
        _bargeInDebugMount();
      }
    } else {
      _bargeInDebugUnmount();
    }
    try {
      console.warn("[barge_in_debug_ui_toggled]", { enabled: next });
    } catch (_) {}
    return next;
  };

  /* Clipboard snapshot — usable from devtools without the overlay open. */
  window.copyBargeInDebugSnapshot = function copyBargeInDebugSnapshot() {
    const snap = _bargeInDebugBuildSnapshot();
    const text = JSON.stringify(snap, null, 2);
    try {
      if (navigator?.clipboard?.writeText) {
        navigator.clipboard.writeText(text).catch(() => {});
      } else if (typeof document !== "undefined") {
        const ta = document.createElement("textarea");
        ta.value = text;
        ta.style.cssText = "position:fixed;left:-9999px;top:-9999px;";
        document.body.appendChild(ta);
        ta.focus();
        ta.select();
        try { document.execCommand("copy"); } catch (_) {}
        document.body.removeChild(ta);
      }
    } catch (_) {}
    try { console.info("[barge_in_debug_snapshot_copied]", snap); } catch (_) {}
    return snap;
  };

  /* Low-frequency polling so the user can flip
   *   window.VERA_DEBUG_BARGE_IN_UI = true
   * (or set the localStorage key from another tab) and have the overlay
   * appear without an explicit toggle call. Stops itself once mounted. */
  if (_veraBargeInDebug.pollIntervalId == null) {
    _veraBargeInDebug.pollIntervalId = setInterval(() => {
      const wantOn = _bargeInDebugUiEnabled();
      const isOn = !!_veraBargeInDebug.containerEl;
      if (wantOn !== _veraBargeInDebug.enabled) _veraBargeInDebug.enabled = wantOn;
      if (wantOn && !isOn) _bargeInDebugMount();
      if (!wantOn && isOn) _bargeInDebugUnmount();
    }, 1000);
  }

  /* Auto-mount if a previous session left the flag set. */
  setTimeout(() => {
    if (_bargeInDebugUiEnabled()) {
      _veraBargeInDebug.enabled = true;
      if (typeof document !== "undefined" && document.readyState === "loading") {
        document.addEventListener("DOMContentLoaded", _bargeInDebugMount, { once: true });
      } else {
        _bargeInDebugMount();
      }
    }
  }, 0);
}

/* fastStopTtsOnVadOnly → moved to voice/interruption.js (Stage 6, 2026-05-27). */

/** Debounce main SR onend → startListening recovery (Chrome sometimes ends the session with no error). */
let browserAsrMainEndRecoveryTimer = null;
/** Debounce tab focus/visibility → resume main SR when Chrome ended the session in background. */
let browserAsrVisibilityResumeTimer = null;

/** Opt-in via localStorage VERA_DEBUG_BROWSER_ASR_STUCK=1 — heartbeats + onend/onerror/silence-timer traces. */
let browserAsrStuckWatchdogId = null;
let browserAsrSessionStartedAt = 0;
let browserAsrLastResultAt = 0;
let browserAsrHadAnyResult = false;
let browserAsrLastResultRole = "";

let audioStartedAt = 0;
let voiceUxTurn = null;
let textUxTurn = null;
// let interruptStart = 0;
let listeningMode = "continuous"; 
let waveState = "idle";   
let waveEnergy = 0;     

let requestInFlight = false; // 🔑 NEW

/** Start of a voice UX turn: t0 for perceived latency (end of user speech in the browser). */
function beginVoiceUxTurn() {
  voiceUxTurn = {
    speechEndAt: performance.now(),
    firstAudioLogged: false,
    mainReplyLogged: false
  };
}

/* logVoiceFirstAudio + logVoiceMainReplyAudio + logVoicePipe → moved to
 * utils/logging.js (Stage 3, 2026-05-27). They still reach `voiceUxTurn`
 * via the shared classic-script global lexical environment. */

/** Set localStorage VERA_DEBUG_TRANSCRIPTS to "0" to silence [VOICE][TRANSCRIPT] logs. */
function voiceTranscriptDebugEnabled() {
  return safeGetLocalStorage("VERA_DEBUG_TRANSCRIPTS") !== "0";
}

/** Set localStorage VERA_DEBUG_PARTIAL_ASR_DONE to "0" to silence [VOICE][PARTIAL-ASR] done / segment logs. */
function voicePartialAsrDoneLogEnabled() {
  return safeGetLocalStorage("VERA_DEBUG_PARTIAL_ASR_DONE") !== "0";
}

/**
 * Verbose browser-ASR diagnostics (heartbeats, onerror, silence-timer skips). Enable with:
 *   localStorage.setItem("VERA_DEBUG_BROWSER_ASR_STUCK", "1")
 * Reload the page after setting. (Recovery from dead SR and zero-audio TTS do not require this.)
 */
function browserAsrStuckDebugEnabled() {
  return safeGetLocalStorage("VERA_DEBUG_BROWSER_ASR_STUCK") === "1";
}

function stopBrowserAsrStuckWatchdog() {
  if (browserAsrStuckWatchdogId != null) {
    clearInterval(browserAsrStuckWatchdogId);
    browserAsrStuckWatchdogId = null;
  }
}

function snapshotBrowserAsrDebugState() {
  const now = performance.now();
  const sinceSessionStart = browserAsrSessionStartedAt
    ? Math.round(now - browserAsrSessionStartedAt)
    : null;
  const sinceLastResult =
    browserAsrHadAnyResult && browserAsrLastResultAt
      ? Math.round(now - browserAsrLastResultAt)
      : null;
  return {
    listening,
    processing,
    requestInFlight,
    waveState,
    interruptBrowserDetectActive,
    interruptBargeInLatched,
    mainBrowserFinalizeKind,
    hasMainRecognizer: !!mainBrowserRecognition,
    hasInterruptRecognizer: !!interruptDetectRecognition,
    hasPostInterruptRecognizer: !!postInterruptRecognition,
    silenceTimerActive: mainBrowserSilenceTimer != null,
    speechWaitPending: speechWaitTimeoutId != null,
    sinceSessionStartMs: sinceSessionStart,
    sinceLastResultMs: sinceLastResult,
    hadAnyResult: browserAsrHadAnyResult,
    lastResultRole: browserAsrLastResultRole || null,
    transcriptPreview: ((mainBrowserFinalTranscript + mainBrowserLastInterim).trim()).slice(0, 120),
  };
}

function logBrowserAsrStuckEvent(message, extra = {}) {
  if (!browserAsrStuckDebugEnabled()) return;
  console.log("[VOICE][BROWSER-ASR-STUCK]", message, { ...extra, ...snapshotBrowserAsrDebugState() });
}

function markBrowserAsrResult(role) {
  browserAsrLastResultAt = performance.now();
  browserAsrHadAnyResult = true;
  browserAsrLastResultRole = role;
}

/**
 * Call after a SpeechRecognition `.start()` succeeds. Heartbeats every 5s; warns if no `onresult` for 8s+ after
 * at least one result, or 12s+ with zero results (Chrome sometimes stops emitting).
 */
function beginBrowserAsrStuckSession(activeRole) {
  if (!browserAsrStuckDebugEnabled()) return;
  browserAsrSessionStartedAt = performance.now();
  browserAsrLastResultAt = 0;
  browserAsrHadAnyResult = false;
  browserAsrLastResultRole = activeRole;
  stopBrowserAsrStuckWatchdog();
  browserAsrStuckWatchdogId = window.setInterval(() => {
    if (!browserAsrStuckDebugEnabled()) {
      stopBrowserAsrStuckWatchdog();
      return;
    }
    const snap = snapshotBrowserAsrDebugState();
    const anyRec =
      snap.hasMainRecognizer || snap.hasInterruptRecognizer || snap.hasPostInterruptRecognizer;
    if (!anyRec) {
      stopBrowserAsrStuckWatchdog();
      return;
    }
    console.log("[VOICE][BROWSER-ASR-STUCK] heartbeat", snap);
    if (snap.hadAnyResult && snap.sinceLastResultMs != null && snap.sinceLastResultMs > 8000) {
      console.warn(
        "[VOICE][BROWSER-ASR-STUCK] no onresult for 8s+ while recognizer still referenced",
        snap
      );
    }
    if (!snap.hadAnyResult && snap.sinceSessionStartMs != null && snap.sinceSessionStartMs > 12000) {
      console.warn("[VOICE][BROWSER-ASR-STUCK] no onresult since session start (12s+)", snap);
    }
  }, 5000);
  logBrowserAsrStuckEvent("session_started", { activeRole });
}

/** One browser-ASR utterance finished (silence gate) and will go to Thinking/infer. */
function logPartialAsrUtteranceDone(text, meta = {}) {
  if (!voicePartialAsrDoneLogEnabled()) return;
  console.log("[VOICE][PARTIAL-ASR] done", { text: text ?? "", ...meta });
}

/** Chrome emitted a final segment for this result (may be multiple per spoken phrase). */
function logPartialAsrSegmentFinal(segmentText, meta = {}) {
  if (!voicePartialAsrDoneLogEnabled()) return;
  console.log("[VOICE][PARTIAL-ASR] segment-final", {
    segment: segmentText ?? "",
    ...meta
  });
}

/* logVoiceTranscript + logFinalTranscriptSentToLlm → moved to
 * utils/logging.js (Stage 3, 2026-05-27). `voiceTranscriptDebugEnabled`
 * remains in app.js (read-only gate, no extraction value). */

/* =========================================================================
 *  TURN TEXT INTEGRITY  (Stabilization Stage 1, 2026-05-27)
 *
 *  Moved to utils/logging.js (Stage 3, 2026-05-27):
 *    - _turnTextIntegrityEnabled
 *    - _veraTurnSeq + _nextVeraTurnId
 *    - logTurnTextIntegrity (+ window alias)
 *
 *  `_readLatestUserBubbleText` (below) STAYS in app.js because four other
 *  Work-Mode bubble-preservation sites also call it; the moved logger
 *  reaches it via the shared classic-script global lexical environment.
 *
 *  Silence with:  localStorage.setItem("VERA_DEBUG_TURN_TEXT", "0")
 *  Re-enable with: localStorage.removeItem("VERA_DEBUG_TURN_TEXT")
 * ========================================================================= */

/** Read the latest USER bubble's plain text from the DOM, ignoring the
 *  translucent interrupt-detection preview. Returns `null` when no user
 *  bubble is currently mounted (typical for work-mode typed turns where the
 *  bubble only appears after the server NDJSON meta arrives). */
function _readLatestUserBubbleText() {
  if (typeof document === "undefined") return null;
  let convo = null;
  try {
    convo = document.getElementById("conversation")
      || document.getElementById("bmo-conversation");
  } catch (_) {
    return null;
  }
  if (!convo) return null;
  let rows = null;
  try { rows = convo.querySelectorAll(".message-row.user"); } catch (_) { return null; }
  if (!rows || !rows.length) return null;
  for (let i = rows.length - 1; i >= 0; i--) {
    const row = rows[i];
    if (!(row instanceof HTMLElement)) continue;
    const bubble = row.querySelector(".bubble");
    if (!(bubble instanceof HTMLElement)) continue;
    if (bubble.classList.contains("interrupt-preview")) continue;
    const txt = (bubble.textContent || "").trim();
    if (txt) return txt;
  }
  return null;
}

/* logTurnTextIntegrity → moved to utils/logging.js (Stage 3, 2026-05-27).
 * window.logTurnTextIntegrity alias is now set inside utils/logging.js. */

/* =========================================================================
 *  WORK MODE — ORIGINAL FULL-COMMAND BUBBLE PRESERVATION
 *  (Stabilization Stage 1.5, 2026-05-27)
 *  ---------------------------------------------------------------------
 *  The Work Mode multi-action planner takes a compound command like
 *  "go to panel 2 and explain the Vietnam War" and dispatches each sub
 *  action through the existing /infer pipeline using the CLEANED segment
 *  text ("explain the Vietnam War"). When that sub-action's server NDJSON
 *  meta arrives, `commitServerUserTranscriptBubble` would normally
 *  overwrite the live user bubble with the cleaned segment, dropping the
 *  navigation half of the user's original phrasing.
 *
 *  This module-scoped "hold" lets the planner's caller pre-seed (or tag)
 *  the bubble with the FULL ORIGINAL TEXT and tell
 *  `commitServerUserTranscriptBubble` to skip any sub-action bubble
 *  overwrite for the duration of the executor.
 *
 *  Strictly UI-side: nothing here changes routing, action execution,
 *  reasoning, checklist, music, news, or close-panel behaviour. The
 *  `[WORKMODE_COMMAND_DISPLAY_TEXT]` log helper is the matching trace.
 * ========================================================================= */

let _veraWorkModeMultiActionBubbleHold = null;
let _veraWorkModeRenderedOriginalBubbleGuard = null;

function _wmNowMs() {
  try { return Date.now(); } catch (_) { return 0; }
}

function _wmHoldOriginalUserBubble(originalFullUserText) {
  _veraWorkModeMultiActionBubbleHold = {
    originalText: String(originalFullUserText || ""),
    startedAt: Date.now(),
  };
}

function _wmReleaseOriginalUserBubbleHold() {
  _veraWorkModeMultiActionBubbleHold = null;
}

function _wmIsOriginalUserBubbleHeld() {
  return _veraWorkModeMultiActionBubbleHold != null;
}

function _wmHeldOriginalUserBubbleText() {
  return _veraWorkModeMultiActionBubbleHold
    ? _veraWorkModeMultiActionBubbleHold.originalText
    : null;
}

/** Normalize for substring-similarity comparison: lowercase, collapse non-word
 *  chars to spaces, trim. Used to confirm that an incoming server transcript
 *  really is a sub-segment of the original full command before suppressing
 *  its bubble overwrite. Prevents an unrelated parallel turn from being
 *  silently dropped on the floor if it ever slips into the hold window. */
function _wmNormalizeForSegmentMatch(s) {
  return String(s || "")
    .toLowerCase()
    .replace(/[^\w]+/g, " ")
    .trim();
}

function _wmCleanExpiredRenderedOriginalGuard() {
  const guard = _veraWorkModeRenderedOriginalBubbleGuard;
  if (!guard) return null;
  const now = _wmNowMs();
  if (guard.expiresAt && now && now > guard.expiresAt) {
    _veraWorkModeRenderedOriginalBubbleGuard = null;
    return null;
  }
  return guard;
}

function _wmMarkOriginalUserBubbleRendered(originalFullUserText, cleanedExecutionTexts = [], source = "") {
  const originalText = String(originalFullUserText || "").trim();
  if (!originalText) return null;
  const cleanedTexts = Array.isArray(cleanedExecutionTexts)
    ? cleanedExecutionTexts
    : [cleanedExecutionTexts];
  const cleanedPrompts = cleanedTexts
    .map((raw) => String(raw || "").trim())
    .filter(Boolean)
    .map((raw) => ({
      raw,
      norm: _wmNormalizeForSegmentMatch(raw),
      suppressedCount: 0,
    }))
    .filter((p) => p.norm);
  const now = _wmNowMs();
  _veraWorkModeRenderedOriginalBubbleGuard = {
    originalText,
    originalNorm: _wmNormalizeForSegmentMatch(originalText),
    cleanedPrompts,
    source,
    startedAt: now,
    expiresAt: now ? now + 45000 : 0,
  };
  return _veraWorkModeRenderedOriginalBubbleGuard;
}

function _wmCleanedExecutionTextsFromPlan(plan) {
  return Array.isArray(plan?.actions)
    ? plan.actions
        .map((a) => String(a?.payload?.prompt || a?.segmentText || "").trim())
        .filter(Boolean)
    : [];
}

function _wmRenderedOriginalGuardText() {
  const guard = _wmCleanExpiredRenderedOriginalGuard();
  return guard ? guard.originalText : null;
}

function _wmSuppressionOriginalUserBubbleText() {
  return _wmHeldOriginalUserBubbleText() || _wmRenderedOriginalGuardText();
}

function _wmIncomingLooksLikeOriginalSegment(incomingText) {
  const original = _wmSuppressionOriginalUserBubbleText();
  if (!original) return false;
  const a = _wmNormalizeForSegmentMatch(original);
  const b = _wmNormalizeForSegmentMatch(incomingText);
  if (!a || !b) return false;
  if (a === b) return true;
  if (a.includes(b)) return true;
  /* Lenient reverse direction so trivial planner re-stitchings still match. */
  if (b.length >= 6 && a.includes(b.slice(0, Math.max(6, Math.floor(b.length * 0.6))))) return true;
  return false;
}

function _wmConsumeDuplicateCleanedPromptGuard(incomingText) {
  const guard = _wmCleanExpiredRenderedOriginalGuard();
  if (!guard) return null;
  const incomingNorm = _wmNormalizeForSegmentMatch(incomingText);
  if (!incomingNorm) return null;
  for (const prompt of guard.cleanedPrompts || []) {
    if (!prompt || !prompt.norm) continue;
    if (prompt.suppressedCount >= 3) continue;
    if (prompt.norm === incomingNorm) {
      prompt.suppressedCount += 1;
      return { originalText: guard.originalText, cleanedText: prompt.raw, source: guard.source };
    }
  }
  return null;
}

function _wmShouldSuppressDuplicateUserBubble(incomingText) {
  if (_wmIsOriginalUserBubbleHeld() && _wmIncomingLooksLikeOriginalSegment(incomingText)) {
    return {
      originalText: _wmSuppressionOriginalUserBubbleText(),
      cleanedText: String(incomingText || "").trim(),
      reason: "active_executor_hold",
    };
  }
  const lateGuardMatch = _wmConsumeDuplicateCleanedPromptGuard(incomingText);
  if (lateGuardMatch) {
    return {
      originalText: lateGuardMatch.originalText,
      cleanedText: lateGuardMatch.cleanedText,
      reason: "rendered_original_guard",
    };
  }
  return null;
}

function _workModeCommandDisplayTextEnabled() {
  try {
    if (typeof window !== "undefined" && window.VERA_DEBUG_WM_DISPLAY === false) return false;
  } catch (_) {}
  return safeGetLocalStorage("VERA_DEBUG_WM_DISPLAY") !== "0";
}

/** Emit a single `[WORKMODE_COMMAND_DISPLAY_TEXT]` line. Strictly diagnostic —
 *  never mutates state. Wrapped in try/catch so a malformed payload can never
 *  break a real turn. */
function logWorkModeCommandDisplayText(fields = {}) {
  if (!_workModeCommandDisplayTextEnabled()) return;
  try {
    const originalFullUserText =
      fields.originalFullUserText != null ? String(fields.originalFullUserText) : null;
    const renderedUserBubbleText =
      fields.renderedUserBubbleText !== undefined
        ? (fields.renderedUserBubbleText == null ? null : String(fields.renderedUserBubbleText))
        : _readLatestUserBubbleText();
    const cleanedExecutionText =
      fields.cleanedExecutionText != null ? String(fields.cleanedExecutionText) : null;
    const eq = (a, b) => {
      if (a == null || b == null) return null;
      return String(a).trim() === String(b).trim();
    };
    const payload = {
      tag: "WORKMODE_COMMAND_DISPLAY_TEXT",
      originalFullUserText,
      cleanedExecutionText,
      renderedUserBubbleText,
      rendered_eq_original: eq(renderedUserBubbleText, originalFullUserText),
      duplicateUserBubbleSuppressed:
        fields.duplicateUserBubbleSuppressed != null
          ? Boolean(fields.duplicateUserBubbleSuppressed)
          : null,
      usedCleanedTextAsInternalPromptOnly:
        fields.usedCleanedTextAsInternalPromptOnly != null
          ? Boolean(fields.usedCleanedTextAsInternalPromptOnly)
          : null,
      commandLooksMultiAction:
        fields.commandLooksMultiAction != null ? Boolean(fields.commandLooksMultiAction) : null,
      source: fields.source || null,
      timestamp: new Date().toISOString(),
    };
    console.info("[WORKMODE_COMMAND_DISPLAY_TEXT]", payload);
  } catch (e) {
    try { console.warn("[WORKMODE_COMMAND_DISPLAY_TEXT] log failed", e); } catch (_) {}
  }
}
try {
  if (typeof window !== "undefined") {
    window.logWorkModeCommandDisplayText = logWorkModeCommandDisplayText;
  }
} catch (_) {}

/* logInterruptTranscriptDebug → moved to utils/logging.js (Stage 3,
 * 2026-05-27). `_veraBargeInDebug` + `_bargeInDebugCaptureEvent` remain
 * in app.js and are reached via the shared global lexical environment. */

/* =========================
   INTERRUPTION TRANSCRIPT CLASSIFICATION

   Barge-in already stopped TTS instantly (see fastStopTtsOnVadOnly). The
   remaining decision after the ASR transcript is finalized is:

     - "stop", "never mind", "shut up" → cancel-only. TTS already stopped,
       nothing else to do; just resume listening.
     - "stop, sync the plan" → strip the leading cancel prefix and route
       the remainder as a normal user command.
     - "sync the plan", "remove the first item", "set a timer", "put that
       in the panel" → route the full transcript as a normal user command.

   The "normal user command" routing reuses the SAME shortcut handlers the
   regular voice / typed pipelines use (maybeHandleWorkChecklistSync*,
   maybeHandleWorkChecklistPlan*, maybeHandleMoveLatestVoiceTaskToReasoning)
   so a sync request that arrives as an interruption produces the same
   client-side mutation a normal voice request would.
========================= */

const INTERRUPT_CANCEL_ONLY_RE =
  /^(?:stop|stop\s+it|stop\s+talking|shut\s*up|shush|hush(?:\s+up)?|be\s+quiet|quiet|cancel(?:\s+that)?|never\s*mind|nevermind|forget\s+it|forget\s+about\s+it|pause|mute(?:\s+yourself)?|enough|that's\s+enough|thats\s+enough|okay\s+stop|ok\s+stop)$/i;

const INTERRUPT_CANCEL_PREFIX_RE =
  /^(?:stop|stop\s+talking|stop\s+it|shut\s*up|shush|hush(?:\s+up)?|be\s+quiet|quiet|cancel(?:\s+that)?|never\s*mind|nevermind|forget\s+it|forget\s+about\s+it|pause|hold\s+on|hold\s+up|wait(?:\s+a\s+(?:second|sec|minute|moment))?|actually|um|uh|no|nope|okay|ok)\b[\s,;:.\-—–]+(.+)$/i;

/**
 * Classify a finalized interruption transcript. Returns the shape the spec
 * calls out:
 *   { isCancelOnly, hasActionIntent, normalizedCommandText,
 *     leadingCancelStripped, reason }
 *
 * Pure judgement function — no side effects, safe to call from anywhere.
 */
function classifyInterruptionTranscript(text) {
  const raw = String(text || "").trim();
  if (!raw) {
    return {
      isCancelOnly: false,
      hasActionIntent: false,
      normalizedCommandText: "",
      leadingCancelStripped: false,
      reason: "empty"
    };
  }
  const lowered = raw.toLowerCase().replace(/[.?!,;:\s]+$/g, "").trim();
  if (INTERRUPT_CANCEL_ONLY_RE.test(lowered)) {
    return {
      isCancelOnly: true,
      hasActionIntent: false,
      normalizedCommandText: "",
      leadingCancelStripped: false,
      reason: "pure_cancel_phrase"
    };
  }
  const m = raw.match(INTERRUPT_CANCEL_PREFIX_RE);
  if (m) {
    const tail = String(m[1] || "").trim();
    if (tail && tail.split(/\s+/).filter(Boolean).length >= 1) {
      return {
        isCancelOnly: false,
        hasActionIntent: true,
        normalizedCommandText: tail,
        leadingCancelStripped: true,
        reason: "stripped_leading_cancel_prefix"
      };
    }
  }
  return {
    isCancelOnly: false,
    hasActionIntent: true,
    normalizedCommandText: raw,
    leadingCancelStripped: false,
    reason: "normal_command"
  };
}

/* interruptTranscriptNewTtsId → moved to voice/interruption.js (Stage 6, 2026-05-27). */

async function getMicPermissionStateForInterrupt() {
  try {
    if (micStream && micStream.active) return "granted";
    const tracks = micStream?.getAudioTracks?.() || [];
    if (tracks.some((t) => t && t.readyState === "live")) return "granted";
  } catch (_) {}
  try {
    if (navigator.permissions?.query) {
      const status = await navigator.permissions.query({ name: "microphone" });
      return String(status?.state || "unknown");
    }
  } catch (_) {}
  return "unknown";
}

function stopInterruptPrearmRecorder(reason = "") {
  try {
    if (interruptPrearmRecorder && interruptPrearmRecorder.state !== "inactive") {
      interruptPrearmRecorder.ondataavailable = null;
      interruptPrearmRecorder.onstop = null;
      interruptPrearmRecorder.stop();
    }
  } catch (_) {}
  interruptPrearmRecorder = null;
  interruptPrearmChunks = [];
  interruptPrearmStartedAt = 0;
  interruptPrearmCommittedAt = 0;
  interruptPrearmSuccess = false;
  if (reason) {
    logInterruptTranscriptDebug("prearm", {
      stream_active: Boolean(micStream?.active),
      media_recorder_ready: false,
      rolling_buffer_enabled: false,
      preroll_ms: INTERRUPTION_PREROLL_MS,
      reason
    });
  }
}

function beginTextUxTurn() {
  textUxTurn = {
    sendAt: performance.now(),
    firstAudioLogged: false,
    mainReplyLogged: false
  };
}

function logTextFirstAudio(kind) {
  if (!textUxTurn || textUxTurn.firstAudioLogged) return;
  const elapsedMs = performance.now() - textUxTurn.sendAt;
  textUxTurn.firstAudioLogged = true;
  console.log(`[UX][TEXT] Send→FirstAudio=${(elapsedMs / 1000).toFixed(3)}s (${kind})`);
}

function logTextMainReplyAudio() {
  if (!textUxTurn || textUxTurn.mainReplyLogged) return;
  const elapsedMs = performance.now() - textUxTurn.sendAt;
  textUxTurn.mainReplyLogged = true;
  console.log(`[UX][TEXT] Send→MainReplyAudio=${(elapsedMs / 1000).toFixed(3)}s`);
}

/** Server-side breakdown + optional client TTFB split — for attribution, not end-user perceived time (see SpeechEnd→MainReplyAudio). */
function logInferLatency(data, label, clientTtfbMs) {
  const L = data?.latency;
  if (!L || typeof L !== "object") return;
  const parts = [];
  if (L.short_circuit) parts.push(`short_circuit=${L.short_circuit}`);
  if (L.pre_asr_s != null) parts.push(`PreASR=${L.pre_asr_s}s`);
  if (L.asr_lock_s != null) parts.push(`ASR_lock=${L.asr_lock_s}s`);
  if (L.asr_transcribe_s != null) parts.push(`ASR_transcribe=${L.asr_transcribe_s}s`);
  if (L.bridge_s != null) parts.push(`Bridge=${L.bridge_s}s`);
  if (L.llm_s != null) parts.push(`LLM=${L.llm_s}s`);
  if (L.llm_first_token_s != null) parts.push(`LLM_first_token=${L.llm_first_token_s}s`);
  if (L.llm_first_sentence_ready_s != null)
    parts.push(`LLM_first_sentence_ready=${L.llm_first_sentence_ready_s}s`);
  if (L.post_llm_s != null) parts.push(`PostLLM=${L.post_llm_s}s`);
  if (L.tts_s != null) parts.push(`TTS=${L.tts_s}s`);
  if (L.tts_first_chunk_s != null) parts.push(`TTS_first_chunk=${L.tts_first_chunk_s}s`);
  if (L.first_tts_audio_ready_total_s != null)
    parts.push(`first_TTS_file_ready_total=${L.first_tts_audio_ready_total_s}s`);
  if (L.first_tts_audio_ready_after_pre_asr_s != null)
    parts.push(`first_TTS_file_ready_after_PreASR=${L.first_tts_audio_ready_after_pre_asr_s}s`);
  if (L.first_tts_audio_ready_after_asr_end_s != null)
    parts.push(`first_TTS_file_ready_after_ASR_end=${L.first_tts_audio_ready_after_asr_end_s}s`);
  if (L.total_s != null) parts.push(`TOTAL=${L.total_s}s`);
  if (L.sum_segments_s != null) parts.push(`Σ=${L.sum_segments_s}s`);
  if (L.drift_s != null) parts.push(`drift=${L.drift_s}s`);
  if (L.llm_internal_reported_s != null) parts.push(`llm_internal=${L.llm_internal_reported_s}s`);
  const line = parts.length ? parts.join(" | ") : JSON.stringify(L);
  console.log(`[UX][LATENCY][${label}] ${line}`, L);
  if (L.total_s != null && clientTtfbMs != null && Number.isFinite(clientTtfbMs)) {
    console.log(
      `[UX][LATENCY][split][${label}] backend total_s=${L.total_s} (server clock: infer start→end of full NDJSON stream on Python) | ` +
        `client_ttfb_ms=${Math.round(clientTtfbMs)} (browser: fetch() start→first response headers; includes body upload + Worker/proxy + network + server until it can stream)`
    );
    console.log(
      `[UX][LATENCY][hint] Backend work = ASR / LLM / TTS columns above (Python). ` +
        `Upload/proxy/internet vs backend: compare client_ttfb_ms to how “heavy” those segments are; TOTAL is not the same moment as TTFB (TOTAL waits for the whole stream to finish on the server).`
    );
  }
}

