const SILENCE_MS = 950;     // silence before ending speech
const TRAILING_MS = 300;   // guaranteed tail
/**
 * Browser SpeechRecognition: cap before first partial (`hasSpoken` false). 0 = off (desktop Chrome can be slow).
 */
