function finalizeWorkChecklistSyncCommandTurn({
  turnId,
  transcript,
  source,
  isVoice,
  success,
  checklistItemsInserted,
  previewUsed
} = {}) {
  const tid = String(turnId || "").trim() || `sync-plan-${++workChecklistSyncCommandSeq}`;
  const finalTranscript = String(transcript || "").trim();
  const fromVoice = Boolean(isVoice);
  // Short, spec-aligned confirmation. The mutation has already been
  // committed to localStorage by the time we reach here (see
  // commitNonCancelableAction("sync_checklist", ...) in
  // maybeHandleWorkChecklistSyncShortcut). The user can safely interrupt
  // this audio — only the playback is cancelled, not the sync itself.
  const replyText = success
    ? "Synced."
    : "I couldn’t find a plan to sync yet.";
  let transcriptFinalized = false;
  let bubbleClosed = false;
  try {
    if (finalTranscript) {
      commitServerUserTranscriptBubble(
        finalTranscript,
        fromVoice ? `work-mode-sync-${source || "voice"}` : "work-mode-sync-typed"
      );
      transcriptFinalized = true;
    }
  } catch (_) {}

  if (fromVoice) {
    try {
      abortBrowserSpeechRecognizers();
    } catch (_) {}
    try {
      clearVoiceMaxDurationTimer();
    } catch (_) {}
    try {
      audioChunks = [];
      hasSpoken = false;
      mainBrowserFinalTranscript = "";
      mainBrowserLastInterim = "";
      mainBrowserFinalizeKind = "main";
      interruptPartialLastText = "";
      interruptBargeInLatched = false;
    } catch (_) {}
  }

  try {
    addBubble(replyText, "vera", {
      path: success ? "work-mode-sync-command-success" : "work-mode-sync-command-failed"
    });
  } catch (_) {}

  requestInFlight = false;
  processing = false;
  voiceUxTurn = null;
  activeWorkChecklistSyncCommand = "";
  bubbleClosed = mainBrowserLiveBubble == null;
  setStatus("Ready", "idle");
  updateMuteInputButton();

  try {
    window.dispatchEvent(
      new CustomEvent("work_mode_command_completed", {
        detail: {
          command_type: "sync_plan",
          turn_id: tid,
          success: Boolean(success),
          checklist_items_inserted: Number(checklistItemsInserted || 0),
          preview_used: Boolean(previewUsed)
        }
      })
    );
  } catch (_) {}

  logSyncVoiceTurnDebug("sync_success", {
    turn_id: tid,
    checklist_items_inserted: Number(checklistItemsInserted || 0),
    preview_used: Boolean(previewUsed),
    action_completed: true,
    success: Boolean(success),
    source: source || ""
  });
  logSyncVoiceTurnDebug("finalize", {
    turn_id: tid,
    transcript_finalized: transcriptFinalized,
    bubble_closed: bubbleClosed,
    route_state_cleared: activeWorkChecklistSyncCommand === "",
    active_command_after_finalize: activeWorkChecklistSyncCommand || null,
    active_transcription_turn_after_finalize:
      mainBrowserRecognition || interruptDetectRecognition || postInterruptRecognition
        ? "browser_asr_active"
        : null,
    source: source || ""
  });

  lastCompletedWorkChecklistSyncCommandTurn = {
    turn_id: tid,
    command_type: "sync_plan",
    completed_at: Date.now()
  };

  if (fromVoice && listeningMode === "continuous" && listening && !inputMuted) {
    window.setTimeout(() => {
      if (!listening || processing || inputMuted) return;
      startListening();
    }, 80);
  }
}

async function maybeHandleWorkChecklistSyncShortcut(text, opts = {}) {
  const userText = String(text || "").trim();
  if (userText && lastCompletedWorkChecklistSyncCommandTurn) {
    const previousTurn = lastCompletedWorkChecklistSyncCommandTurn;
    const inheritedIntent = activeWorkChecklistSyncCommand === previousTurn.command_type;
    logSyncVoiceTurnDebug("next_turn", {
      previous_turn_id: previousTurn.turn_id,
      new_turn_id: opts.turnId || null,
      new_transcript: userText,
      inherited_previous_intent: Boolean(inheritedIntent),
      inherited_intent_name: inheritedIntent ? activeWorkChecklistSyncCommand : ""
    });
    lastCompletedWorkChecklistSyncCommandTurn = null;
  }
  const inWorkMode = isVeraWorkModeOn();
  const mode = appModePrefix();
  const looksRelevant = /\b(sync|synced|synchroniz|check\s*list|checklist|to-?do|todo|task\s*list|plan|reasoning)\b/i.test(
    userText
  );
  if (!inWorkMode || mode !== "vera") {
    if (looksRelevant) {
      logPlanSyncDebug("shortcut_gate", {
        user_text: userText,
        matched_intent: false,
        handled: false,
        reason_if_ignored: !inWorkMode ? "not_in_work_mode" : "not_vera_mode",
        in_work_mode: inWorkMode,
        app_mode: mode
      });
    }
    return false;
  }
  const matchedIntent = isWorkChecklistSyncCommandIntent(userText);
  if (!matchedIntent) {
    if (looksRelevant) {
      logPlanSyncDebug("shortcut_gate", {
        user_text: userText,
        matched_intent: false,
        handled: false,
        reason_if_ignored: "sync_intent_regex_no_match",
        in_work_mode: inWorkMode,
        app_mode: mode
      });
    }
    return false;
  }
  logPlanSyncDebug("shortcut_gate", {
    user_text: userText,
    matched_intent: true,
    handled: true,
    reason_if_ignored: "",
    in_work_mode: inWorkMode,
    app_mode: mode
  });
  const ctx = describePlanSyncActiveContext();
  const selected = getWorkChecklistSyncSourceCandidate();
  const turnId = String(opts.turnId || "").trim() || `sync-plan-${++workChecklistSyncCommandSeq}`;
  activeWorkChecklistSyncCommand = "sync_plan";
  logSyncVoiceTurnDebug("start", {
    turn_id: turnId,
    transcript: userText,
    detected_command: "sync_plan",
    active_panel_id: ctx.active_panel_id || null,
    active_lane_id: ctx.active_panel_id || null,
    source: opts.source || ""
  });
  logPlanSyncDebug("voice_sync_request", {
    user_text: userText,
    active_panel_id: ctx.active_panel_id,
    active_panel_title: ctx.active_panel_title,
    last_plan_panel_id: workChecklistSyncPendingPlanMeta?.panel_id || null,
    last_plan_panel_title: workChecklistSyncPendingPlanMeta?.panel_title || "",
    selected_source_panel_id: selected?.meta?.panel_id || null,
    selected_source_panel_title: selected?.meta?.panel_title || "",
    sync_candidate_count: selected?.rows?.length || 0,
    opened_preview: false,
    auto_applied: false,
    reason_if_failed: selected?.rows?.length ? "" : "no_sync_candidates_before_apply",
    trigger_source: "voice_or_typed_shortcut"
  });
  const ok = runWorkChecklistSyncFromLatestPlan({
    triggerSource: "voice_or_typed_shortcut",
    userText
  });
  let autoApplied = false;
  if (ok) {
    autoApplied = applyWorkChecklistSyncPreview();
  }
  // Commit-before-speak: the local mutation is already in localStorage
  // via applyWorkChecklistSyncPreview(); flush the debounced server PUT
  // RIGHT NOW so an interrupt that arrives milliseconds later cannot
  // discard a not-yet-flighted update. The TTS that comes next is
  // purely confirmation — see NON_CANCELABLE_AFTER_COMMIT_ACTIONS.
  if (ok && autoApplied) {
    try {
      if (typeof flushWorkChecklistSyncBeforeCommand === "function") {
        flushWorkChecklistSyncBeforeCommand().catch(() => {});
      } else if (typeof syncWorkChecklistToServerNow === "function") {
        syncWorkChecklistToServerNow().catch(() => {});
      }
    } catch (_) {}
    commitNonCancelableAction("sync_checklist", {
      turn_id: turnId,
      items_inserted: selected?.rows?.length || 0,
      source: opts.source || "voice_or_typed_shortcut"
    });
  }
  logPlanSyncDebug("voice_sync_request", {
    user_text: userText,
    active_panel_id: ctx.active_panel_id,
    active_panel_title: ctx.active_panel_title,
    last_plan_panel_id: workChecklistSyncPendingPlanMeta?.panel_id || null,
    last_plan_panel_title: workChecklistSyncPendingPlanMeta?.panel_title || "",
    selected_source_panel_id: selected?.meta?.panel_id || null,
    selected_source_panel_title: selected?.meta?.panel_title || "",
    sync_candidate_count: selected?.rows?.length || 0,
    opened_preview: ok,
    auto_applied: Boolean(autoApplied),
    reason_if_failed: ok ? "" : "run_plan_returned_false",
    trigger_source: "voice_or_typed_shortcut_completed"
  });
  finalizeWorkChecklistSyncCommandTurn({
    turnId,
    transcript: userText,
    source: opts.source || "voice_or_typed_shortcut",
    isVoice: opts.isVoice === true,
    success: Boolean(ok && autoApplied),
    checklistItemsInserted: ok && autoApplied ? selected?.rows?.length || 0 : 0,
    previewUsed: Boolean(ok)
  });
  return true;
}

async function runWorkChecklistHelpPlan({ signal } = {}) {
  if (!isVeraWorkModeOn()) return false;
  if (workChecklistPlanRequestInFlight) return true;
  const lines = collectWorkChecklistOngoingTexts();
  if (!lines.length) {
    flashWorkChecklistPlanHint("Add text to at least one ongoing item first.");
    return true;
  }
  const text = buildWorkChecklistHelpPlanUserMessage(lines);
  const helpPlanBtn = document.getElementById("vera-wm-checklist-help-plan");
  workChecklistPlanRequestInFlight = true;
  if (helpPlanBtn instanceof HTMLButtonElement) helpPlanBtn.disabled = true;
  try {
    const reasoningScroll = getActiveReasoningScrollEl();
    if (reasoningScroll instanceof HTMLElement) {
      reasoningScroll.scrollIntoView({ behavior: "smooth", block: "nearest" });
    }
    const turnContext = createWorkModeFrozenTurnContext({
      userText: text,
      source: "keyboard"
    });
    await streamWorkModeReasoningComposer(text, signal, { turnContext });
    const mdAfterHelp = getLatestWorkModeReasoningMarkdown();
    if (mdAfterHelp && /#{1,6}\s*SYNC CHECKLIST\b/i.test(mdAfterHelp)) {
      const rows = buildChecklistProposalFromMarkdown(mdAfterHelp);
      const activeLaneId = getActiveDomReasoningLaneId();
      const panelMeta = getPlanSyncPanelMetaForLane(activeLaneId);
      workChecklistSyncPlanVersion += 1;
      workChecklistSyncPendingMarkdown = mdAfterHelp;
      workChecklistSyncPendingPlanMeta = {
        ...panelMeta,
        source: "checklist_help_plan",
        created_at: Date.now()
      };
      logPlanSyncDebug("created", {
        lane_id: panelMeta.lane_id || null,
        panel_id: panelMeta.panel_id || null,
        panel_title: panelMeta.panel_title || "",
        active_panel_id: panelMeta.active_panel_id || null,
        is_plan_detected: true,
        syncable: rows.length > 0,
        has_sync_metadata: true,
        sync_candidate_count: rows.length,
        sync_candidates_preview: planSyncPreviewRows(rows),
        reason_if_not_syncable: rows.length ? "" : "no_checklist_candidates_extracted",
        response_kind: "sync_checklist_markdown",
        route_kind: "checklist_help_plan",
        source: "checklist_shortcut"
      });
      syncWorkChecklistSyncPlanButton();
    }
  } finally {
    workChecklistPlanRequestInFlight = false;
    syncWorkChecklistHelpPlanButton();
  }
  return true;
}

async function maybeHandleWorkChecklistPlanShortcut(text, signal) {
  if (!isVeraWorkModeOn() || appModePrefix() !== "vera") return false;
  if (!isWorkChecklistPlanShortcutIntent(text)) return false;
  await runWorkChecklistHelpPlan({ signal });
  return true;
}

/* queueWorkChecklistRowEnterAnimation moved to workmode/checklist.js
