function isFlowModeSidePaneCrossfadeEnabled() {
  try {
    if (appModePrefix() === "vera" && document.getElementById("vera-app")?.classList.contains("work-mode")) {
      return false;
    }
  } catch {}
  return true;
}

/**
 * When the side pane is already visible, swap inner content with a short fade (music ↔ news / finance)
 * so innerHTML replacement does not fight the panel slide-in transition.
 */
function runFlowModeSidePaneContentCrossfade(sidePaneEl, renderCallback) {
  if (
    !sidePaneEl ||
    !isFlowModeSidePaneCrossfadeEnabled() ||
    sidePaneEl.hidden ||
    !sidePaneEl.classList.contains("visible")
  ) {
    renderCallback();
    return;
  }

  let outDone = false;
  let fallbackOut = null;
  const finishOut = () => {
    if (outDone) return;
    outDone = true;
    if (fallbackOut != null) window.clearTimeout(fallbackOut);
    sidePaneEl.removeEventListener("transitionend", onOutEnd);
    renderCallback();
    window.requestAnimationFrame(() => {
      sidePaneEl.classList.remove("side-pane-swap-hiding");
      sidePaneEl.classList.add("side-pane-swap-in");
      let fallbackIn = null;
      function clearIn() {
        if (fallbackIn != null) window.clearTimeout(fallbackIn);
        sidePaneEl.removeEventListener("animationend", onInEnd);
        sidePaneEl.classList.remove("side-pane-swap-in");
      }
      function onInEnd(ev) {
        const n = String(ev.animationName || "");
        if (!n.includes("side-pane-content-swap-in")) return;
        clearIn();
      }
      sidePaneEl.addEventListener("animationend", onInEnd);
      fallbackIn = window.setTimeout(clearIn, 480);
    });
  };

  const onOutEnd = (ev) => {
    if (ev.target !== sidePaneEl) return;
    if (ev.propertyName !== "opacity" && ev.propertyName !== "filter") return;
    finishOut();
  };

  sidePaneEl.classList.add("side-pane-swap-hiding");
  sidePaneEl.addEventListener("transitionend", onOutEnd);
  fallbackOut = window.setTimeout(finishOut, 420);
}

/** NDJSON can call ``applyActionPayload`` from ``finalizeNdjsonStreamingReply`` before first audio and again from ``onPlayStart`` — duplicate Spotify starts / skips twitch the UI. */
function musicPlaybackDedupeKey(payload, op) {
  if (!payload || payload.panel_type !== "music_control") return "";
  if (op === "play_track" && payload.uri) return `play_track:${String(payload.uri).trim()}`;
  if (op === "play_album" && payload.uri) return `play_album:${String(payload.uri).trim()}`;
  if (op === "play_playlist_by_name") {
    const n = String(payload.playlist_name || "").trim().toLowerCase();
    if (n) return `play_playlist_by_name:${n}`;
  }
  if (op === "play_builtin") {
    const p = String(payload.playlist_id || "").trim().toLowerCase();
    const s = String(payload.sound_id || "").trim().toLowerCase();
    if (p) return `play_builtin:pl:${p}`;
    if (s) return `play_builtin:snd:${s}`;
  }
  return "";
}

function isRecentSameMusicPlay(payload, op) {
  const key = musicPlaybackDedupeKey(payload, op);
  if (!key) return false;
  const prev = window.__veraMusicPlaybackDedupe;
  return !!(prev && prev.key === key && performance.now() - prev.at < 7000);
}

/**
 * Collapse NDJSON double ``applyActionPayload`` (finalize + first audio).
 * Applies to non-idempotent music controls only:
 *   - ``skip_next`` / ``skip_previous`` — each call advances/rewinds a track.
 *   - ``volume_delta`` — each call adds ``payload.delta`` to volume, so the
 *     double-dispatch path was actually doubling the user's "turn up / turn
 *     down the music" command (+10% per turn instead of +5%). Keyed by
 *     sign-of-delta so that "volume up then volume down" within the dedupe
 *     window still applies both directions.
 *
 * ``pause`` / ``resume`` are idempotent (calling pause on an already-paused
 * stream is a no-op) so we don't dedupe them.
 *
 * 900 ms window is short enough that legitimate consecutive commands still
 * fire — humans don't realistically issue the same transport command twice
 * within a second.
 */
function shouldApplyMusicTransportAction(payload, op) {
  let key;
  if (op === "skip_next" || op === "skip_previous") {
    key = `music_transport:${op}`;
  } else if (op === "volume_delta") {
    const rawDelta = Number((payload && payload.delta) || 0);
    if (!Number.isFinite(rawDelta) || rawDelta === 0) return true;
    const dir = rawDelta > 0 ? "+1" : "-1";
    key = `music_transport:volume_delta:${dir}`;
  } else {
    return true;
  }
  const now = performance.now();
  const prev = window.__veraMusicTransportDedupe;
  if (prev && prev.key === key && now - prev.at < 900) {
    if (op === "skip_previous") {
      console.log("[MUSIC][SKIP_PREV] dedupe-drop", { delta_ms: Math.round(now - prev.at) });
    } else if (op === "volume_delta") {
      console.log("[MUSIC][VOLUME] dedupe-drop", {
        delta_ms: Math.round(now - prev.at),
        delta: Number((payload && payload.delta) || 0),
      });
    }
    return false;
  }
  window.__veraMusicTransportDedupe = { key, at: now };
  return true;
}

function invokeSpotifyTransport(op, { source = "unknown" } = {}) {
  const fn =
    op === "skip_previous"
      ? window.VeraSpotify?.skipPrevious
      : op === "skip_next"
      ? window.VeraSpotify?.skipNext
      : null;
  if (typeof fn !== "function") {
    console.log("[MUSIC][TRANSPORT] missing-handler", { op, source });
    return false;
  }
  console.log("[MUSIC][TRANSPORT] invoke", { op, source });
  void fn();
  return true;
}

function builtinMusicTransportSkipNext(prefix) {
  const st = window.__veraFreeMusicPlayback;
  if (st?.mode === "playlist" && st.queue?.length > 1) {
    const next = ((Number(st.index) || 0) + 1) % st.queue.length;
    void freeMusicPlayQueueIndex(prefix, next);
    return true;
  }
  return false;
}

function builtinMusicTransportSkipPrevious(prefix) {
  const st = window.__veraFreeMusicPlayback;
  const a = document.getElementById(`${prefix}-free-music-audio`);
  if (st?.mode === "playlist" && st.queue?.length > 1) {
    const pos = Math.round((a?.currentTime || 0) * 1000);
    if (pos > SPOTIFY_PREVIOUS_RESTART_MS && a) {
      a.currentTime = 0;
      freeMusicSyncNowFromAudio(prefix);
      return true;
    }
    const prev = ((Number(st.index) || 0) + st.queue.length - 1) % st.queue.length;
    void freeMusicPlayQueueIndex(prefix, prev);
    return true;
  }
  return false;
}

/** Returns false when the same play was already started a few seconds ago (NDJSON finalize + first-audio both call this). */
function shouldPlayMusicThisInvocation(payload, op) {
  const key = musicPlaybackDedupeKey(payload, op);
  if (!key) return true;
  const now = performance.now();
  const prev = window.__veraMusicPlaybackDedupe;
  if (prev && prev.key === key && now - prev.at < 7000) return false;
  window.__veraMusicPlaybackDedupe = { key, at: now };
  return true;
}

/** NDJSON may invoke ``applyActionPayload`` twice (finalize + first audio) — skip duplicate reasoning ops. */
function workModeReasoningDedupeKey(payload) {
  if (!payload || payload.panel_type !== "work_mode_reasoning") return "";
  const op = String(payload.op || "");
  if (op === "open_new") return `open_new:${Math.max(1, Number(payload.count) || 1)}`;
  if (op === "activate" && payload.panel_index != null) {
    return `activate:${Number(payload.panel_index)}`;
  }
  return "";
}

/**
 * Block server-driven reasoning tab activation when the user line refers to homework ordinals
 * ("second problem") rather than UI navigation ("second panel"). Mirrors
 * `should_block_reasoning_panel_activation_for_ordinal_problem` in actions/work_mode_reasoning.py.
 */
function shouldBlockOrdinalProblemLaneActivation(userText) {
  const s = String(userText || "").trim();
  if (!s) return false;
  const low = s.toLowerCase();
  if (/\b(?:reasoning\s+)?(?:panel|tab|lane)\b/i.test(low)) return false;
  if (/\breasoning\s+space\b/i.test(low)) return false;
  if (
    /\b(?:go\s+back\s+to|go\s+to|jump\s+to|switch\s+to|change\s+to|open|activate|show|select|use)\b[^.?!]{0,96}\b(?:reasoning\s+)?(?:panel|tab|lane|page)\b/i.test(
      low
    )
  ) {
    return false;
  }
  if (
    /\b(?:first|second|third|fourth|fifth|sixth|seventh|eighth|next|previous|last|prior)\s+(?:reasoning\s+)?(?:panel|tab|lane|page)\b/i.test(
      low
    )
  ) {
    return false;
  }
  if (/\b(?:panel|tab)\s*#?\s*\d{1,2}\b/i.test(low)) return false;
  if (
    /\b(?:first|second|third|fourth|fifth|next|previous|last|prior|other|another)\s+(?:problem|question|part|exercise)\b/i.test(
      low
    )
  ) {
    return true;
  }
  if (/\b(?:next|another)\s+(?:problem|question|part)\b/i.test(low)) return true;
  if (/\bproblem\s*(?:#|no\.?|number\s*)?\s*\d/i.test(low)) return true;
  if (/\bproblem\s*(?:#|no\.?)?\s*\d+\.\d+/i.test(low)) return true;
  if (/\b(?:ex\.?|exercise|question|q)\s*[#.]?\s*\d+/i.test(low)) return true;
  if (/\bthe\s+other\s+(?:problem|question|part)\b/i.test(low)) return true;
  if (
    /\b(?:this|that|the)\s+assignment(?:'s|s)?\s+(?:first|second|third|fourth|next|last)\s+part\b/i.test(
      low
    )
  ) {
    return true;
  }
  if (/\bpart\s*\d+\b/i.test(low)) return true;
  return false;
}

function inferUserTextForLaneActivationGuard(data) {
  return String(
    data?.transcript || (typeof window !== "undefined" && window.__veraLastInferUserTextForLaneGuard) || ""
  ).trim();
}

function shouldApplyWorkModeReasoningInvocation(payload) {
  const key = workModeReasoningDedupeKey(payload);
  if (!key) return true;
  const now = performance.now();
  const prev = window.__veraWorkModeReasoningDedupe;
  if (prev && prev.key === key && now - prev.at < 8000) return false;
  window.__veraWorkModeReasoningDedupe = { key, at: now };
  return true;
}

/**
 * Source-state tracker. Single source of truth for which music backend is
 * currently audible vs. paused-on-purpose vs. suspended-because-the-other-
 * source-took-over. The model matches the spec from 2026-05-29:
 *
 *   activeMusicSource   "builtin" | "spotify" | "none"
 *   builtinState        "playing" | "paused_by_user" | "suspended_for_spotify" | "stopped"
 *   spotifyState        "playing" | "paused_by_user" | "suspended_for_builtin" | "stopped"
 *
 * Crucial invariant: pause/stop for ONE source NEVER auto-resumes the
 * other. Suspended state is preserved across switches so an explicit
 * "play lo-fi" / "resume Spotify" can restore the prior position when
 * the user asks for it.
 */
function veraMusicSourceState() {
  if (!window.__veraMusicSourceState) {
    window.__veraMusicSourceState = {
      active: "none",
      builtin: {
        state: "stopped",
        currentTime: 0,
        playlistId: "",
        soundId: "",
        // Display fields kept independent of the live audio element so the
        // built-in tab can re-render its last known item even when Spotify
        // is the currently audible source.
        title: "",
        subtitle: "",
        cover_url: "",
        paused: true,
        position_ms: 0,
        duration_ms: 0,
        updatedAt: 0
      },
      spotify: {
        state: "stopped",
        uri: "",
        title: "",
        artist: "",
        playlist_id: "",
        playlist_name: "",
        cover_url: "",
        paused: true,
        position_ms: 0,
        duration_ms: 0,
        updatedAt: 0
      }
    };
  }
  const st = window.__veraMusicSourceState;
  // Backfill new fields on existing state objects so older sessions don't
  // miss the display sub-fields after a code update.
  if (st.builtin && st.builtin.title === undefined) {
    Object.assign(st.builtin, {
      title: "", subtitle: "", cover_url: "", paused: true,
      position_ms: 0, duration_ms: 0, updatedAt: 0
    });
  }
  if (st.spotify && st.spotify.cover_url === undefined) {
    Object.assign(st.spotify, {
      cover_url: "", paused: true, position_ms: 0, duration_ms: 0, updatedAt: 0
    });
  }
  return st;
}

/**
 * Update one source's UI display snapshot without touching the other.
 *
 * The music panel needs to remember what each tab was last showing
 * independently of which source is currently audible, so e.g. switching
 * to the Spotify tab after lo-fi was playing still shows the previous
 * Spotify track instead of "Nothing playing".
 *
 * Call this from whichever path actually changed the source's state —
 * builtin sync from the audio element, Spotify state from the Web SDK
 * or from a play call. Safe to call with partial updates.
 */
function captureMusicPanelDisplay(source, partial) {
  if (!partial || typeof partial !== "object") return;
  const st = veraMusicSourceState();
  let target = null;
  if (source === "builtin") target = st.builtin;
  else if (source === "spotify") target = st.spotify;
  if (!target) return;
  for (const key of Object.keys(partial)) {
    if (partial[key] === undefined) continue;
    target[key] = partial[key];
  }
  target.updatedAt = Date.now();
}

function veraMusicPanelDisplayHasData(source) {
  const st = veraMusicSourceState();
  const snap = source === "builtin" ? st.builtin : (source === "spotify" ? st.spotify : null);
  if (!snap) return false;
  return Boolean((snap.title || "").trim()) || Number(snap.updatedAt || 0) > 0;
}

function _captureBuiltinSnapshot() {
  const prefix = (typeof appModePrefix === "function") ? appModePrefix() : "vera";
  const free = document.getElementById(`${prefix}-free-music-audio`);
  const pb = window.__veraFreeMusicPlayback || {};
  return {
    currentTime: Number(free?.currentTime || 0),
    playlistId: String(pb.playlistId || ""),
    soundId: String(pb.soundId || ""),
    isPlaying: Boolean(free && !free.paused && Number(free.currentTime) > 0)
  };
}

function _captureSpotifySnapshot() {
  const last = window.__veraSpotifyLast || {};
  let isPlaying = false;
  try {
    const ns = (typeof spotifyEnsureNowState === "function") ? spotifyEnsureNowState() : null;
    if (ns) isPlaying = Boolean(ns.active) && !Boolean(ns.paused);
  } catch (_) {}
  return {
    uri: String(last.preview_url ? "" : (last.uri || "")) || "",
    title: String(last.title || ""),
    artist: String(last.artist || ""),
    playlist_id: String(window.__veraSpotifyActivePlaylistId || ""),
    playlist_name: String(window.__veraSpotifyActivePlaylistName || ""),
    isPlaying
  };
}

function musicSourceMarkPlaying(source, meta = {}) {
  const st = veraMusicSourceState();
  const newSource = String(source || "").toLowerCase();
  const activeBefore = st.active;
  const builtinStateBefore = st.builtin.state;
  const spotifyStateBefore = st.spotify.state;
  if (newSource === "builtin") {
    const priorBuiltinState = st.builtin.state;
    const priorBuiltinCurrentTime = Number(st.builtin.currentTime || 0);
    // Suspend Spotify if it was the active audible source — preserve its
    // metadata so an explicit "resume Spotify" can return to it.
    if (st.active === "spotify" && st.spotify.state === "playing") {
      st.spotify.state = "suspended_for_builtin";
    }
    st.active = "builtin";
    st.builtin.state = "playing";
    if (meta.playlistId !== undefined) st.builtin.playlistId = String(meta.playlistId || "");
    if (meta.soundId !== undefined) st.builtin.soundId = String(meta.soundId || "");
    if (meta.title !== undefined) st.builtin.title = String(meta.title || "");
    if (meta.subtitle !== undefined) st.builtin.subtitle = String(meta.subtitle || "");
    if (meta.currentTime !== undefined) {
      st.builtin.currentTime = Number(meta.currentTime || 0);
    } else if (priorBuiltinState === "suspended_for_spotify") {
      st.builtin.currentTime = priorBuiltinCurrentTime;
    } else {
      st.builtin.currentTime = 0;
    }
    st.builtin.paused = false;
    st.builtin.updatedAt = Date.now();
  } else if (newSource === "spotify") {
    if (st.active === "builtin" && st.builtin.state === "playing") {
      // Snapshot the current audio position before suspending so explicit
      // "play lo-fi" later can resume from the same spot when possible.
      const snap = _captureBuiltinSnapshot();
      st.builtin.state = "suspended_for_spotify";
      st.builtin.currentTime = snap.currentTime;
      st.builtin.paused = true;
    }
    st.active = "spotify";
    st.spotify.state = "playing";
    if (meta.uri !== undefined) st.spotify.uri = String(meta.uri || "");
    if (meta.title !== undefined) st.spotify.title = String(meta.title || "");
    if (meta.artist !== undefined) st.spotify.artist = String(meta.artist || "");
    if (meta.playlist_id !== undefined) st.spotify.playlist_id = String(meta.playlist_id || "");
    if (meta.playlist_name !== undefined) st.spotify.playlist_name = String(meta.playlist_name || "");
    if (meta.playlist_id) window.__veraSpotifyActivePlaylistId = String(meta.playlist_id || "");
    if (meta.playlist_name) window.__veraSpotifyActivePlaylistName = String(meta.playlist_name || "");
    st.spotify.paused = false;
    st.spotify.updatedAt = Date.now();
  }
  console.info("[music_source_state]", {
    transition: `${newSource}_play`,
    playback_source_changed: activeBefore !== st.active,
    playback_source_change_reason: meta.reason || "explicit_play",
    active_playback_source_before: activeBefore,
    active_playback_source_after: st.active,
    builtin_state_before: builtinStateBefore,
    builtin_state_after: st.builtin.state,
    builtin_title: st.builtin.title || "",
    builtin_current_time_preserved: st.builtin.state === "suspended_for_spotify"
      ? Number(st.builtin.currentTime || 0)
      : null,
    spotify_state_before: spotifyStateBefore,
    spotify_state_after: st.spotify.state,
    spotify_title: st.spotify.title || "",
    spotify_artist: st.spotify.artist || "",
    spotify_uri: st.spotify.uri || ""
  });
}

function musicSourceMarkPausedByUser() {
  // Generic "pause music" — pause whichever source is currently active and
  // mark it paused_by_user. Do NOT touch the suspended-source state: that
  // way "pause music" after a builtin→spotify switch stops audio without
  // accidentally resurrecting built-in lo-fi.
  const st = veraMusicSourceState();
  const prev = st.active;
  const builtinStateBefore = st.builtin.state;
  const spotifyStateBefore = st.spotify.state;
  if (prev === "builtin" && st.builtin.state === "playing") {
    st.builtin.state = "paused_by_user";
    st.builtin.paused = true;
  }
  if (prev === "spotify" && st.spotify.state === "playing") {
    st.spotify.state = "paused_by_user";
    st.spotify.paused = true;
  }
  st.active = "none";
  console.info("[music_source_state]", {
    transition: "pause_by_user",
    playback_source_changed: prev !== "none",
    playback_source_change_reason: "user_pause",
    active_playback_source_before: prev,
    active_playback_source_after: st.active,
    builtin_state_before: builtinStateBefore,
    builtin_state_after: st.builtin.state,
    builtin_title: st.builtin.title || "",
    spotify_state_before: spotifyStateBefore,
    spotify_state_after: st.spotify.state,
    spotify_title: st.spotify.title || "",
    spotify_artist: st.spotify.artist || "",
    spotify_paused_without_builtin_resume: prev === "spotify",
    blocked_auto_resume_reason:
      prev === "spotify" && st.builtin.state === "suspended_for_spotify"
        ? "spotify_paused_keep_builtin_suspended"
        : prev === "builtin" && st.spotify.state === "suspended_for_builtin"
          ? "builtin_paused_keep_spotify_suspended"
          : null
  });
}

/**
 * Stop whichever music source is currently audible before starting a new
 * one. Built-in `<audio>` elements and Spotify Web Playback can each be
 * playing independently — if a "play" payload arrives while another
 * source is active, the new track must take over instead of layering.
 *
 * source describes the NEW playback we're about to start:
 *   "builtin" → free-music audio element (lo-fi, rain, noise, etc.)
 *   "spotify" → Spotify track / album / playlist via VeraSpotify
 *   "unknown" → caller doesn't know yet; pause everything
 *
 * Always safe to call: never raises, never starts new playback, only
 * pauses what's already running.
 */
function stopCurrentMusicPlaybackBeforeNewPlay(source) {
  const newSource = String(source || "unknown").toLowerCase();
  const prefix = (typeof appModePrefix === "function") ? appModePrefix() : "vera";
  const free = document.getElementById(`${prefix}-free-music-audio`);
  const st = veraMusicSourceState();
  const activeBefore = st.active;
  const builtinStateBefore = st.builtin.state;
  const spotifyStateBefore = st.spotify.state;
  const builtinWasPlaying = Boolean(free && !free.paused && free.currentTime > 0);
  let spotifyWasPlaying = false;
  try {
    const ns = (typeof spotifyEnsureNowState === "function") ? spotifyEnsureNowState() : null;
    if (ns && Boolean(ns.active) && !Boolean(ns.paused)) {
      spotifyWasPlaying = true;
    }
  } catch (_) { /* getter may not exist on older builds */ }

  // Snapshot currentTime of built-in audio BEFORE we pause it so the
  // suspended-state preserves "where we were" for a later explicit
  // resume ("play lo-fi" after switching to Spotify and back).
  const builtinSnap = _captureBuiltinSnapshot();

  console.info("[music_dispatch]", {
    stop_current_music_before_new_play_called: true,
    new_source: newSource,
    builtin_music_was_playing: builtinWasPlaying,
    spotify_was_playing: spotifyWasPlaying,
    active_music_source_before: activeBefore,
    builtin_state_before: builtinStateBefore,
    spotify_state_before: spotifyStateBefore,
    builtin_current_time_preserved: builtinSnap.currentTime
  });

  let builtinStopped = false;
  let spotifyStopped = false;
  try {
    if (free && !free.paused) {
      free.pause();
      builtinStopped = true;
      if (typeof freeMusicSyncNowFromAudio === "function") freeMusicSyncNowFromAudio(prefix);
      if (typeof spotifySyncPlayButtonUi === "function") spotifySyncPlayButtonUi(prefix);
      // If we're switching to Spotify, mark built-in suspended (state may
      // be restored by an explicit "play lo-fi"). Switching to built-in
      // again with a fresh play is a no-op as the new play resets state.
      if (newSource === "spotify") {
        st.builtin.state = "suspended_for_spotify";
        st.builtin.currentTime = builtinSnap.currentTime;
        st.builtin.playlistId = builtinSnap.playlistId;
        st.builtin.soundId = builtinSnap.soundId;
      }
    }
  } catch (err) {
    console.warn("[music_dispatch] builtin_pause_failed", err);
  }
  try {
    const pause = window.VeraSpotify && window.VeraSpotify.pausePlayback;
    if (typeof pause === "function" && (spotifyWasPlaying || newSource === "builtin")) {
      // Pause Spotify whenever we're switching TO built-in. When switching
      // between Spotify tracks (play_track / play_album) Spotify itself
      // replaces the current track on the next play call, so an explicit
      // pause is only required when crossing the source boundary.
      void pause();
      spotifyStopped = true;
      if (newSource === "builtin" && spotifyWasPlaying) {
        st.spotify.state = "suspended_for_builtin";
      }
    }
  } catch (err) {
    console.warn("[music_dispatch] spotify_pause_failed", err);
  }
  console.info("[music_dispatch]", {
    new_source: newSource,
    builtin_music_stopped: builtinStopped,
    spotify_playback_stopped: spotifyStopped,
    active_music_source_after: st.active,
    builtin_state_after: st.builtin.state,
    spotify_state_after: st.spotify.state,
    builtin_suspended_for_spotify: st.builtin.state === "suspended_for_spotify",
    spotify_suspended_for_builtin: st.spotify.state === "suspended_for_builtin",
    builtin_auto_resume_blocked: true,
    spotify_auto_resume_blocked: true
  });
}

const VERA_NDJSON_PAYLOAD_DEDUPE_TTL_MS = 30000;

function veraNdjsonPayloadDedupeStore() {
  if (!window.__veraNdjsonPayloadDedupe || !(window.__veraNdjsonPayloadDedupe instanceof Map)) {
    window.__veraNdjsonPayloadDedupe = new Map();
  }
  return window.__veraNdjsonPayloadDedupe;
}

function makeNdjsonPayloadDedupeKey(event, payload, index) {
  const req =
    event?.request_id ||
    event?.client_request_id ||
    event?.requestId ||
    event?.session_id ||
    "no_request";
  const type = payload?.panel_type || payload?.type || "unknown_payload";
  const op = payload?.op || payload?.action || payload?.action_name || "no_op";
  return `${req}:${Number(index) || 0}:${type}:${op}`;
}

function applyNdjsonActionPayloadEvent(event, ndjsonEventType = "unknown") {
  const plural = Array.isArray(event?.action_payloads)
    ? event.action_payloads.filter(Boolean)
    : [];
  const payloads = plural.length ? plural : (event?.action_payload ? [event.action_payload] : []);
  const store = veraNdjsonPayloadDedupeStore();
  const now = Date.now();
  for (const [key, at] of store.entries()) {
    if (now - Number(at || 0) > VERA_NDJSON_PAYLOAD_DEDUPE_TTL_MS) store.delete(key);
  }

  console.info("[ndjson_payload_apply]", {
    ndjson_event_type: ndjsonEventType,
    action_payloads_received_count: payloads.length,
    used_plural_payloads: plural.length > 0,
    action_type: event?.action_type || "",
    request_id: event?.request_id || null
  });

  payloads.forEach((payload, idx) => {
    if (!payload || typeof payload !== "object") return;
    const key = makeNdjsonPayloadDedupeKey(event, payload, idx);
    const panelType = payload.panel_type || payload.type || "";
    const op = payload.op || "";
    const duplicate = store.has(key);
    console.info("[ndjson_payload_apply]", {
      ndjson_event_type: ndjsonEventType,
      applying_payload_index: idx,
      applying_payload_type: panelType,
      payload_op: op,
      dedupe_payload_key: key,
      skipped_duplicate_payload: duplicate,
      music_control_received: panelType === "music_control"
    });
    if (duplicate) return;
    store.set(key, now);
    applyActionPayload({ ...event, action_payload: payload, action_payloads: null });
  });
}

function applyActionPayload(data) {
  // 2026-05-29 — multi-action planner pass-through.
  // When the backend executed a typed compound command, every action's
  // ui_payload arrives in data.action_payloads in execution order. We
  // apply each one through this same function (recursive single-payload
  // dispatch) so every existing per-panel branch below keeps working
  // unchanged. We deliberately also apply data.action_payload at the end
  // when it's the FIRST payload (it duplicates data.action_payloads[0]
  // when both are present — skip in that case to avoid double-render).
  const planned = Array.isArray(data?.action_payloads) ? data.action_payloads.filter(Boolean) : [];
  if (planned.length > 1) {
    const seen = new WeakSet();
    planned.forEach((p, idx) => {
      if (!p || typeof p !== "object") return;
      if (seen.has(p)) return;
      seen.add(p);
      try {
        applyActionPayload({ ...data, action_payload: p, action_payloads: null });
      } catch (err) {
        console.warn("[planner] action_payloads dispatch failed", { idx, err });
      }
    });
    return;
  }
  const payload = data?.action_payload;
  const lockToMusicPanel =
    isVeraWorkModeOn() && appModePrefix() === "vera";

  if (
    lockToMusicPanel &&
    (payload?.panel_type === "media_tabs" ||
      payload?.panel_type === "news_results" ||
      payload?.panel_type === "finance_chart" ||
      payload?.panel_type === "product_results_panel" ||
      payload?.panel_type === "location_map_panel")
  ) {
    const sidePaneEl = uiEl("side-pane");
    if (sidePaneEl) {
      const hasProductivityMarkup =
        Boolean(sidePaneEl.innerHTML.trim()) && sidePaneEl.dataset.sidePaneKind === "productivity";
      if (hasProductivityMarkup) {
        if (sidePaneEl.hidden) restoreProductivityPanel("vera");
      } else {
        renderProductivityPanel();
      }
    }
    return;
  }

  if (payload?.panel_type === "media_tabs" || payload?.panel_type === "news_results") {
    /* Large innerHTML (news + images + video embeds) can block the main thread; defer so BMO mouth RAF keeps up. */
    requestAnimationFrame(() => renderMediaTabsPanel(payload));
    return;
  }

  /* News panel UI command — pure open/close, never a Work Mode reasoning
     panel switch. Backend emits this when the user says "open the news
     panel", "show news tab", "close news". The render path reuses the
     existing News Results panel surface (or hides it). Empty headlines
     are fine — the user asked for a UI surface, not a briefing. */
  if (payload?.panel_type === "news_panel_ui") {
    const op = (payload.op || "open").toLowerCase();
    if (op === "close") {
      hideSidePanel();
      console.info("[news_panel_ui]", { stage: "frontend", op: "close" });
      return;
    }
    /* op === "open" — render the news panel shell. If we have no fresh
       results, show an empty headlines placeholder so the panel surface
       exists and the user can use the tab controls. We deliberately do
       NOT trigger a Serper call here — the user only asked for the UI. */
    const openPayload = {
      panel_type: "news_results",
      title: payload.title || "News",
      query: payload.query || "Latest headlines",
      default_tab: "news",
      news_results: [],
      results: [],
      images: [],
      videos: [],
    };
    requestAnimationFrame(() => renderMediaTabsPanel(openPayload));
    console.info("[news_panel_ui]", { stage: "frontend", op: "open" });
    return;
  }

  if (payload?.panel_type === "finance_chart") {
    renderFinanceChartPanel(payload);
    return;
  }

  if (payload?.panel_type === "product_results_panel") {
    requestAnimationFrame(() => renderProductResultsPanel(payload));
    return;
  }

  if (payload?.panel_type === "location_map_panel") {
    requestAnimationFrame(() => renderLocationMapPanel(payload));
    return;
  }

  if (payload?.panel_type === "checklist_control") {
    try {
      markWorkChecklistLocalMutation();
      if (Array.isArray(payload.items)) {
        localStorage.setItem(WORK_CHECKLIST_STORAGE_KEY, JSON.stringify(payload.items));
      }
      if (typeof payload.completed_collapsed === "boolean") {
        localStorage.setItem(
          WORK_CHECKLIST_COMPLETED_COLLAPSED_KEY,
          payload.completed_collapsed ? "1" : "0"
        );
      }
      loadWorkChecklistItems();
      syncWorkChecklistHelpPlanButton();
    } catch (_) {}
    return;
  }

  if (payload?.panel_type === "work_mode_reasoning") {
    if (!shouldApplyWorkModeReasoningInvocation(payload)) return;
    if (!isVeraWorkModeOn() || appModePrefix() !== "vera") return;
    const op = payload.op || "";
    if (op === "open_new") {
      const count = Math.max(1, Math.min(REASONING_TABS_MAX, Number(payload.count) || 1));
      /* PART 5+6 (2026-05-28): tag each open with the backend-payload
         source so the recently-opened flag is set with provenance the
         dest-resolver log can show. */
      for (let i = 0; i < count; i += 1) {
        addReasoningTab({ source: "backend_open_panel_action" });
      }
      return;
    }
    /* PART 3: backend can also drive panel close (e.g. the LLM router sent
       back work_mode.reasoning_close_panel because the heuristic didn't
       fire, or via /infer for a typed command). The payload carries the
       parsed command shape from PART 14 and we re-run the executor here
       so the source of truth for index resolution + refill + active
       reselection stays in one place. */
    if (op === "close" || op === "close_panel" || op === "close_panels") {
      const userTextForClose = String(payload.user_text || "");
      /* PART 2: if the client-side shortcut already executed a close for
         this user turn, the backend round-trip is a stale echo. Skip the
         duplicate mutation; the bubble is already on screen. */
      if (_hasActiveReasoningCloseLock()) {
        logReasoningCloseConfirmationUiDebug({
          stage: "backend_payload_dedup_skip",
          close_panel_intent_detected: true,
          close_action_completed: true,
          confirmation_text: String(_peekReasoningCloseLock()?.confirmation || ""),
          confirmation_render_path: "assistant_bubble",
          confirmation_tts_enqueued: false,
          duplicate_confirmation_suppressed: true,
          action_result_consumed_by_normal_reply_pipeline: true,
          source: payload.reason || "backend_action_payload",
        });
        logReasoningClosePolishDebug({
          stage: "backend_payload_dedup_skip",
          reason: "client_lock_active",
          prev_lock: _peekReasoningCloseLock(),
          backend_op: op,
          backend_user_text: userTextForClose.slice(0, 200),
        });
        return;
      }
      const parsedRaw = payload.parsed && typeof payload.parsed === "object"
        ? payload.parsed
        : parseCloseReasoningPanelsCommand(userTextForClose, getReasoningPanelOrder().length);
      /* Backend "parsed" shape is the minimal subset; rerun the parser on
         the user text so we get the full scan/rank metadata and avoid
         losing the close-span deduplication logic. */
      const parsedFull = (parsedRaw && parsedRaw.allCloseSpans)
        ? parsedRaw
        : parseCloseReasoningPanelsCommand(userTextForClose, getReasoningPanelOrder().length);
      /* Use backend-provided slot if it carries info the user text doesn't
         expose (e.g. by_title where title came from LLM extraction). */
      const parsed = {
        ...parsedFull,
        ...(parsedRaw && parsedRaw.titleQuery ? { titleQuery: parsedRaw.titleQuery } : {}),
        ...(parsedRaw && (parsedRaw.closeScope === "by_title" || parsedRaw.closeScope === "reopen_last")
          ? { closeScope: parsedRaw.closeScope, parsedRangeType: parsedRaw.closeScope }
          : {}),
      };
      const exec = executeCloseReasoningPanelsCommand(parsed, {
        userText: userTextForClose,
        reason: payload.reason || "backend_action_payload",
      });
      /* PART 2: emit exactly one bubble — exec.confirmation when ok, or
         the failure reply otherwise. Backend's spoken_reply is NOT bubbled
         separately by us; the chat pipeline that delivered this payload
         is responsible for that. We set the lock so no further shortcuts
         in the same turn double-fire. */
      const reply = exec?.confirmation || buildCloseReasoningPanelsVoiceReply(exec, parsed);
      _setReasoningCloseLock({
        scope: parsed.closeScope,
        indices: parsed.indices || null,
        confirmation: reply,
        source: payload.reason || "backend_action_payload",
      });
      if (!exec.ok) {
        renderReasoningCloseAssistantConfirmation(reply, {
          path: "close-reasoning-panel-backend-failure",
          source: payload.reason || "backend_action_payload",
          isVoice: false,
          stage: "backend_payload_close_failure",
          closeActionCompleted: false,
        });
      } else {
        logReasoningCloseConfirmationUiDebug({
          stage: "backend_payload_close_success",
          close_panel_intent_detected: true,
          close_action_completed: true,
          confirmation_text: reply,
          confirmation_render_path: "assistant_bubble",
          confirmation_tts_enqueued: Boolean(
            !inputMuted &&
            !(appModePrefix() === "vera" && isVeraWorkModeOn() && isWorkModeMuteEnabled())
          ),
          duplicate_confirmation_suppressed: false,
          action_result_consumed_by_normal_reply_pipeline: true,
          source: payload.reason || "backend_action_payload",
        });
      }
      return;
    }
    if (op === "reopen_last") {
      if (_hasActiveReasoningCloseLock()) {
        logReasoningCloseConfirmationUiDebug({
          stage: "backend_payload_dedup_skip_reopen",
          close_panel_intent_detected: true,
          close_action_completed: true,
          confirmation_text: String(_peekReasoningCloseLock()?.confirmation || ""),
          confirmation_render_path: "assistant_bubble",
          confirmation_tts_enqueued: false,
          duplicate_confirmation_suppressed: true,
          action_result_consumed_by_normal_reply_pipeline: true,
          source: payload.reason || "backend_action_payload",
        });
        logReasoningClosePolishDebug({
          stage: "backend_payload_dedup_skip",
          reason: "client_lock_active",
          prev_lock: _peekReasoningCloseLock(),
          backend_op: op,
        });
        return;
      }
      const r = reopenLastClosedReasoningPanel({ userText: String(payload.user_text || "") });
      if (r.ok) {
        _setReasoningCloseLock({ scope: "reopen_last", indices: null, confirmation: "Bringing back the last closed panel.", source: payload.reason || "backend_action_payload" });
      }
      if (!r.ok && r.failureReason === "stack_empty") {
        renderReasoningCloseAssistantConfirmation("I don't have a recently closed panel to reopen.", {
          path: "reopen-reasoning-panel-empty-backend",
          source: payload.reason || "backend_action_payload",
          isVoice: false,
          stage: "backend_payload_reopen_empty",
          closeActionCompleted: false,
        });
      }
      return;
    }
    if (op === "activate" && payload.panel_index != null) {
      const idx = Number(payload.panel_index);
      if (!Number.isFinite(idx)) return;
      const guardText = inferUserTextForLaneActivationGuard(data);
      if (shouldBlockOrdinalProblemLaneActivation(guardText)) {
        console.info("[blocked_lane_activation]", {
          user_text: guardText,
          requested_panel_index: idx,
          reason: "ordinal_problem_not_tab_navigation"
        });
        return;
      }
      const panelEl = document.querySelector(
        `#vera-reasoning-tab-panels .vera-reasoning-tab-panel[data-tab-index="${idx}"]`
      );
      if (panelEl) {
        activateReasoningTab(idx, {
          commandText: guardText,
          requestedIndex: idx + 1,
          resolvedFrom: "visible_order",
        });
      }
      return;
    }
    return;
  }

  if (payload?.panel_type === "music_control") {
    const prefix = appModePrefix();
    const op = payload.op || "open_panel";
    console.info("[music_control_payload]", {
      music_control_received: true,
      op,
      playlist_id: payload.playlist_id || "",
      sound_id: payload.sound_id || "",
      source_event_type: data?.type || "",
      request_id: data?.request_id || null
    });
    if (op === "close_panel") {
      hideSidePanel();
      return;
    }
    if (op === "skip_next") {
      if (!shouldApplyMusicTransportAction(payload, op)) return;
      if (getProductivityMusicSource(prefix) === "builtin") {
        builtinMusicTransportSkipNext(prefix);
        return;
      }
      invokeSpotifyTransport("skip_next", { source: "command" });
      return;
    }
    if (op === "skip_previous") {
      if (!shouldApplyMusicTransportAction(payload, op)) return;
      console.log("[MUSIC][SKIP_PREV] applyActionPayload dispatch", {
        source: data?.type || "unknown",
        has_payload: Boolean(payload),
      });
      if (getProductivityMusicSource(prefix) === "builtin") {
        builtinMusicTransportSkipPrevious(prefix);
        return;
      }
      invokeSpotifyTransport("skip_previous", { source: "command" });
      return;
    }
    if (op === "pause") {
      const free = document.getElementById(`${prefix}-free-music-audio`);
      if (free && !free.paused) free.pause();
      const pause = window.VeraSpotify?.pausePlayback;
      if (typeof pause === "function") void pause();
      if (free && getProductivityMusicSource(prefix) === "builtin") {
        freeMusicSyncNowFromAudio(prefix);
        spotifySyncPlayButtonUi(prefix);
      }
      // Mark whichever source was active as paused_by_user and ensure
      // we never auto-resume the OTHER source (spec rule 6: a pause for
      // one source must not resurrect another).
      musicSourceMarkPausedByUser();
      return;
    }
    if (op === "resume") {
      if (getProductivityMusicSource(prefix) === "builtin") {
        const free = document.getElementById(`${prefix}-free-music-audio`);
        if (free?.src) {
          void free.play().then(() => {
            freeMusicSyncNowFromAudio(prefix);
            spotifySyncPlayButtonUi(prefix);
          });
          return;
        }
      }
      const resume = window.VeraSpotify?.resumePlayback;
      if (typeof resume === "function") void resume();
      return;
    }
    if (op === "volume_delta") {
      if (!shouldApplyMusicTransportAction(payload, op)) return;
      const cur = typeof window.VeraSpotify?.getVolume === "function"
        ? window.VeraSpotify.getVolume()
        : spotifyGetVolume();
      const setVolume = window.VeraSpotify?.setVolume;
      const next = Math.max(0, Math.min(SPOTIFY_VOLUME_MAX, Number(cur) + (Number(payload.delta) || 0)));
      if (typeof setVolume === "function") void setVolume(next);
      else {
        window.__veraSpotifyVolume = next;
        const free = document.getElementById(`${prefix}-free-music-audio`);
        if (free) free.volume = next;
        const preview = document.getElementById(`${prefix}-spotify-preview-audio`);
        if (preview) preview.volume = next;
      }
      return;
    }
    const skipPanelRepeat = isRecentSameMusicPlay(payload, op);
    const sidePaneEl = uiEl("side-pane");
    if (sidePaneEl && !skipPanelRepeat) {
      const hasProductivityMarkup =
        Boolean(sidePaneEl.innerHTML.trim()) && sidePaneEl.dataset.sidePaneKind === "productivity";
      document.querySelectorAll(".productivity-mode-btn").forEach((b) => b.classList.remove("is-active"));
      if (hasProductivityMarkup) {
        if (sidePaneEl.hidden) restoreProductivityPanel(prefix);
      } else {
        renderProductivityPanel();
      }
      document.getElementById(`${prefix}-productivity-mode`)?.classList.add("is-active");
    }
    if (op === "play_builtin" && shouldPlayMusicThisInvocation(payload, op)) {
      const sourceStateBeforeBuiltinPlay = veraMusicSourceState();
      const preservedBuiltinTime =
        sourceStateBeforeBuiltinPlay.builtin.state === "suspended_for_spotify"
          ? Number(sourceStateBeforeBuiltinPlay.builtin.currentTime || 0)
          : 0;
      stopCurrentMusicPlaybackBeforeNewPlay("builtin");
      musicSourceMarkPlaying("builtin", {
        playlistId: payload.playlist_id || "",
        soundId: payload.sound_id || "",
        currentTime: preservedBuiltinTime
      });
      void (async () => {
        const pfx = appModePrefix();
        console.info("[music_control_payload]", {
          music_play_op: "play_builtin",
          play_builtin_called: true,
          playback_backend: "builtin_audio",
          playlist_id: payload.playlist_id || "",
          sound_id: payload.sound_id || "",
          request_id: data?.request_id || null
        });
        try {
          await runBuiltinVoicePlayback(pfx, {
            playlistId: payload.playlist_id,
            soundId: payload.sound_id
          });
          if (preservedBuiltinTime > 0) {
            const free = document.getElementById(`${pfx}-free-music-audio`);
            if (free && Number.isFinite(free.duration) && preservedBuiltinTime < free.duration) {
              try {
                free.currentTime = preservedBuiltinTime;
                freeMusicSyncNowFromAudio(pfx);
                console.info("[music_source_state]", {
                  builtin_resume_from_preserved_time: true,
                  builtin_current_time_preserved: preservedBuiltinTime,
                  active_music_source_after: "builtin"
                });
              } catch (_) {
                /* keep playback going even if seeking fails */
              }
            }
          }
          console.info("[music_control_payload]", {
            music_play_op: "play_builtin",
            playback_started: true,
            playback_backend: "builtin_audio",
            playlist_id: payload.playlist_id || "",
            sound_id: payload.sound_id || "",
            request_id: data?.request_id || null
          });
        } catch (err) {
          console.warn("[music_control_payload]", {
            music_play_op: "play_builtin",
            playback_error: String(err && err.message || err || "unknown"),
            playback_backend: "builtin_audio",
            request_id: data?.request_id || null
          });
        }
      })();
    } else if (op === "play_track" && payload.uri && shouldPlayMusicThisInvocation(payload, op)) {
      stopCurrentMusicPlaybackBeforeNewPlay("spotify");
      musicSourceMarkPlaying("spotify", {
        uri: payload.uri,
        title: payload.title || "",
        artist: payload.artist || ""
      });
      const play = window.VeraSpotify?.playTrack;
      console.info("[music_control_payload]", {
        music_play_op: "play_track",
        playback_backend: "spotify",
        spotify_playtrack_available: typeof play === "function",
        title: payload.title || "",
        artist: payload.artist || "",
        requested_spotify_uri: String(payload.uri || ""),
        spotify_play_called_with_uri: Boolean(payload.uri),
        blocked_resume_for_new_track: true,
        request_id: data?.request_id || null
      });
      if (typeof play === "function") {
        void Promise.resolve(play(String(payload.uri), {
          title: payload.title || "",
          artist: payload.artist || "",
          preview_url: payload.preview_url || "",
          open_url: payload.open_url || ""
        })).then(() => {
          console.info("[music_control_payload]", {
            music_play_op: "play_track",
            playback_started: true,
            playback_backend: "spotify",
            request_id: data?.request_id || null
          });
        }).catch((err) => {
          console.warn("[music_control_payload]", {
            music_play_op: "play_track",
            playback_error: String(err && err.message || err || "unknown"),
            playback_backend: "spotify",
            request_id: data?.request_id || null
          });
        });
      }
    } else if (op === "play_playlist_scoped" && shouldPlayMusicThisInvocation(payload, op)) {
      // New op for "play X in my playlist" — search WITHIN the user's
      // active Spotify playlist (set by their last interaction with a
      // playlist context) instead of doing a global Spotify search.
      // If no playlist context is known we surface a clear "which
      // playlist" message in the spotify-track-artist line.
      const rawQuery = String(payload.query || "").trim();
      const playlistId = String(payload.playlist_id || window.__veraSpotifyActivePlaylistId || "").trim();
      const playlistName = String(payload.playlist_name || window.__veraSpotifyActivePlaylistName || "").trim();
      console.info("[music_control_payload]", {
        music_play_op: "play_playlist_scoped",
        playback_backend: "spotify",
        playlist_scope_query: rawQuery,
        selected_playlist_id: playlistId,
        selected_playlist_name: playlistName,
        current_playlist_context_available: Boolean(playlistId),
        generic_track_search_blocked: true,
        request_id: data?.request_id || null
      });
      const artistEl = document.getElementById(`${prefix}-spotify-track-artist`);
      if (!playlistId) {
        if (artistEl) artistEl.textContent = "Which playlist should I search?";
        console.info("[music_control_payload]", {
          music_play_op: "play_playlist_scoped",
          clarification_asked: true,
          request_id: data?.request_id || null
        });
        return;
      }
      stopCurrentMusicPlaybackBeforeNewPlay("spotify");
      void (async () => {
        const getTracks = window.VeraSpotify?.getPlaylistTracks;
        if (typeof getTracks !== "function") {
          if (artistEl) artistEl.textContent = "Playlist search is not available right now.";
          return;
        }
        let tracks = [];
        try {
          tracks = await getTracks(playlistId);
        } catch (err) {
          if (artistEl) artistEl.textContent = "Couldn't load that playlist's tracks.";
          console.warn("[music_control_payload]", {
            music_play_op: "play_playlist_scoped",
            playback_error: String(err && err.message || err || "unknown"),
            request_id: data?.request_id || null
          });
          return;
        }
        const needle = rawQuery.toLowerCase();
        // Light fuzzy match: exact title substring beats artist substring,
        // and we require at least one needle token (length >= 3) to appear
        // in the title to call it a confident match. Without this guard
        // the planner would pick a random track for short queries.
        const tokens = needle.split(/\s+/).filter((t) => t && t.length >= 3);
        let best = null;
        let bestScore = 0;
        for (const t of (tracks || [])) {
          const title = String(t.name || t.title || "").toLowerCase();
          const artistLine = (Array.isArray(t.artists)
            ? t.artists.map((a) => a?.name || "").join(", ")
            : String(t.artist || "")).toLowerCase();
          let score = 0;
          if (title === needle) score = 1.0;
          else if (title.includes(needle)) score = 0.9;
          else if (tokens.length && tokens.every((tok) => title.includes(tok))) score = 0.75;
          else if (artistLine.includes(needle)) score = 0.5;
          if (score > bestScore) {
            bestScore = score;
            best = t;
          }
        }
        const confident = best && bestScore >= 0.75;
        console.info("[music_control_payload]", {
          music_play_op: "play_playlist_scoped",
          playlist_match_title: best ? (best.name || best.title || "") : "",
          playlist_match_confidence: bestScore,
          playlist_track_played: Boolean(confident),
          playlist_track_not_found: !confident,
          request_id: data?.request_id || null
        });
        if (!confident) {
          if (artistEl) artistEl.textContent = `I couldn't find "${rawQuery}" in ${playlistName || "that playlist"}.`;
          return;
        }
        const uri = String(best.uri || "");
        if (!uri) {
          if (artistEl) artistEl.textContent = `Found "${best.name || best.title}" but couldn't play it.`;
          return;
        }
        const title = String(best.name || best.title || "");
        const artistStr = Array.isArray(best.artists)
          ? best.artists.map((a) => a?.name || "").filter(Boolean).join(", ")
          : String(best.artist || "");
        musicSourceMarkPlaying("spotify", {
          uri,
          title,
          artist: artistStr,
          playlist_id: playlistId,
          playlist_name: playlistName
        });
        const playFn = window.VeraSpotify?.playTrack;
        if (typeof playFn !== "function") {
          if (artistEl) artistEl.textContent = "Spotify playback is not available.";
          return;
        }
        try {
          await playFn(uri, { title, artist: artistStr });
          console.info("[music_control_payload]", {
            music_play_op: "play_playlist_scoped",
            playback_started: true,
            playback_backend: "spotify",
            spotify_play_called_with_uri: true,
            requested_spotify_uri: uri,
            new_spotify_track: `${title} — ${artistStr}`,
            request_id: data?.request_id || null
          });
        } catch (err) {
          console.warn("[music_control_payload]", {
            music_play_op: "play_playlist_scoped",
            playback_error: String(err && err.message || err || "unknown"),
            request_id: data?.request_id || null
          });
        }
      })();
    } else if (op === "play_album" && payload.uri && shouldPlayMusicThisInvocation(payload, op)) {
      stopCurrentMusicPlaybackBeforeNewPlay("spotify");
      musicSourceMarkPlaying("spotify", {
        uri: payload.uri,
        title: payload.title || "",
        artist: payload.artist || ""
      });
      const playCtx = window.VeraSpotify?.playPlaylist;
      if (typeof playCtx === "function") {
        void (async () => {
          const prefix = appModePrefix();
          const base = localBackendBase();
          const uri = String(payload.uri || "").trim();
          const title = payload.title || "";
          const artist = payload.artist || "";
          const sub = artist ? `"${title}" by "${artist}"` : `"${title}"`;
          const openUrl = String(payload.open_url || spotifyUriToOpenUrl(uri) || "").trim();
          const st = await fetch(`${base}/api/spotify/connection-status`, {
            credentials: "include",
            headers: { ...veraSpotifyAuthHeaders() }
          })
            .then((r) => (r.ok ? r.json() : { connected: false }))
            .catch(() => ({ connected: false }));
          const artistEl = document.getElementById(`${prefix}-spotify-track-artist`);
          if (st.connected) {
            await playCtx(uri, { playlist_name: title, context_subtitle: sub });
          } else if (openUrl) {
            window.open(openUrl, "_blank", "noopener,noreferrer");
            if (artistEl) {
              artistEl.textContent =
                `${artist ? `${artist} — ` : ""}Opened Spotify in a new tab (connect for in-page playback).`.trim();
            }
          } else if (artistEl) {
            artistEl.textContent = "Connect Spotify to play this album in VERA.";
          }
        })();
      }
    } else if (op === "play_playlist_by_name") {
      const rawName = String(payload.playlist_name || "").trim();
      if (rawName && shouldPlayMusicThisInvocation(payload, op)) {
        void (async () => {
          const prefix = appModePrefix();
          const built = matchBuiltinPlaylistOrSoundNameForClient(rawName);
          if (built) {
            stopCurrentMusicPlaybackBeforeNewPlay("builtin");
            musicSourceMarkPlaying("builtin", {
              playlistId: built.playlistId || "",
              soundId: built.soundId || ""
            });
            console.info("[music_control_payload]", {
              music_play_op: "play_playlist_by_name",
              playback_backend: "builtin_audio",
              playlist_name: rawName,
              request_id: data?.request_id || null
            });
            await runBuiltinVoicePlayback(prefix, built);
            return;
          }
          const getLists = window.VeraSpotify?.getPlaylists;
          const playCtx = window.VeraSpotify?.playPlaylist;
          const artistEl = document.getElementById(`${prefix}-spotify-track-artist`);
          if (typeof getLists !== "function" || typeof playCtx !== "function") {
            if (artistEl) artistEl.textContent = "Playlist playback is not available.";
            return;
          }
          const lists = await getLists().catch(() => []);
          const needle = rawName.toLowerCase();
          let hit =
            lists.find((p) => String(p.name || "").toLowerCase() === needle) ||
            lists.find((p) => String(p.name || "").toLowerCase().includes(needle));
          if (!hit && needle.length >= 3) {
            hit = lists.find((p) => needle.includes(String(p.name || "").toLowerCase()));
          }
          if (!hit?.uri) {
            if (artistEl) artistEl.textContent = `No playlist in your library matched "${rawName}".`;
            console.info("[music_control_payload]", {
              music_play_op: "play_playlist_by_name",
              playlist_match_title: "",
              playlist_track_not_found: true,
              generic_track_search_blocked: true,
              request_id: data?.request_id || null
            });
            return;
          }
          const disp = hit.name || rawName;
          stopCurrentMusicPlaybackBeforeNewPlay("spotify");
          musicSourceMarkPlaying("spotify", {
            uri: hit.uri,
            playlist_id: String(hit.id || hit.uri || ""),
            playlist_name: disp
          });
          console.info("[music_control_payload]", {
            music_play_op: "play_playlist_by_name",
            playback_backend: "spotify",
            requested_spotify_query: rawName,
            requested_spotify_uri: hit.uri,
            spotify_playlist_play_called_with_uri: true,
            blocked_resume_for_new_play_request: true,
            generic_track_search_blocked: true,
            request_id: data?.request_id || null
          });
          await playCtx(hit.uri, {
            playlist_name: disp,
            context_subtitle: `"${disp}" in my playlist`
          });
        })();
      }
    }
    return;
  }

  /* Keep the music panel open across normal assistant replies unless a new panel payload replaces it. */
  const sidePaneEl = uiEl("side-pane");
  if (
    sidePaneEl &&
    !sidePaneEl.hidden &&
    sidePaneEl.dataset.sidePaneKind === "productivity"
  ) {
    return;
  }

  hideSidePanel();
}

/** News/finance side panel + assistant bubble — call when main reply audio actually starts (not when LLM JSON/meta arrives). */
function applyAssistantReplyAndPanels(data) {
  if (!data) return;
  if (data.work_mode_timer) {
    applyWorkModeTimerPayload(data.work_mode_timer);
  }
  applyActionPayload(data);
  if (data.reply == null || data.reply === "") return;
  // Real reply is taking over — drop the "Searching news…" placeholder
  // before the actual assistant bubble appears so the user only sees the
  // final answer (no double-bubble flash).
  cancelPendingNewsStatusBubble("assistant_reply_applied");
  addBubble(data.reply, "vera");
}

function createNdjsonStreamingReplyState(initialReplyBack = null, opts = {}) {
  return {
    bubble: null,
    latest: "",
    pendingVoiceQuote: replyBackQuoteText(initialReplyBack),
    pendingReplyBack: initialReplyBack,
    /** When true, ignore streamed reply_so_far until finalize sets the canonical line. */
    suppressReplyProgress: Boolean(opts.suppressReplyProgress),
    stage2EffectiveLocked: false
  };
}

/**
 * Grow one assistant bubble as each NDJSON chunk includes reply_so_far (sentence-cumulative text).
 */
function applyNdjsonStreamingReplySoFar(replySoFar, state) {
  if (replySoFar == null || replySoFar === "") return;
  if (state?.suppressReplyProgress || state?.stage2EffectiveLocked) return;
  state.latest = String(replySoFar);
  const convoEl = uiEl("conversation");
  if (!convoEl) return;
  const text = state.latest;
  if (state.bubble?.isConnected) {
    const cur = state.bubble.textContent || "";
    /* Done line can arrive before deferred first play; finalize may have filled the full reply — don't overwrite with a shorter cumulative partial. */
    if (text.length >= cur.length) {
      state.bubble.textContent = text;
    }
  } else {
    // Streaming reply is about to create the real bubble — drop the
    // "Searching news…" placeholder so they don't sit side-by-side.
    cancelPendingNewsStatusBubble("ndjson_reply_so_far");
    let opts = { path: "ndjson-reply-so-far" };
    if (state.pendingReplyBack) {
      opts = mergeReplyBackIntoBubbleMeta(opts, state.pendingReplyBack);
      state.pendingReplyBack = null;
      state.pendingVoiceQuote = null;
    }
    state.bubble = addBubble(text, "vera", opts);
  }
  convoEl.scrollTop = convoEl.scrollHeight;
  persistVeraChatState();
}

/** After NDJSON done: sync bubble to final reply, or add bubble if no streaming partials. */
function finalizeNdjsonStreamingReply(ndjsonMeta, done, state) {
  if (!done?.reply) return;
  const merged = {
    ...(ndjsonMeta && typeof ndjsonMeta === "object" ? ndjsonMeta : {}),
    ...done,
    reply: done.reply
  };
  if (
    !state.pendingReplyBack &&
    merged.work_mode_voice_brief_completion === true &&
    merged.work_mode_voice_quote != null &&
    String(merged.work_mode_voice_quote).trim()
  ) {
    const q = String(merged.work_mode_voice_quote).trim();
    if (q) {
      state.pendingVoiceQuote = q;
      state.pendingReplyBack = {
        reply_to_user_text: q,
        reply_to_turn_id: "",
        reply_to_lane_id: "",
        reply_to_lane_title: "",
        stage: 2
      };
    }
  }
  const pay = merged?.action_payload;
  const op = pay?.op;
  if (
    pay?.panel_type === "music_control" &&
    (op === "skip_next" || op === "skip_previous" || op === "play_builtin")
  ) {
    applyActionPayload(merged);
  }
  /* Work Mode Stage 2: one bubble with reply-back is created via ensureStage2VoiceBubble after resolve. */
  if (state?.suppressReplyProgress) {
    state.latest = String(done.reply || "");
    state.stage2EffectiveLocked = true;
    persistVeraChatState();
    return;
  }
  if (state.bubble?.isConnected) {
    state.bubble.textContent = done.reply;
    state.stage2EffectiveLocked = true;
    persistVeraChatState();
    return;
  }
  /* Must assign state.bubble so applyNdjsonStreamingReplySoFar doesn't add a second bubble if done arrives before first audio (defer path). */
  applyActionPayload(merged);
  // Streaming finalized without ever calling onReplyProgress (no partials),
  // so we drop the pending bubble here just before creating the final one.
  cancelPendingNewsStatusBubble("ndjson_finalize");
  let finOpts = { path: "ndjson-final" };
  if (state.pendingReplyBack) {
    finOpts = mergeReplyBackIntoBubbleMeta(finOpts, state.pendingReplyBack);
    state.pendingReplyBack = null;
    state.pendingVoiceQuote = null;
  }
  state.bubble = addBubble(done.reply, "vera", finOpts);
  state.stage2EffectiveLocked = true;
  persistVeraChatState();
}

/** Stops TTS and resets interrupt UI counters (shared by heuristic + browser barge-in). */
function cancelBrowserInterruptTtsOnly() {
  /* PART 1 — record entry into the shared cancel path. */
  _recordInterruptTimingPoint("t5_interruptSpeech_entered", {
    extra: { gatePath: "cancelBrowserInterruptTtsOnly" },
  });
  /* PART 1/3 — t8: UI flipped from speaking → interrupted. */
  _recordInterruptTimingPoint("t8_ui_state_set_interrupted");
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    "interrupted",
    "interrupt_browser_or_single_asr",
    "cancelBrowserInterruptTtsOnly"
  );
  setStatus("Listening… (interrupted)", "recording");
  resetAudioHandlers();
  cancelMainTtsPlayback();
  const a = getAudioEl();
  if (a) {
    a.pause();
    a.currentTime = 0;
  }
  /* PART 1 — t11: audio element paused after cancel. */
  _recordInterruptTimingPoint("t11_audio_audibly_stopped", {
    extra: { path: "cancelBrowserInterruptTtsOnly" },
  });
  /* PART 1/3 — t9: voice state flipped to listening. */
  _logVoiceStateTransition(
    "interrupted",
    "listening",
    "cancelBrowserInterruptTtsOnly_complete",
    "cancelBrowserInterruptTtsOnly"
  );
  listening = true;
  processing = false;
  waveState = "listening";
  _recordInterruptTimingPoint("t9_ui_state_set_listening");
  interruptSpeechFrames = 0;
  interruptSpeechStart = 0;
  interruptSpeechAccumMs = 0;
  lastInterruptDetectTime = 0;
  interruptLastSpeechLikeTime = 0;
  lastInterruptSpeechLikeSnapshot = null;
  interruptLastVoiceTime = performance.now();
  /* PART 1 — flush trace on next tick to capture any tail t10/t11 events. */
  try {
    setTimeout(
      () => _flushInterruptDelayTrace("cancelBrowserInterruptTtsOnly_complete"),
      0
    );
  } catch (_) {}
}

function promoteInterruptPreviewToMainLiveBubble() {
  if (interruptDetectionBubbleEl?.isConnected) {
    mainBrowserLiveBubble = interruptDetectionBubbleEl;
    interruptDetectionBubbleEl = null;
    try {
      mainBrowserLiveBubble.classList.remove("interrupt-preview");
    } catch (_) {}
  }
}

/**
 * Browser ASR: >2 words ⇒ stop TTS; keep the same SpeechRecognition session and use 1.3s stable transcript → LLM.
 * (Does not start a second recognition — that was the old post-interrupt listener.)
 */
function onBrowserInterruptBargeInFromDetect(event) {
  if (interruptBargeInLatched) return;
  interruptBargeInLatched = true;
  const commitAt = performance.now();
  vadFastStopAsrFinalAt = commitAt;
  /* PART 1 — t5: barge-in handler entered. */
  _recordInterruptTimingPoint("t5_interruptSpeech_entered", {
    extra: { gatePath: "onBrowserInterruptBargeInFromDetect" },
  });
  // Latency telemetry: if the fast VAD stop already fired earlier in
  // this TTS turn, report the gap between the two events so we can see
  // exactly how much speak-over time was saved. If the heuristic never
  // fired (rare on desktop, common in PTT), the ASR path was the only
  // gate; both metrics become null/0 in that case.
  const vadFiredEarlier = vadFastStopFiredAt > 0;
  logBargeInLatencyDebug("final_asr_received", {
    tts_playing: isAssistantTtsPlaying(),
    tts_id: vadFastStopTtsId || interruptPrearmTtsId || null,
    delay_vad_to_tts_stop_ms: vadFiredEarlier
      ? Number((vadFastStopTtsStoppedAt - vadFastStopFiredAt).toFixed(2))
      : null,
    delay_vad_to_final_asr_ms: vadFiredEarlier
      ? Number((vadFastStopAsrFinalAt - vadFastStopFiredAt).toFixed(2))
      : null,
    audio_already_stopped_by_vad: vadFiredEarlier,
    note: vadFiredEarlier
      ? "TTS stopped on VAD; final ASR transcript routes intent"
      : "no early VAD trigger; ASR alone drove this barge-in"
  });
  cancelBrowserInterruptTtsOnly();
  promoteInterruptPreviewToMainLiveBubble();
  mainBrowserFinalizeKind = "interrupt";

  let interimBuf = "";
  let finalP = "";
  let _sawFinal = false;
  for (let i = 0; i < event.results.length; i++) {
    const r = event.results[i];
    if (r.isFinal) {
      const piece = r[0].transcript;
      finalP += piece;
      _sawFinal = true;
      logPartialAsrSegmentFinal(piece.trim(), { mode: "interrupt-barge" });
    } else {
      interimBuf += r[0].transcript;
    }
  }
  /* PART 1 — t3: first final fragment from the browser SR (if any).
     Useful to verify TTS cancel did NOT wait for this point. */
  if (_sawFinal) {
    _recordInterruptTimingPoint("t3_final_transcript_available", {
      extra: { finalLen: finalP.length },
    });
  }
  mainBrowserFinalTranscript = finalP;
  mainBrowserLastInterim = interimBuf;
  const _wasSpokenInterruptOnResult = hasSpoken;
  hasSpoken =
    mainBrowserFinalTranscript.trim().length > 0 || interimBuf.trim().length > 0;
  if (hasSpoken && !_wasSpokenInterruptOnResult) {
    armVoiceMaxDurationTimer("browser_asr_first_partial_interrupt");
  }
  if (hasSpoken && speechWaitTimeoutId != null) {
    clearTimeout(speechWaitTimeoutId);
    speechWaitTimeoutId = null;
  }
  updateMainBrowserLiveBubble(mainBrowserFinalTranscript, interimBuf);
  logInterruptTranscriptDebug("capture_committed", {
    included_preroll_ms: 0,
    live_capture_started_at_ms: Number((interruptPartialLastChangeAt || commitAt).toFixed(1)),
    bubble_created_at_ms: Number(commitAt.toFixed(1)),
    asr_request_started_at_ms: null,
    browser_asr_live_stream: true
  });
  scheduleMainBrowserEndOfUtterance();
}

/* interruptSpeech → moved to voice/interruption.js (Stage 6, 2026-05-27). */

function detectInterrupt() {
  if (!analyser) {
    requestAnimationFrame(detectInterrupt);
    return;
  }

  /*
   * Previously: when the browser-ASR detector was alive on desktop, the
   * heuristic RAF loop returned early — meaning TTS only stopped AFTER
   * Chrome's Web Speech API produced enough words. That added 300-700ms
   * of "VERA talking over me" latency.
   *
   * New behaviour: the heuristic loop ALWAYS runs while TTS is playing.
   * In browser-ASR mode we still defer the full barge-in transition
   * (bubble promotion, transcript routing) to the SR session — but we
   * use VAD as a fast audio-only kill switch via fastStopTtsOnVadOnly().
   * That keeps intent classification on the SR transcript (per spec)
   * while removing the user-perceived speak-over latency.
   */
  const browserAsrParallelMode =
    browserAsrPreferred() && !isNarrowViewport() && !!interruptDetectRecognition;

  const buf = new Float32Array(analyser.fftSize);
  analyser.getFloatTimeDomainData(buf);

  // RMS
  let sum = 0;
  for (let i = 0; i < buf.length; i++) sum += buf[i] * buf[i];
  const rms = Math.sqrt(sum / buf.length);

  // ZCR (voicing) + crest (reject single sharp transients from bumps/clicks)
  const zcr = computeZCR(buf);
  let peak = 0;
  for (let i = 0; i < buf.length; i++) {
    const a = Math.abs(buf[i]);
    if (a > peak) peak = a;
  }
  const crest = peak / (rms + 1e-8);

  const now = performance.now();

  // Only interrupt while main TTS is playing: single-file uses <audio>; chunked/streaming uses Web Audio BufferSources.
  const outAudio = getAudioEl();
  const htmlAudioPlaying = outAudio && !outAudio.paused;
  const webAudioMainTtsPlaying =
    activeMainTtsBufferSources.length > 0 || mainTtsPlaybackActive;

  /* DEBUG: RAF gap measurement. If the main thread stalls (e.g. news
     panel render), detectInterrupt RAF frames are dropped and VAD
     accumulates wall-clock without contributing to interrupt detection.
     We log any gap > 100ms while TTS is playing. */
  if (isVeraInterruptDebugEnabled()) {
    try {
      if (_veraInterruptRafLastAt > 0) {
        const gapMs = now - _veraInterruptRafLastAt;
        if (gapMs > 100 && (htmlAudioPlaying || webAudioMainTtsPlaying)) {
          logVeraInterruptDebug({
            tag: "interrupt_raf_gap",
            now: Number(now.toFixed(1)),
            gapMs: Number(gapMs.toFixed(1)),
            duringNewsRender: _veraNewsPanelRenderInFlight,
            ttsPlaying: Boolean(htmlAudioPlaying || webAudioMainTtsPlaying)
          });
        }
      }
      _veraInterruptRafLastAt = now;
    } catch (_) {}
  }

  if (
  listeningMode === "continuous" &&
  (htmlAudioPlaying || webAudioMainTtsPlaying)
) {
    // grace period to avoid clicks
    if (now - audioStartedAt > 200) {
      const dtRaw = lastInterruptDetectTime ? now - lastInterruptDetectTime : 0;
      const dt = Math.min(Math.max(dtRaw, 0), 80);
      lastInterruptDetectTime = now;

      const heuristicChecks = computeHeuristicInterruptChecks(rms, zcr, crest);
      const speechLike = heuristicChecks.passes;

      /* DEBUG: throttled VAD frame log (max ~once per 250ms) so we can
         see whether detectInterrupt is firing at all while news TTS
         plays, and whether accumulated speech is approaching the sustain
         threshold. */
      logVeraInterruptDebug(
        {
          tag: "interrupt_vad_frame",
          now: Number(now.toFixed(1)),
          listeningMode,
          asrMode: (function () { try { return getVeraAsrMode(); } catch (_) { return null; } })(),
          browserAsrPreferred: (function () { try { return browserAsrPreferred(); } catch (_) { return null; } })(),
          browserAsrParallelMode,
          assistantTtsPlaying: (function () { try { return isAssistantTtsPlaying(); } catch (_) { return null; } })(),
          mainTtsPlaybackActive,
          activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
          htmlAudioPlaying: Boolean(htmlAudioPlaying),
          rms: Number(rms.toFixed(5)),
          zcr: Number(zcr.toFixed(4)),
          crest: Number(crest.toFixed(2)),
          speechLike,
          vadAccumMs: Number(interruptSpeechAccumMs.toFixed(1)),
          sustainThresholdMs: getInterruptSustainMs(),
          vadThresholdPassed:
            speechLike &&
            interruptSpeechFrames + 1 >= INTERRUPT_MIN_FRAMES &&
            interruptSpeechAccumMs + dt >= getInterruptSustainMs(),
          interruptRecording,
          vadFastStopArmed,
          activeNdjsonBodyReaderPresent: Boolean(activeNdjsonBodyReader),
          audioStartedAt: Number(Number(audioStartedAt || 0).toFixed(1)),
          timeSinceTtsStartMs: Number((now - (audioStartedAt || now)).toFixed(1)),
          duringNewsRender: _veraNewsPanelRenderInFlight
        },
        { throttleKey: "interrupt_vad_frame", throttleMs: 250 }
      );

      if (speechLike) {
        interruptSpeechAccumMs += dt;
        if (interruptSpeechFrames === 0) {
          interruptSpeechStart = now;
          /* PART 1 — t0: first speech-like VAD frame. autoStart=true so
             the trace begins here even if the browser SR never reports
             interim transcripts (single-ASR / whisper mode). */
          _recordInterruptTimingPoint("t0_user_speech_audio_detected", {
            autoStart: true,
            extra: {
              rms: Number(rms.toFixed(5)),
              zcr: Number(zcr.toFixed(4)),
              crest: Number(crest.toFixed(2)),
              browserAsrParallelMode,
              timeSinceTtsStartMs: Number((now - (audioStartedAt || now)).toFixed(1)),
            },
          });
        }
        interruptSpeechFrames++;
        interruptLastSpeechLikeTime = now;
        lastInterruptSpeechLikeSnapshot = {
          rms,
          zcr,
          crest,
          heuristicChecks,
          at: now,
        };
      } else if (
        interruptLastSpeechLikeTime &&
        now - interruptLastSpeechLikeTime <= INTERRUPT_GAP_RESET_MS
      ) {
        // Allow tiny gaps so normal speech doesn't need a perfect uninterrupted stream (time here does not add to interruptSpeechAccumMs).
      } else {
        interruptSpeechFrames = 0;
        interruptSpeechStart = 0;
        interruptSpeechAccumMs = 0;
        interruptLastSpeechLikeTime = 0;
        lastInterruptSpeechLikeSnapshot = null;
      }

      if (
        speechLike &&
        interruptSpeechFrames >= INTERRUPT_MIN_FRAMES &&
        interruptSpeechAccumMs >= getInterruptSustainMs()
      ) {
        const gate = "heuristic";
        const snap = lastInterruptSpeechLikeSnapshot;
        logInterruptTriggerReason({
          gate,
          triggerFrame: { rms, zcr, crest, speechLike },
          lastSpeechLike: snap,
          speechAccumMs: interruptSpeechAccumMs,
          wallMsSinceFirstSpeech: interruptSpeechStart
            ? now - interruptSpeechStart
            : 0,
          rafFrames: interruptSpeechFrames,
        });
        lastInterruptProbe = {
          atTrigger: { rms, zcr, crest, speechLike },
          lastSpeechLike: snap,
          interruptGate: gate,
          interruptReason: "heuristic",
          heuristicChecks: snap?.heuristicChecks ?? heuristicChecks,
          speechAccumMs: interruptSpeechAccumMs,
          wallMsSinceFirstSpeech: interruptSpeechStart
            ? now - interruptSpeechStart
            : 0,
          frames: interruptSpeechFrames,
        };
        logInterruptTranscriptDebug("speech_detected", {
          tts_id: interruptPrearmTtsId || null,
          time_since_tts_start_ms: Number((now - (audioStartedAt || now)).toFixed(1)),
          speech_confirm_delay_ms: Number((interruptSpeechAccumMs || 0).toFixed(1)),
          rms: Number(rms.toFixed(5)),
          vad_score: Number((speechLike ? 1 : 0).toFixed(2)),
          preroll_available_ms: interruptPrearmStartedAt
            ? Number(Math.min(MAX_INTERRUPTION_PREROLL_MS, now - interruptPrearmStartedAt).toFixed(1))
            : 0,
          gate: browserAsrParallelMode ? "heuristic_fast_stop" : "heuristic"
        });

        /* DEBUG: VAD threshold passed — log before dispatch so we know
           which branch will fire and what the state looks like. */
        logVeraInterruptDebug({
          tag: "interrupt_vad_threshold_passed",
          now: Number(now.toFixed(1)),
          gate: browserAsrParallelMode ? "browser_asr_parallel" : "single_asr_interrupt_speech",
          rms: Number(rms.toFixed(5)),
          zcr: Number(zcr.toFixed(4)),
          crest: Number(crest.toFixed(2)),
          vadAccumMs: Number(interruptSpeechAccumMs.toFixed(1)),
          rafFrames: interruptSpeechFrames,
          interruptRecording,
          mainTtsPlaybackActive,
          activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
          activeNdjsonBodyReaderPresent: Boolean(activeNdjsonBodyReader),
          timeSinceTtsStartMs: Number((now - (audioStartedAt || now)).toFixed(1)),
          duringNewsRender: _veraNewsPanelRenderInFlight
        });

        if (browserAsrParallelMode) {
          // Parallel mode: VAD only cancels audio. The browser-ASR
          // session keeps running and will deliver the final transcript
          // (see onBrowserInterruptBargeInFromDetect for the bubble +
          // routing). Reset the heuristic counters so we don't fire the
          // fast-stop more than once per TTS turn.
          /* PART 1 — t4: gate passed, intent confirmed (VAD parallel). */
          _recordInterruptTimingPoint("t4_interrupt_intent_detected", {
            autoStart: true,
            extra: { gate: "heuristic_fast_stop" },
          });
          fastStopTtsOnVadOnly({
            rms,
            zcr,
            crest,
            vadAccumMs: interruptSpeechAccumMs
          });
        } else {
          /* PART 1 — t4: gate passed, intent confirmed (single-ASR heuristic). */
          _recordInterruptTimingPoint("t4_interrupt_intent_detected", {
            autoStart: true,
            extra: { gate: "heuristic_single_asr" },
          });
          interruptSpeech();
        }
        interruptSpeechFrames = 0;
        interruptSpeechStart = 0;
        interruptSpeechAccumMs = 0;
        interruptLastSpeechLikeTime = 0;
        lastInterruptSpeechLikeSnapshot = null;
      }

      if (
        MOBILE_VAD_DEBUG &&
        now - lastMobileVadSampleLogAt >= MOBILE_VAD_SAMPLE_INTERVAL_MS
      ) {
        lastMobileVadSampleLogAt = now;
        pushMobileInterruptVadLog(
          `vad rms=${rms.toFixed(4)} zcr=${zcr.toFixed(4)} crest=${crest.toFixed(2)} like=${speechLike} acc=${interruptSpeechAccumMs.toFixed(0)}ms thr=${getInterruptSustainMs()}ms`
        );
      }
    }
  } else {
    interruptSpeechFrames = 0;
    interruptSpeechStart = 0;
    interruptSpeechAccumMs = 0;
    lastInterruptDetectTime = 0;
    interruptLastSpeechLikeTime = 0;
    lastInterruptSpeechLikeSnapshot = null;
  }

  requestAnimationFrame(detectInterrupt);
}

function resetAudioHandlers() {
  const a = getAudioEl();
  if (a) {
    a.onplay = null;
    a.onended = null;
  }
}

let interruptLastVoiceTime = 0;

function detectInterruptSpeechEnd() {
  if (!interruptRecording || interruptRecorder?.state !== "recording") return;

  const buf = new Float32Array(analyser.fftSize);
  analyser.getFloatTimeDomainData(buf);

  let sum = 0;
  for (let i = 0; i < buf.length; i++) sum += buf[i] * buf[i];
  const rms = Math.sqrt(sum / buf.length);

  const now = performance.now();

  if (listeningFrameIsSpeechLike(buf, rms)) {
    interruptLastVoiceTime = now;
  }

  if (
    interruptLastVoiceTime &&
    now - interruptLastVoiceTime > SILENCE_MS
  ) {
    interruptRecorder.stop(); // ✅ NOW stop
    interruptRecording = false;
    return;
  }

  requestAnimationFrame(detectInterruptSpeechEnd);
}

function computeZCR(buf) {
  let crossings = 0;
  for (let i = 1; i < buf.length; i++) {
    if ((buf[i - 1] >= 0 && buf[i] < 0) ||
        (buf[i - 1] < 0 && buf[i] >= 0)) {
      crossings++;
    }
  }
  return crossings / buf.length;
}

/** RMS + ZCR voiced band — used so background noise alone does not stall end-of-speech. */
function listeningFrameIsSpeechLike(buf, rms) {
  const zcr = computeZCR(buf);
  if (IS_MOBILE) {
    /* Phone mics (Bluetooth, handset, AGC off) are often quieter and ZCR sits outside desktop bands. */
    const th = VOLUME_THRESHOLD * 0.55;
    if (rms <= th) return false;
    const zLo = LISTEN_END_ZCR_MIN * 0.55;
    const zHi = Math.min(0.28, LISTEN_END_ZCR_MAX * 1.35);
    return zcr >= zLo && zcr <= zHi;
  }
  if (rms <= VOLUME_THRESHOLD) return false;
  return zcr >= LISTEN_END_ZCR_MIN && zcr <= LISTEN_END_ZCR_MAX;
}

/** Per-threshold flags for interrupt (RMS/ZCR/crest); all must pass for a frame to count as speech-like. */
function computeHeuristicInterruptChecks(rms, zcr, crest) {
  const rmsAboveMin = rms > INTERRUPT_RMS;
  const rmsBelowMax = rms < MAX_SPEECH_RMS;
  const zcrInRange = zcr >= INTERRUPT_ZCR_MIN && zcr <= INTERRUPT_ZCR_MAX;
  const crestOk = crest <= INTERRUPT_MAX_CREST;
  return {
    rmsAboveMin,
    rmsBelowMax,
    zcrInRange,
    crestOk,
    passes:
      rmsAboveMin && rmsBelowMax && zcrInRange && crestOk,
  };
}

function logInterruptTriggerReason({
  gate,
  triggerFrame,
  lastSpeechLike,
  speechAccumMs,
  wallMsSinceFirstSpeech,
  rafFrames,
}) {
  const base = {
    gate,
    speechAccumMs: Number(speechAccumMs.toFixed(1)),
    wallMsSinceFirstSpeech: Number(wallMsSinceFirstSpeech.toFixed(1)),
    rafFrames,
    triggerKind: `speech_frame (accumulated speechLike time ≥ ${getInterruptSustainMs()}ms)`,
    triggerFrame: {
      rms: Number(triggerFrame.rms.toFixed(5)),
      zcr: Number(triggerFrame.zcr.toFixed(5)),
      crest: Number(triggerFrame.crest.toFixed(4)),
      speechLike: triggerFrame.speechLike,
    },
  };
  const h =
    lastSpeechLike?.heuristicChecks ??
    computeHeuristicInterruptChecks(
      lastSpeechLike?.rms ?? triggerFrame.rms,
      lastSpeechLike?.zcr ?? triggerFrame.zcr,
      lastSpeechLike?.crest ?? triggerFrame.crest
    );
  const checks = [];
  if (h.rmsAboveMin) checks.push("rms_min");
  if (h.rmsBelowMax) checks.push("rms_max");
  if (h.zcrInRange) checks.push("zcr");
  if (h.crestOk) checks.push("crest");
  console.log(
    "[INTERRUPT] trigger — heuristic (RMS/ZCR/crest + sustain; all must pass on speech frames)",
    {
      ...base,
      lastSpeechLike: lastSpeechLike
        ? {
            rms: Number(lastSpeechLike.rms.toFixed(5)),
            zcr: Number(lastSpeechLike.zcr.toFixed(5)),
            crest: Number(lastSpeechLike.crest.toFixed(4)),
            heuristicChecks: checks.join("+"),
            flags: {
              rmsAboveMin: h.rmsAboveMin,
              rmsBelowMax: h.rmsBelowMax,
              zcrInRange: h.zcrInRange,
              crestOk: h.crestOk,
            },
          }
        : null,
    }
  );
  pushMobileInterruptVadLog(
    `[INTERRUPT] gate=${gate} accumMs=${speechAccumMs.toFixed(1)} rms=${triggerFrame.rms.toFixed(5)} zcr=${triggerFrame.zcr.toFixed(5)} crest=${triggerFrame.crest.toFixed(4)} checks=${checks.join("+")}`
  );
}

function pushMobileInterruptVadLog(msg) {
  if (!MOBILE_VAD_DEBUG) return;
  const t = new Date().toISOString().slice(11, 23);
  interruptVadLogLines.push(`[${t}] ${msg}`);
  if (interruptVadLogLines.length > INTERRUPT_VAD_LOG_MAX) {
    interruptVadLogLines.splice(0, interruptVadLogLines.length - INTERRUPT_VAD_LOG_MAX);
  }
  renderMobileInterruptVadLogs();
}

function renderMobileInterruptVadLogs() {
  const text = interruptVadLogLines.join("\n");
  const p1 = document.getElementById("vera-interrupt-debug-pre");
  const p2 = document.getElementById("bmo-interrupt-debug-pre");
  if (p1) p1.textContent = text;
  if (p2) p2.textContent = text;
}

function toggleInterruptDebugPanel(prefix) {
  const panel = document.getElementById(`${prefix}-interrupt-debug-panel`);
  const btn = document.getElementById(`${prefix}-interrupt-debug-toggle`);
  const headerBtn = document.getElementById(`${prefix}-interrupt-debug-header`);
  if (!panel) return;
  const opening = panel.hidden;
  panel.hidden = !opening;
  const expanded = opening ? "true" : "false";
  btn?.setAttribute("aria-expanded", expanded);
  headerBtn?.setAttribute("aria-expanded", expanded);
  if (opening) {
    requestAnimationFrame(() => {
      panel.scrollIntoView({ block: "end", behavior: "smooth" });
    });
  }
}

function injectMobileVadLogUiIfNeeded() {
  if (!MOBILE_VAD_DEBUG) return;
  document.body.classList.add("vad-log-mode");

  const veraHeader = document.querySelector("#vera-app .vera-app-header");
  const veraOpenBmo = document.getElementById("open-bmo-from-vera");
  if (veraHeader && veraOpenBmo && !document.getElementById("vera-interrupt-debug-header")) {
    const wrap = document.createElement("div");
    wrap.className = "vera-header-actions";
    const vadBtn = document.createElement("button");
    vadBtn.type = "button";
    vadBtn.id = "vera-interrupt-debug-header";
    vadBtn.className = "interrupt-debug-header-btn";
    vadBtn.setAttribute("aria-controls", "vera-interrupt-debug-panel");
    vadBtn.textContent = "VAD log";
    veraOpenBmo.parentNode.insertBefore(wrap, veraOpenBmo);
    wrap.appendChild(vadBtn);
    wrap.appendChild(veraOpenBmo);
  }

  const bmoHeader = document.querySelector("#bmo-page .bmo-chat-header");
  if (bmoHeader && !document.getElementById("bmo-interrupt-debug-header")) {
    const vadBtn = document.createElement("button");
    vadBtn.type = "button";
    vadBtn.id = "bmo-interrupt-debug-header";
    vadBtn.className = "interrupt-debug-header-btn";
    vadBtn.setAttribute("aria-controls", "bmo-interrupt-debug-panel");
    vadBtn.textContent = "VAD log";
    bmoHeader.appendChild(vadBtn);
  }

  function buildExtender(prefix) {
    const wrap = document.createElement("div");
    wrap.className = "interrupt-debug-extender";
    const toggle = document.createElement("button");
    toggle.type = "button";
    toggle.id = `${prefix}-interrupt-debug-toggle`;
    toggle.className = "interrupt-debug-toggle";
    toggle.setAttribute("aria-expanded", "false");
    toggle.setAttribute("aria-controls", `${prefix}-interrupt-debug-panel`);
    toggle.textContent = "Interrupt / VAD log";
    const panel = document.createElement("div");
    panel.id = `${prefix}-interrupt-debug-panel`;
    panel.className = "interrupt-debug-panel";
    panel.hidden = true;
    const pre = document.createElement("pre");
    pre.id = `${prefix}-interrupt-debug-pre`;
    pre.className = "interrupt-debug-pre";
    pre.setAttribute("aria-live", "polite");
    const clearBtn = document.createElement("button");
    clearBtn.type = "button";
    clearBtn.id = `${prefix}-interrupt-debug-clear`;
    clearBtn.className = "interrupt-debug-clear";
    clearBtn.textContent = "Clear";
    panel.appendChild(pre);
    panel.appendChild(clearBtn);
    wrap.appendChild(toggle);
    wrap.appendChild(panel);
    return wrap;
  }

  const veraIc = document.querySelector("#vera-app .input-container");
  if (veraIc && !document.getElementById("vera-interrupt-debug-panel")) {
    veraIc.appendChild(buildExtender("vera"));
  }

  const bmoIc = document.querySelector("#bmo-page .input-container");
  if (bmoIc && !document.getElementById("bmo-interrupt-debug-panel")) {
    bmoIc.appendChild(buildExtender("bmo"));
  }
}

function wireMobileInterruptDebugUi() {
  if (!MOBILE_VAD_DEBUG) return;
  injectMobileVadLogUiIfNeeded();
  pushMobileInterruptVadLog(
    `sustain=${getInterruptSustainMs()}ms (${INTERRUPT_SUSTAIN_MS_PHONE}ms phone / ${INTERRUPT_SUSTAIN_MS_DESKTOP}ms desktop viewport)`
  );
  ["vera", "bmo"].forEach((prefix) => {
    const btn = document.getElementById(`${prefix}-interrupt-debug-toggle`);
    const headerBtn = document.getElementById(`${prefix}-interrupt-debug-header`);
    const panel = document.getElementById(`${prefix}-interrupt-debug-panel`);
    const clearBtn = document.getElementById(`${prefix}-interrupt-debug-clear`);
    if (!panel) return;
    const toggle = () => toggleInterruptDebugPanel(prefix);
    btn?.addEventListener("click", toggle);
    headerBtn?.addEventListener("click", toggle);
    clearBtn?.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      interruptVadLogLines.length = 0;
      renderMobileInterruptVadLogs();
    });
  });
}

function startInterruptCapture() {
  /* DEBUG: log every call to startInterruptCapture and every early exit
     so we can confirm interruptRecording is flipped true for single-ASR
     news responses. The "stays false for whole response" hypothesis
     hinges on this firing. */
  const _dbgState = (event, extra) => logVeraInterruptDebug({
    tag: "interrupt_capture_state",
    event,
    now: Number(performance.now().toFixed(1)),
    listeningMode,
    inputMuted,
    useBrowserAsr: (function () { try { return browserAsrPreferred(); } catch (_) { return null; } })(),
    isNarrowViewport: (function () { try { return isNarrowViewport(); } catch (_) { return null; } })(),
    interruptRecording,
    interruptRecorderState: interruptRecorder?.state ?? null,
    interruptChunksCount: Array.isArray(interruptChunks) ? interruptChunks.length : null,
    prearmActive: Boolean(interruptPrearmRecorder && interruptPrearmRecorder.state === "recording"),
    ttsPlaying: (function () { try { return isAssistantTtsPlaying(); } catch (_) { return null; } })(),
    currentTtsId: interruptPrearmTtsId || null,
    actionType: _veraCurrentTtsDebugContext?.actionType ?? null,
    ...(extra || {})
  });

  _dbgState("start_called");

  if (listeningMode !== "continuous") {
    interruptRecording = false;
    interruptChunks = [];
    _dbgState("start_aborted", { reason: "not_continuous" });
    return;
  }
  if (inputMuted) {
    interruptRecording = false;
    interruptChunks = [];
    stopAllBrowserSpeechRecognizers();
    showMutedStatusIfIdle();
    _dbgState("start_aborted", { reason: "input_muted" });
    return;
  }
  if (browserAsrPreferred() && !isNarrowViewport()) {
    startInterruptBrowserPartialDetection();
    _dbgState("start_aborted", { reason: "browser_asr_partial_detection_used" });
    return;
  }

  // 🔥 HARD FLUSH — stop and discard any previous capture
  if (interruptRecorder && interruptRecorder.state !== "inactive") {
    try {
      interruptRecorder.ondataavailable = null;
      interruptRecorder.onstop = null;
      interruptRecorder.stop();
    } catch {}
  }

  interruptRecorder = null;
  interruptRecording = false;
  interruptChunks = [];
  interruptSpeechFrames = 0;
  interruptSpeechStart = 0;
  interruptSpeechAccumMs = 0;
  lastInterruptDetectTime = 0;
  interruptLastSpeechLikeTime = 0;
  lastInterruptSpeechLikeSnapshot = null;
  interruptPrearmStartedAt = performance.now();

  // ---------- START / COMMIT RECORDER ----------
  // If TTS pre-armed a rolling recorder, keep the same recorder alive so
  // the eventual ASR upload contains the user's first words. The old path
  // created MediaRecorder only after VAD confirmed speech, which could miss
  // the phrase opening ("wait actually", "pause", "stop").
  if (
    interruptPrearmRecorder &&
    interruptPrearmRecorder.state === "recording"
  ) {
    try {
      interruptPrearmRecorder.requestData?.();
    } catch (_) {}
    interruptRecorder = interruptPrearmRecorder;
    interruptChunks = interruptPrearmChunks.map((x) => x?.blob).filter(Boolean);
    interruptPrearmCommittedAt = performance.now();
    interruptPrearmRecorder = null;
    interruptPrearmChunks = [];
    interruptRecorder.ondataavailable = (e) => {
      if (e.data && e.data.size > 0) {
        interruptChunks.push(e.data);
      }
    };
    interruptRecorder.onstop = () => {
      _dbgState("recorder_stopped", { path: "prearm_commit" });
      const blob = new Blob(interruptChunks, { type: "audio/webm" });
      interruptRecorder = null;
      interruptRecording = false;
      interruptChunks = [];
      handleInterruptUtterance(blob);
    };
    interruptRecording = true;
    _dbgState("recorder_started", { path: "prearm_commit" });
    logInterruptTranscriptDebug("capture_committed", {
      included_preroll_ms: Math.min(
        MAX_INTERRUPTION_PREROLL_MS,
        Math.max(0, interruptPrearmCommittedAt - interruptPrearmStartedAt)
      ),
      live_capture_started_at_ms: Number((interruptPrearmStartedAt || 0).toFixed(1)),
      bubble_created_at_ms: null,
      asr_request_started_at_ms: null
    });
    return;
  }

  // ---------- START FRESH RECORDER ----------
  if (!micStream || !micStream.active) {
    interruptRecording = false;
    interruptChunks = [];
    logInterruptTranscriptDebug("prearm", {
      stream_active: false,
      media_recorder_ready: false,
      rolling_buffer_enabled: false,
      preroll_ms: INTERRUPTION_PREROLL_MS,
      reason: "no_active_mic_stream"
    });
    _dbgState("start_aborted", { reason: "no_active_mic_stream" });
    return;
  }
  /* PART 12: use shared opus-preferred recorder helper so interrupt-path
     audio matches the quality of the main + hybrid recorders. */
  interruptRecorder = createVeraMediaRecorder(micStream);

  interruptRecorder.ondataavailable = (e) => {
    if (e.data && e.data.size > 0) {
      interruptChunks.push(e.data);
    }
  };

  interruptRecorder.onstop = () => {
    _dbgState("recorder_stopped", { path: "fresh_recorder" });
    const blob = new Blob(interruptChunks, { type: "audio/webm" });

    interruptRecorder = null;
    interruptRecording = false;
    interruptChunks = [];

    handleInterruptUtterance(blob);
  };

  interruptRecorder.start(100);
  interruptRecording = true;
  _dbgState("recorder_started", { path: "fresh_recorder" });
}

async function prearmInterruptCaptureForTts({ turnId = "", ttsId = "" } = {}) {
  /* DEBUG: capture-state log on entry so we can see whether prearm even
     ran for the news response. */
  logVeraInterruptDebug({
    tag: "interrupt_capture_state",
    event: "prearm_called",
    now: Number(performance.now().toFixed(1)),
    listeningMode,
    inputMuted,
    ttsId: ttsId || null,
    turnId: turnId || null,
    interruptRecording,
    prearmActive: Boolean(interruptPrearmRecorder && interruptPrearmRecorder.state === "recording"),
    ttsPlaying: (function () { try { return isAssistantTtsPlaying(); } catch (_) { return null; } })(),
    actionType: _veraCurrentTtsDebugContext?.actionType ?? null,
  });
  if (listeningMode !== "continuous" || inputMuted) {
    logVeraInterruptDebug({
      tag: "interrupt_capture_state",
      event: "prearm_aborted",
      reason: listeningMode !== "continuous" ? "not_continuous" : "input_muted",
      now: Number(performance.now().toFixed(1)),
    });
    return false;
  }
  if (!isAssistantTtsPlaying()) {
    logVeraInterruptDebug({
      tag: "interrupt_capture_state",
      event: "prearm_aborted",
      reason: "tts_not_playing",
      now: Number(performance.now().toFixed(1)),
      mainTtsPlaybackActive,
      activeMainTtsBufferSourcesCount: activeMainTtsBufferSources.length,
    });
    return false;
  }
  const micPermissionState = await getMicPermissionStateForInterrupt();
  const attempted =
    micPermissionState === "granted" ||
    Boolean(micStream?.active) ||
    (browserAsrPreferred() && !isNarrowViewport());
  logInterruptTranscriptDebug("tts_start", {
    turn_id: turnId || null,
    tts_id: ttsId || null,
    mic_permission_state: micPermissionState,
    prearm_attempted: attempted,
    prearm_success: false
  });
  if (!attempted || micPermissionState === "prompt" || micPermissionState === "denied") {
    return false;
  }

  interruptPrearmTtsId = ttsId || interruptPrearmTtsId || interruptTranscriptNewTtsId();
  interruptPrearmTurnId = turnId || interruptPrearmTurnId || "";

  if (browserAsrPreferred() && !isNarrowViewport()) {
    if (!interruptDetectRecognition) {
      startInterruptBrowserPartialDetection();
    }
    interruptPrearmSuccess = Boolean(interruptDetectRecognition);
    logInterruptTranscriptDebug("prearm", {
      stream_active: Boolean(micStream?.active),
      media_recorder_ready: false,
      rolling_buffer_enabled: false,
      preroll_ms: 0,
      browser_asr_prearmed: interruptPrearmSuccess
    });
    logInterruptTranscriptDebug("tts_start", {
      turn_id: interruptPrearmTurnId || null,
      tts_id: interruptPrearmTtsId || null,
      mic_permission_state: micPermissionState,
      prearm_attempted: true,
      prearm_success: interruptPrearmSuccess
    });
    return interruptPrearmSuccess;
  }

  if (!micStream || !micStream.active || typeof MediaRecorder === "undefined") {
    logInterruptTranscriptDebug("prearm", {
      stream_active: Boolean(micStream?.active),
      media_recorder_ready: false,
      rolling_buffer_enabled: false,
      preroll_ms: INTERRUPTION_PREROLL_MS,
      reason: "no_media_recorder_or_stream"
    });
    return false;
  }

  try {
    if (interruptRecorder && interruptRecorder.state === "recording") {
      interruptPrearmSuccess = true;
      logInterruptTranscriptDebug("prearm", {
        stream_active: Boolean(micStream?.active),
        media_recorder_ready: true,
        rolling_buffer_enabled: true,
        preroll_ms: INTERRUPTION_PREROLL_MS,
        recorder_already_active: true
      });
      logInterruptTranscriptDebug("tts_start", {
        turn_id: interruptPrearmTurnId || null,
        tts_id: interruptPrearmTtsId || null,
        mic_permission_state: micPermissionState,
        prearm_attempted: true,
        prearm_success: true
      });
      return true;
    }
    if (interruptPrearmRecorder && interruptPrearmRecorder.state !== "inactive") return true;
    stopInterruptPrearmRecorder("");
    interruptPrearmChunks = [];
    interruptPrearmStartedAt = performance.now();
    /* PART 12: opus + bitrate so pre-arm captures sound as good as the
       main recorder. The "opening syllables get clipped" risk is mitigated
       by the prearm-start latency timing, not the encoder. */
    interruptPrearmRecorder = createVeraMediaRecorder(micStream);
    interruptPrearmRecorder.ondataavailable = (e) => {
      if (!e.data || e.data.size <= 0) return;
      interruptPrearmChunks.push({ blob: e.data, at: performance.now() });
      const cutoff = performance.now() - MAX_INTERRUPTION_PREROLL_MS;
      interruptPrearmChunks = interruptPrearmChunks.filter((x) => x.at >= cutoff);
    };
    interruptPrearmRecorder.onstop = () => {};
    interruptPrearmRecorder.start(100);
    interruptPrearmSuccess = true;
    logInterruptTranscriptDebug("prearm", {
      stream_active: Boolean(micStream?.active),
      media_recorder_ready: true,
      rolling_buffer_enabled: true,
      preroll_ms: INTERRUPTION_PREROLL_MS
    });
    logInterruptTranscriptDebug("tts_start", {
      turn_id: interruptPrearmTurnId || null,
      tts_id: interruptPrearmTtsId || null,
      mic_permission_state: micPermissionState,
      prearm_attempted: true,
      prearm_success: true
    });
    return true;
  } catch (err) {
    logInterruptTranscriptDebug("prearm", {
      stream_active: Boolean(micStream?.active),
      media_recorder_ready: false,
      rolling_buffer_enabled: false,
      preroll_ms: INTERRUPTION_PREROLL_MS,
      error_message: String(err?.message || err || "").slice(0, 160)
    });
    return false;
  }
}

async function handleInterruptUtterance(blob) {
  /* DEBUG: log upload entry so we can see whether the interrupt capture
     made it all the way to the server upload step. If we never see this
     during a failed news interruption, the recorder either never started
     or never stopped. */
  logVeraInterruptDebug({
    tag: "interrupt_capture_state",
    event: "upload_started",
    now: Number(performance.now().toFixed(1)),
    blobSize: blob?.size ?? null,
    minAudioBytes: MIN_AUDIO_BYTES,
    skippedAsTooSmall: (blob?.size ?? 0) < MIN_AUDIO_BYTES,
    actionType: _veraCurrentTtsDebugContext?.actionType ?? null,
  });
  if (blob.size < MIN_AUDIO_BYTES) {
    listening = true;
    return;
  }

  requestInFlight = true;
  processing = true;
  /* PART 3 — log the "interrupted/listening" → "processing/thinking" hop
     that happens once the interrupt recorder closes the utterance. */
  _logVoiceStateTransition("listening", "processing", "interrupt_utterance_upload", "handleInterruptUtterance");
  waveState = "idle";
  setStatus("Thinking", "thinking");

  const formData = new FormData();
  formData.append("audio", blob);
  formData.append("session_id", getSessionId());
  formData.append("client", appModePrefix());
  formData.append("context_snapshot", JSON.stringify(buildClientContextSnapshot()));
  formData.append("mode", "interrupt"); // backend can branch if desired
  formData.append(
    "interrupt_debug",
    JSON.stringify({
      probe: lastInterruptProbe,
      thresholds: {
        INTERRUPT_RMS,
        INTERRUPT_ZCR_MIN,
        INTERRUPT_ZCR_MAX,
        INTERRUPT_SUSTAIN_MS: getInterruptSustainMs(),
        INTERRUPT_GAP_RESET_MS,
        INTERRUPT_MAX_CREST,
        MAX_SPEECH_RMS,
      },
    })
  );
  formData.append("stream_tts", shouldStreamTts() ? "1" : "0");

  logInterruptTranscriptDebug("capture_committed", {
    included_preroll_ms: interruptPrearmCommittedAt && interruptPrearmStartedAt
      ? Number(Math.min(MAX_INTERRUPTION_PREROLL_MS, interruptPrearmCommittedAt - interruptPrearmStartedAt).toFixed(1))
      : 0,
    live_capture_started_at_ms: Number((interruptPrearmStartedAt || performance.now()).toFixed(1)),
    bubble_created_at_ms: null,
    asr_request_started_at_ms: Number(performance.now().toFixed(1)),
    blob_size: blob.size
  });
  await runInferInterruptPipeline(formData);
}

async function playInterruptAnswer(data) {
  const run = async () => {
    resetAudioHandlers();
    try {
      await playTtsFromApi(data, {
        onPlayStart: () => {
          logVoiceFirstAudio("main-reply");
          logVoiceMainReplyAudio();
          applyAssistantReplyAndPanels(data);
          /* PART 3 — interrupt-reply TTS starts: state hop into speaking. */
          _logVoiceStateTransition("processing", "speaking", "interrupt_reply_play_start", "playInterruptAnswer.onPlayStart");
          waveState = "speaking";
          audioStartedAt = performance.now();
          resetVadFastStopState("main_tts_start");
          setStatus("Speaking… (can only be interrupted once)", "speaking");
          processing = false;
        },
        onPlayEnd: () => {
          resumeListeningAfterInterruptPlayback();
        }
      });
    } catch (e) {
      console.warn(e);
    }
  };

  await run();
}
/* =========================
   MIC INIT
========================= */

/** Per-mode TTS <audio> through Web Audio (vera-audio / bmo-audio). */
async function ensureMainAudioTtsGraph() {
  const m = appModePrefix();
  const el = getAudioEl();
  if (!el || ttsByMode[m].source) return;
  if (!audioCtx) {
    audioCtx = new AudioContext({ sampleRate: 16000 });
  }
  await audioCtx.resume();
  const analyser = audioCtx.createAnalyser();
  analyser.fftSize = 2048;
  const gain = audioCtx.createGain();
  gain.gain.value = 1;
  const source = audioCtx.createMediaElementSource(el);
  source.connect(analyser);
  source.connect(gain);
  gain.connect(audioCtx.destination);
  ttsByMode[m].source = source;
  ttsByMode[m].analyser = analyser;
  ttsByMode[m].gain = gain;
  applyVeraWorkModeMuteSetting();
}

/** Prefer `audio_urls` when present (sentence-chunked TTS); else single `audio_url`. */
function resolveAudioUrls(data) {
  if (Array.isArray(data.audio_urls) && data.audio_urls.length) return data.audio_urls;
  if (data.audio_url) return [data.audio_url];
  return [];
}

/* =========================================================================
 *  MAIN-TTS RUNTIME STATE + BOOKKEEPING + CANCELLATION
 *  → moved to voice/ttsQueue.js (Stage 5, 2026-05-27).
 *
 *  Moved bindings:
 *    let activeMainTtsBufferSources, let mainTtsPlaybackActive,
 *    let mainTtsPlaybackToken, let activeNdjsonBodyReader,
 *    function registerMainTtsBufferSource,
 *    function stopAllMainTtsWebAudio,
 *    function cancelMainTtsPlayback.
 *
 *  isAssistantTtsPlaying remains here because many non-TTS sites call
 *  it; it still reads the moved state via the shared classic-script
 *  global lexical environment.
 * ========================================================================= */

function isAssistantTtsPlaying() {
  const outAudio = getAudioEl();
  const htmlAudioPlaying = outAudio && !outAudio.paused;
  const webAudioMainTtsPlaying =
    activeMainTtsBufferSources.length > 0 || mainTtsPlaybackActive;
  return Boolean(htmlAudioPlaying || webAudioMainTtsPlaying);
}

let activePipelineAbort = null;
let queuedAssistantTtsPlayback = Promise.resolve();

function attachPipelineAbortSignal() {
  activePipelineAbort?.abort();
  activePipelineAbort = new AbortController();
  return activePipelineAbort.signal;
}

function enqueueAssistantTtsPlayback(task) {
  const run = queuedAssistantTtsPlayback
    .catch(() => {})
    .then(async () => {
      await waitUntilAssistantTtsIdle();
      await task();
      await waitUntilAssistantTtsIdle();
    });
  queuedAssistantTtsPlayback = run.catch(() => {});
  return run;
}

async function waitUntilAssistantTtsIdle(maxWaitMs = 60000) {
  const start = performance.now();
  while (isAssistantTtsPlaying()) {
    if (performance.now() - start > maxWaitMs) break;
    await new Promise((resolve) => window.setTimeout(resolve, 40));
  }
}

async function waitForAssistantPlaybackEnd(onFinishHook) {
  let done = false;
  let resolveDone;
  const donePromise = new Promise((resolve) => {
    resolveDone = resolve;
  });
  const finishDone = () => {
    if (done) return;
    done = true;
    resolveDone?.();
  };
  const wrappedOnFinish = () => {
    try {
      if (typeof onFinishHook === "function") onFinishHook();
    } finally {
      finishDone();
    }
  };
  // Safety timeout in case a browser event is missed.
  const timeoutId = window.setTimeout(finishDone, 45000);
  return {
    wrappedOnFinish,
    donePromise: donePromise.finally(() => window.clearTimeout(timeoutId))
  };
}

function isMainTtsOrHtmlAudioPlaying() {
  const a = getAudioEl();
  const htmlPlaying = a && !a.paused;
  const webTts =
    activeMainTtsBufferSources.length > 0 || mainTtsPlaybackActive;
  return htmlPlaying || webTts;
}

function isServerPipelineBusy() {
  return (
    requestInFlight ||
    processing ||
    isMainTtsOrHtmlAudioPlaying()
  );
}

/** Typed send (flow or work mode) can replace an in-flight reply / speaking TTS. */
function isFlowModeKeyboardInterruptAllowed() {
  return true;
}

/** Abort fetch + stop main TTS so the next `/text` send can proceed (keyboard barge-in). */
function interruptAssistantPipelineForTypedMessage() {
  /* PART 3/4 — typed keyboard barge-in is structurally similar to voice
     barge-in: log the state transition so the trace shows where TTS got
     cancelled when the user typed instead of spoke. */
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    "interrupted",
    "typed_pipeline_barge_in",
    "interruptAssistantPipelineForTypedMessage"
  );
  activePipelineAbort?.abort();
  activePipelineAbort = null;
  _veraTtsCancelSource = "typed_pipeline_barge_in";
  cancelMainTtsPlayback();
  resetAudioHandlers();
  const a = getAudioEl();
  if (a) {
    a.pause();
    a.currentTime = 0;
  }
  processing = false;
  requestInFlight = false;
  // The prior assistant request is gone — any pending "Searching news…"
  // bubble that was waiting on it would never resolve.
  cancelPendingNewsStatusBubble("pipeline_interrupted_by_typed");
  clearInterruptDetectionBubble();
  interruptBargeInLatched = false;
  voiceUxTurn = null;
  textUxTurn = null;
  if (listeningMode === "ptt") {
    listening = false;
    pttRecording = false;
    waveState = "idle";
    setStatus("Ready", "idle");
  } else {
    listening = true;
    waveState = "listening";
    if (inputMuted) showMutedStatusIfIdle();
    else setStatus("Listening…", "recording");
  }
  updateMuteInputButton();
}

function cancelVoicePipelineAndResetState() {
  /* PART 3 — full pipeline reset (e.g. mode swap, error recovery). */
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    "idle",
    "voice_pipeline_reset",
    "cancelVoicePipelineAndResetState"
  );
  // Diagnostic: if a non-cancelable action was just committed (sync /
  // add / remove / update / toggle / timer), the audio cancellation
  // below is allowed but the underlying state mutation MUST NOT be
  // unwound. The helpers in this function never touch checklist /
  // timer state directly, so the policy is preserved — we log here so
  // any future regression is obvious in DevTools.
  if (wasNonCancelableActionRecentlyCommitted()) {
    logChecklistActionCommitDebug({
      phase: "interrupt_during_committed_action",
      action_type: lastCommittedNonCancelableAction?.action_type || null,
      committed_at: lastCommittedNonCancelableAction?.committed_at || 0,
      reset_state_touched: false,
      notes: "cancelling only audio — checklist/timer mutation preserved"
    });
  }
  activePipelineAbort?.abort();
  activePipelineAbort = null;
  _veraTtsCancelSource = "voice_pipeline_reset";
  cancelMainTtsPlayback();
  resetAudioHandlers();
  const a = getAudioEl();
  if (a) {
    a.pause();
    a.removeAttribute("src");
    a.load?.();
  }
  if (rafId) {
    cancelAnimationFrame(rafId);
    rafId = null;
  }
  if (speechWaitTimeoutId != null) {
    clearTimeout(speechWaitTimeoutId);
    speechWaitTimeoutId = null;
  }
  if (interruptRecorder && interruptRecorder.state !== "inactive") {
    try {
      interruptRecorder.ondataavailable = null;
      interruptRecorder.onstop = null;
      interruptRecorder.stop();
    } catch {}
  }
  interruptRecorder = null;
  interruptRecording = false;
  interruptChunks = [];
  stopInterruptPrearmRecorder("");
  stopAllBrowserSpeechRecognizers();
  if (mediaRecorder && mediaRecorder.state === "recording") {
    suppressNextUtterance = true;
    mediaRecorder.stop();
  }
  processing = false;
  requestInFlight = false;
  voiceUxTurn = null;
  textUxTurn = null;
  pttRecording = false;
  listening = false;
  audioChunks = [];
  hasSpoken = false;
  lastVoiceTime = 0;
  waveState = "idle";
  cancelPendingNewsStatusBubble("voice_pipeline_reset");
  clearVoiceMaxDurationTimer();
  setStatus("Ready", "idle");
  updateMuteInputButton();
}

function resumeAfterAssistantReplyPlayback() {
  /* PART 3 — natural end of an assistant reply: speaking → listening/idle. */
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    listeningMode === "ptt" ? "idle" : "listening",
    "assistant_reply_playback_end",
    "resumeAfterAssistantReplyPlayback"
  );
  browserAsrMainNetworkRetries = 0;
  processing = false;
  requestInFlight = false;
  stopInterruptPrearmRecorder("");
  if (workModeTypedTurnQueue.length > 0) scheduleWorkModeTypedQueueDrain();
  clearInterruptDetectionBubble();
  if (listeningMode === "ptt") {
    listening = false;
    pttRecording = false;
    waveState = "idle";
    setStatus("Ready", "idle");
    updateMuteInputButton();
    return;
  }
  waveState = "listening";
  if (listeningMode === "continuous") {
    listening = true;
    if (inputMuted) {
      showMutedStatusIfIdle();
      return;
    }
    /* Defer so Web Audio / <audio> teardown and NDJSON reader finish; avoids empty SR sessions that never transcribe. */
    window.setTimeout(() => {
      if (!listening || processing || inputMuted) return;
      startListening();
    }, 80);
  }
}

function resumeListeningAfterInterruptPlayback() {
  /* PART 3 — natural end of an INTERRUPT reply playback. */
  _logVoiceStateTransition(
    typeof waveState !== "undefined" ? waveState : null,
    listeningMode === "ptt" ? "idle" : "listening",
    "interrupt_reply_playback_end",
    "resumeListeningAfterInterruptPlayback"
  );
  browserAsrMainNetworkRetries = 0;
  processing = false;
  requestInFlight = false;
  stopInterruptPrearmRecorder("");
  clearInterruptDetectionBubble();
  if (listeningMode === "ptt") {
    listening = false;
    pttRecording = false;
    waveState = "idle";
    setStatus("Ready", "idle");
    updateMuteInputButton();
    return;
  }
  waveState = "listening";
  listening = true;
  if (inputMuted) {
    showMutedStatusIfIdle();
    return;
  }
  window.setTimeout(() => {
    if (!listening || processing || inputMuted) return;
    startListening();
  }, 80);
}

/** Same wiring as MediaElementSource → analyser + destination: chunked TTS must feed the TTS analyser or BMO mouth / VERA wave stay flat. */
function connectBufferSourceToTtsGraph(src) {
  const m = appModePrefix();
  const t = ttsByMode[m];
  if (t?.analyser) {
    src.connect(t.analyser);
  }
  if (t?.gain) src.connect(t.gain);
  else src.connect(audioCtx.destination);
}

function wrapLastChunkForBmoMouth(onLastEnd) {
  if (!onLastEnd) return undefined;
  return () => {
    mainTtsPlaybackActive = false;
    if (document.body.classList.contains("bmo-open")) {
      stopBmoTtsMouthAnimation();
    }
    onLastEnd();
  };
}

/** Mirrors `split_sentences_for_tts` / TTS.py: paragraphs, then `.!?` or newlines. */
function splitSentencesForTtsClient(text) {
  let t = (text || "").trim();
  if (!t) return [];
  t = t.replace(/\u201c/g, '"').replace(/\u201d/g, '"').replace(/\u2019/g, "'");
  t = t.replace(/\u3002/g, ".");
  t = t.replace(/(?<=[a-z])\.(?=[A-Z])/g, ". ");
  const paragraphs = t.split(/\n\s*\n+/);
  const out = [];
  for (const para of paragraphs) {
    const p = para.trim();
    if (!p) continue;
    const parts = p.split(/(?<=[.!?])\s+|\n+/);
    for (const part of parts) {
      const x = part.trim();
      if (x) out.push(x);
    }
  }
  return out.length ? out : [t];
}

const BMO_TTS_SAD_HINTS =
  /\b(sorry|sad|sorrow|cry|tears|tearful|afraid|scared|fear|worried|worry|anxious|anxiety|depress|lonely|alone|hurt|hurts|pain|aching|hate|hatred|angry|rage|terrible|awful|horrible|worst|tragic|unfortunately|regret|guilt|ashamed|loss|lose|lost|die|death|dead|dying|kill|never\s+again|hopeless|despair|upset|disappoint|failed?|failure|breakdown|grief|mourn)\b/i;
const BMO_TTS_HAPPY_HINTS =
  /\b(happy|happiness|joy|joyful|great|wonderful|awesome|amazing|love|loved|celebrat|excit|excited|fun|funny|laugh|smile|cheer|yay|best|lucky|glad|proud|relief|relieved|good\s+news|victory|won|win|beautiful|perfect)\b/i;
// Playful/idiomatic phrases that contain "negative" tokens but are clearly NOT sad.
// We test these BEFORE the sad hints so "never hurt anyone" stays neutral instead of
// flipping to a sad face on the bare 'hurt'/'pain'/'sorry' tokens.
const BMO_PLAYFUL_NEGATIVE_RX =
  /\b(never\s+(?:hurt|hurts|harmed|killed|cried|failed|did\s+anything)\s+(?:anyone|anybody|anything|nobody|no\s+one|a\s+soul)|(?:doesn|don|didn|won|wouldn|couldn|shouldn|can|cannot|cant)'?t\s+hurt(?:\s+(?:to|anyone|anybody|me|us|you|it))?|no\s+harm(?:\s+done|\s+in\s+(?:that|trying|asking))?|just\s+(?:kidding|teasing|joking|playing|messing\s+with\s+you)|only\s+(?:kidding|teasing|joking)|no\s+big\s+deal|nothing\s+to\s+worry\s+about|all\s+in\s+good\s+fun|grammatical\s+weathering)\b/i;

function bmoSentenceIsPlayfulNegative(seg) {
  const s = String(seg || "").trim();
  if (!s) return false;
  return BMO_PLAYFUL_NEGATIVE_RX.test(s);
}

function normalizeBmoTtsMood(x) {
  const s = String(x || "neutral").trim().toLowerCase();
  if (s === "sad" || s === "neutral" || s === "happy") return s;
  return "neutral";
}

function classifyBmoTtsSegmentHeuristic(seg) {
  const s = (seg || "").trim();
  if (!s) return "neutral";
  // Playful idiom guard: don't let bare 'hurt'/'pain'/'sorry' force sad on a clearly
  // playful sentence ("a little weathering never hurt anyone", "no harm done", etc.).
  if (bmoSentenceIsPlayfulNegative(s)) {
    if (BMO_TTS_HAPPY_HINTS.test(s) && !BMO_TTS_SAD_HINTS.test(s)) return "happy";
    return "neutral";
  }
  if (BMO_TTS_SAD_HINTS.test(s) && !BMO_TTS_HAPPY_HINTS.test(s)) return "sad";
  if (BMO_TTS_HAPPY_HINTS.test(s) && !BMO_TTS_SAD_HINTS.test(s)) return "happy";
  if (BMO_TTS_SAD_HINTS.test(s)) return "sad";
  if (BMO_TTS_HAPPY_HINTS.test(s)) return "happy";
  return "neutral";
}

/** Strict lexicon override — always force sad regardless of user_text or LLM label.
 *  Reserved for unambiguous grief / deep apology / condolences phrasings. Generic
 *  "sorry" / "wish I could" do NOT belong here; those move to the soft set below.
 */
function bmoAssistantSegmentRequiresSadFaceStrict(seg) {
  const s = String(seg || "").trim();
  if (!s) return false;
  if (bmoSentenceIsPlayfulNegative(s)) return false;
  if (
    /\b(my\s+condolences|deepest\s+condolences|so\s+sorry\s+for\s+your\s+loss|i'?m\s+so\s+sorry\s+to\s+hear|that'?s\s+(?:so\s+)?heartbreaking|that\s+sounds\s+(?:truly|really)\s+(?:awful|devastating|heartbreaking))\b/i.test(
      s
    )
  ) {
    return true;
  }
  return false;
}

/** Soft empathy/apology — only forces sad when the USER_text shows distress. */
function bmoAssistantSegmentSoftEmpathy(seg) {
  const s = String(seg || "").trim();
  if (!s) return false;
  if (bmoSentenceIsPlayfulNegative(s)) return false;
  if (/\b(sorry|apologi[sz]e|apologies)\b/i.test(s)) return true;
  if (/\b(i\s*'?m\s+sorry|i\s+am\s+sorry|we\s*'?re\s+sorry|so\s+sorry|really\s+sorry|deeply\s+sorry)\b/i.test(s))
    return true;
  if (/\b(sorry\s+you'?re|sorry\s+to\s+hear|sorry\s+about|sorry\s+for)\b/i.test(s)) return true;
  if (
    /\b(that\s+sounds\s+(?:really\s+)?(?:hard|rough|awful|tough|difficult)|hearing\s+(?:that|you)|wish\s+i\s+could|i\s+hear\s+you|i'?m\s+here\s+for\s+you)\b/i.test(
      s
    )
  )
    return true;
  return false;
}

// Tightened user-distress hint: bare tokens like "down" / "blue" / "alone" / "hurt"
// / "pain" require accompanying "feel(ing)" or "I'm" context so casual phrasing
// like "Trump is going down to China" doesn't promote BMO to sad mode.
const BMO_USER_DISTRESS_RX =
  /\b(sad|depressed|depressing|anxious|anxiety|worried|worries|cry|crying|tearful|grief|grieving|mourning|hopeless|despair|despairing|overwhelmed|exhausted|drained|can'?t\s+cope|cannot\s+cope|cant\s+cope|not\s+ok(?:ay)?|having\s+a\s+(?:hard|tough|rough)\s+time|need\s+(?:to\s+)?(?:cry|vent|talk))\b|\bfeel(?:ing)?\s+(?:down|blue|empty|numb|lonely|alone|sad|hurt|broken|hopeless|low|terrible|awful|miserable|like\s+crap|like\s+shit)\b|\bi'?m\s+(?:hurting|hurt|in\s+pain|crying|broken|lost|done|struggling|overwhelmed|exhausted|drained|not\s+ok(?:ay)?|miserable|grieving)\b/i;

function bmoUserTextIsDistressed(userText) {
  const ut = String(userText || "").trim();
  if (!ut) return false;
  return BMO_USER_DISTRESS_RX.test(ut);
}

/** Backward-compat name still used by callers in this file. */
function bmoAssistantSegmentPrefersSadFace(seg, userText) {
  if (bmoAssistantSegmentRequiresSadFaceStrict(seg)) return true;
  if (bmoUserTextIsDistressed(userText) && bmoAssistantSegmentSoftEmpathy(seg)) return true;
  return false;
}

/**
 * If TTS is one file for many sentences, any STRICT apology (condolences, deep grief)
 * in the reply deserves the sad mouth even when modes is a single-element array.
 * SOFT empathy ("I'm sorry", "wish I could") only flips when userText is distressed.
 */
function applyBmoSadFaceLexiconOverride(sentences, faceModes, userText) {
  if (!Array.isArray(sentences) || !Array.isArray(faceModes) || !faceModes.length) return faceModes;
  const distressed = bmoUserTextIsDistressed(userText);
  const shouldOverride = (s) => {
    if (bmoAssistantSegmentRequiresSadFaceStrict(s)) return true;
    if (distressed && bmoAssistantSegmentSoftEmpathy(s)) return true;
    return false;
  };
  if (faceModes.length === 1 && sentences.length > 1) {
    if (sentences.some(shouldOverride)) return ["sad"];
    return faceModes;
  }
  return faceModes.map((mode, i) => (shouldOverride(sentences[i]) ? "sad" : mode));
}

function logBmoEmotionDecision(row) {
  try {
    console.log("[bmo_emotion_decision]", JSON.stringify(row));
  } catch {}
}

function bmoMoodToFaceMode(mood) {
  return normalizeBmoTtsMood(mood) === "sad" ? "sad" : "happy";
}

/** When the user sounded clearly distressed, do not keep empathy/apology sentences as
 *  neutral (LLM often does). Casual user phrasing must NOT trigger this — playful
 *  idioms in the assistant reply are left alone via the playful-negative guard.
 */
function boostBmoMoodsForUserDistress(userText, sentences, moods) {
  const ut = (userText || "").trim();
  if (!ut || !Array.isArray(sentences) || !Array.isArray(moods) || moods.length !== sentences.length) {
    return moods;
  }
  if (!bmoUserTextIsDistressed(ut)) return moods;
  return moods.map((m, i) => {
    const lab = normalizeBmoTtsMood(m);
    if (lab === "sad" || lab === "happy") return lab;
    const s = String(sentences[i] || "");
    if (bmoSentenceIsPlayfulNegative(s)) return lab;
    if (bmoAssistantSegmentSoftEmpathy(s) || bmoAssistantSegmentRequiresSadFaceStrict(s)) {
      return "sad";
    }
    return lab;
  });
}

function alignBmoFaceModesToChunkCount(modes, chunkCount) {
  const n = Math.max(0, chunkCount | 0);
  if (!n) return [];
  const m = Array.isArray(modes) ? modes.slice(0, n) : [];
  const last = m.length ? m[m.length - 1] : "happy";
  while (m.length < n) m.push(last);
  for (let i = 0; i < m.length; i++) {
    m[i] = m[i] === "sad" ? "sad" : "happy";
  }
  return m;
}

function bmoNewSegmentFromCumulativeReply(prevCum, newCum) {
  const p = (prevCum || "").trimEnd();
  const c = (newCum || "").trim();
  if (!c) return "";
  if (!p) return c;
  if (c === p) return "";
  if (c.startsWith(p)) return c.slice(p.length).trimStart();
  return c;
}

function setBmoTtsFaceTrack(track) {
  const svg = document.getElementById("bmo-smile-svg");
  if (!svg) return;
  if (track === "sad") svg.setAttribute("data-bmo-tts-face-track", "sad");
  else svg.removeAttribute("data-bmo-tts-face-track");
}

async function fetchBmoTtsEmotionLabels(userText, sentences) {
  const res = await fetch(`${API_URL}/tts_emotion_route`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      session_id: getSessionId(),
      user_text: userText || "",
      sentences
    })
  });
  if (!res.ok) throw new Error(`emotion route HTTP ${res.status}`);
  const data = await res.json();
  const raw = data.labels;
  if (!Array.isArray(raw)) throw new Error("emotion route: missing labels");
  return sentences.map((_, i) => normalizeBmoTtsMood(raw[i]));
}

async function resolveBmoTtsSegmentFaceModesForPlayback(data, urlCount) {
  if (!document.body.classList.contains("bmo-open")) return null;
  const n = Math.max(0, urlCount | 0);
  if (!n) return null;
  const reply = String(data?.reply ?? "").trim();
  const userText = String(
    data?.transcript ?? data?.user_text ?? data?.text ?? ""
  ).trim();
  if (!reply) return alignBmoFaceModesToChunkCount([], n);
  const sentences = splitSentencesForTtsClient(reply);
  if (!sentences.length) return alignBmoFaceModesToChunkCount([], n);

  // Heuristic per sentence — always computed so we can include it in [bmo_emotion_decision].
  const heuristicLabels = sentences.map((s) => classifyBmoTtsSegmentHeuristic(s));

  // LLM labels are PRIMARY when available; heuristic is only a fallback.
  let llmLabels = null;
  try {
    llmLabels = await fetchBmoTtsEmotionLabels(userText, sentences);
  } catch (e) {
    console.warn("[BMO][TTS] emotion route", e);
    llmLabels = null;
  }
  const primary = llmLabels || heuristicLabels.slice();
  const boosted = boostBmoMoodsForUserDistress(userText, sentences, primary);

  let modes = sentences.map((_, i) => bmoMoodToFaceMode(boosted[i]));
  modes = alignBmoFaceModesToChunkCount(modes, n);
  // Lexicon override now requires either a STRICT phrase (always) or SOFT empathy
  // + a clearly distressed user (never on a single bare 'sorry' / 'hurt' alone).
  modes = applyBmoSadFaceLexiconOverride(sentences, modes, userText);

  for (let i = 0; i < sentences.length; i++) {
    const llm = llmLabels ? normalizeBmoTtsMood(llmLabels[i]) : null;
    const heur = normalizeBmoTtsMood(heuristicLabels[i]);
    const final = normalizeBmoTtsMood(boosted[i]);
    let overrideApplied = false;
    let overrideReason = "";
    if (llm && llm !== final) {
      overrideApplied = true;
      if (llm === "sad" && final !== "sad" && bmoSentenceIsPlayfulNegative(sentences[i])) {
        overrideReason = "demoted_playful_negative";
      } else if (final === "sad") {
        if (bmoAssistantSegmentRequiresSadFaceStrict(sentences[i])) {
          overrideReason = "strict_empathy_lexicon";
        } else if (bmoUserTextIsDistressed(userText) && bmoAssistantSegmentSoftEmpathy(sentences[i])) {
          overrideReason = "soft_empathy_with_user_distress";
        } else {
          overrideReason = "boost_for_user_distress";
        }
      } else {
        overrideReason = "label_changed";
      }
    } else if (!llm) {
      overrideReason = "heuristic_fallback";
    }
    logBmoEmotionDecision({
      sentence: String(sentences[i] || "").slice(0, 200),
      user_text: String(userText || "").slice(0, 200),
      llm_label: llm,
      heuristic_label: heur,
      final_label: final,
      override_applied: overrideApplied,
      override_reason: overrideReason,
    });
  }

  return modes;
}

/* playTtsUrlSequenceGapless → moved to voice/ttsQueue.js (Stage 5, 2026-05-27). */

/** Single <audio> for one file; Web Audio queue when multiple sentence chunks. */
async function playTtsFromApi(data, { onPlayStart, onPlayEnd, ephemeralAck } = {}) {
  if (appModePrefix() === "vera" && isVeraWorkModeOn() && isWorkModeMuteEnabled()) {
    logVeraSettings("tts_play_suppressed_workmode_mute", { mode: "playTtsFromApi" });
    mainTtsPlaybackActive = false;
    if (typeof onPlayStart === "function") onPlayStart();
    if (typeof onPlayEnd === "function") onPlayEnd();
    return;
  }
  if (!ephemeralAck && listeningMode === "continuous" && inputMuted) {
    logVeraSettings("tts_play_suppressed_continuous_input_muted", { mode: "playTtsFromApi" });
    mainTtsPlaybackActive = false;
    if (typeof onPlayStart === "function") onPlayStart();
    waveState = "idle";
    processing = false;
    requestInFlight = false;
    showMutedStatusIfIdle();
    if (typeof onPlayEnd === "function") onPlayEnd();
    return;
  }
  const urls = resolveAudioUrls(data);
  if (!urls.length) return;

  let segmentFaceModes = null;
  if (document.body.classList.contains("bmo-open")) {
    segmentFaceModes = await resolveBmoTtsSegmentFaceModesForPlayback(data, urls.length);
  }

  if (urls.length > 1) {
    console.log(
      `[UX][TTS] ${urls.length} segments — one /text or /infer response; next: ${urls.length} GETs to /audio/...`,
      urls
    );
  }

  const sessionToken = mainTtsPlaybackToken;
  const runPlayStart = () => {
    if (onPlayStart) onPlayStart();
  };

  if (urls.length === 1) {
    const el = getAudioEl();
    if (!el) return;
    el.src = `${API_URL}${urls[0]}`;
    await ensureMainAudioTtsGraph();
    el.addEventListener(
      "play",
      () => {
        mainTtsPlaybackActive = true;
        if (document.body.classList.contains("bmo-open")) {
          const face =
            segmentFaceModes != null && segmentFaceModes.length
              ? segmentFaceModes[0]
              : "happy";
          setBmoTtsFaceTrack(face);
          void startBmoTtsMouthAnimation();
        }
        runPlayStart();
      },
      { once: true }
    );
    el.addEventListener(
      "ended",
      () => {
        mainTtsPlaybackActive = false;
        if (onPlayEnd) onPlayEnd();
      },
      { once: true }
    );
    const onSingleAudioError = (ev) => {
      try { el.removeEventListener("error", onSingleAudioError); } catch (_) {}
      logVeraCapabilityFailure("tts", "audio_element_error", {
        src: el.src,
        error_code: el.error?.code
      });
      logCapabilityFallbackDebug({
        capability: "speaking",
        failure_kind: "inference_error",
        should_show_bubble: true,
        source_function: "playTtsFromApi.onSingleAudioError",
        raw_error_message: `audio_error_code=${el.error?.code ?? "?"}`
      });
      mainTtsPlaybackActive = false;
      veraShowCapabilityFailureBubble(
        "tts_failure",
        VERA_SAFETY_LIMITS.messages.ttsFailure
      );
      if (onPlayEnd) onPlayEnd();
    };
    el.addEventListener("error", onSingleAudioError, { once: true });
    try {
      await el.play();
    } catch (err) {
      onSingleAudioError(err);
    }
    return;
  }

  await playTtsUrlSequenceGapless(API_URL, urls, {
    onFirstStart: runPlayStart,
    onLastEnd: onPlayEnd,
    sessionToken,
    segmentFaceModes
  });
}

/* createTtsUrlQueue → moved to voice/ttsQueue.js (Stage 5, 2026-05-27). */

/* playTtsUrlSequenceIncremental → moved to voice/ttsQueue.js
 * (Stage 5, 2026-05-27). */

/**
 * When NDJSON playback is queued behind prior TTS, `runNdjsonTtsPlayback` may not start until later,
 * delaying `meta` and leaving work-mode timers disarmed. Read a cloned body until `meta` and apply
 * `work_mode_timer` immediately (main infer still consumes the original `res` body).
 */
async function tryPeekApplyWorkModeTimerFromNdjsonClone(res) {
  if (!res?.body || !res.ok) return;
  let c;
  try {
    c = res.clone();
  } catch {
    return;
  }
  const reader = c.body.getReader();
  const decoder = new TextDecoder();
  let buf = "";
  try {
    while (true) {
      const { value, done } = await reader.read();
      if (done) break;
      buf += decoder.decode(value, { stream: true });
      const lines = buf.split("\n");
      buf = lines.pop() || "";
      for (const line of lines) {
        const t = line.trim();
        if (!t) continue;
        let obj;
        try {
          obj = JSON.parse(t);
        } catch {
          continue;
        }
        if (obj.type === "asr") continue;
        if (obj.type === "meta") {
          if (obj.work_mode_timer) applyWorkModeTimerPayload(obj.work_mode_timer);
          return;
        }
        if (obj.type === "chunk" || obj.type === "done") return;
      }
    }
  } catch {
    /* ignore */
  } finally {
    try {
      reader.releaseLock();
    } catch (_) {}
  }
}

/* runNdjsonTtsPlayback → moved to voice/ttsQueue.js (Stage 5, 2026-05-27). */

async function initMic() {
  if (micStream) return;

  const audioConstraints = isNarrowViewport()
    ? {
        echoCancellation: true,
        noiseSuppression: true,
        autoGainControl: true,
      }
    : {
        echoCancellation: false,
        noiseSuppression: false,
        autoGainControl: false,
      };

  try {
    micStream = await navigator.mediaDevices.getUserMedia({ audio: audioConstraints });
  } catch (err) {
    /* Separate permission/setup state (no bubble) from true module/inference
       failure (bubble). getUserMedia rejections cover both: a NotAllowedError
       just means the user hasn't granted mic access yet, while NotReadable /
       NotSupported / TrackStartError mean the listening module itself is
       broken on this device. Only the latter should surface a Vera bubble. */
    const failureKind = classifyMicMediaError(err);
    const rawMessage = String(err?.message || err || "").slice(0, 200);
    const isPermissionOrSetup = micFailureKindIsPermissionOrSetup(failureKind);
    logVeraCapabilityFailure("asr", "mic_capture_failed", {
      error_name: err?.name,
      error_message: rawMessage,
      failure_kind: failureKind,
      bubble_suppressed: isPermissionOrSetup
    });
    logCapabilityFallbackDebug({
      capability: "listening",
      failure_kind: failureKind,
      should_show_bubble: !isPermissionOrSetup,
      source_function: "initMic",
      raw_error_message: rawMessage
    });
    if (!isPermissionOrSetup) {
      veraShowCapabilityFailureBubble(
        "asr_failure",
        VERA_SAFETY_LIMITS.messages.asrFailure
      );
      try { setStatus("Listening unavailable — use the keyboard", "offline"); } catch (_) {}
    }
    /* Re-raise so PTT / continuous start can reset wave state. Permission
       paths simply unwind silently — the browser permission prompt is the
       canonical UX, not a Vera fallback bubble. */
    throw err;
  }

  if (!audioCtx) {
    audioCtx = new AudioContext({ sampleRate: 16000 });
  }
  await audioCtx.resume();
  resizeWaveCanvas();

  analyser = audioCtx.createAnalyser();
  analyser.fftSize = 2048;

  audioCtx.createMediaStreamSource(micStream).connect(analyser);

  await ensureMainAudioTtsGraph();

  detectInterrupt();
  startWaveAnimation();
  updateMuteInputButton();
}
/* =========================
   WAVE ANIMATION
   - Frequency-band bars (FFT): bass → treble, amplitude per band
   - Ripple effect: concentric circles that pulse outward with amplitude
========================= */

const BARS = 48;  // frequency bands (bass on sides, treble toward center for symmetry)
const RIPPLE_EXPAND_SPEED = 2.2;
const RIPPLE_FADE_SPEED = 0.018;
const RIPPLE_SPAWN_THRESHOLD = 0.12;  // min avg magnitude to spawn ripple

function freqDataToBands(analyserRef, freqBuf, barValues) {
  if (!analyserRef || !freqBuf) return;
  analyserRef.getByteFrequencyData(freqBuf);
  const binCount = freqBuf.length;
  // Log-like band mapping: more resolution in bass/low-mids (where voice lives)
  for (let i = 0; i < BARS; i++) {
    const fracStart = Math.pow(i / BARS, 1.4);
    const fracEnd = Math.pow((i + 1) / BARS, 1.4);
    const binStart = Math.floor(fracStart * binCount);
    const binEnd = Math.min(Math.ceil(fracEnd * binCount), binCount);
    let sum = 0;
    let n = 0;
    for (let b = binStart; b < binEnd; b++) {
      sum += freqBuf[b];
      n++;
    }
    barValues[i] = n > 0 ? sum / n / 255 : 0;
  }
}

function startWaveAnimation() {
  if (waveformRaf) return;

  function draw() {
    waveformRaf = requestAnimationFrame(draw);

    const canvas = getWaveCanvas();
    const waveCtx = getWaveCtx();
    if (!canvas || !waveCtx) return;

    const dpr = window.devicePixelRatio || 1;
    const width = canvas.width / dpr;
    const height = canvas.height / dpr;
    const centerX = width / 2;
    const centerY = height / 2;

    waveCtx.clearRect(0, 0, width, height);

    const bmoOpen = document.body.classList.contains("bmo-open");
    /* BMO: waveform only while user is speaking (listening); TTS uses SVG mouth */
    if (bmoOpen && waveState === "speaking") {
      return;
    }

    const ttsA = getTtsAnalyser();
    let activeAnalyser = null;
    if (waveState === "listening" && analyser) activeAnalyser = analyser;
    if (waveState === "speaking" && ttsA) activeAnalyser = ttsA;

    if (!frequencyData || !activeAnalyser || frequencyData.length !== activeAnalyser.frequencyBinCount) {
      if (activeAnalyser) {
        frequencyData = new Uint8Array(activeAnalyser.frequencyBinCount);
        smoothedBars = new Float32Array(BARS);
      }
    }

    const targetEnergy = waveState === "speaking" ? 0.9 : waveState === "listening" ? 0.8 : 0;
    waveEnergy += (targetEnergy - waveEnergy) * 0.06;

    const barValues = new Float32Array(BARS);
    if (activeAnalyser && frequencyData) {
      freqDataToBands(activeAnalyser, frequencyData, barValues);
    }

    const barSpacing = width / BARS;
    const barWidth = barSpacing * 0.4;
    let avgMagnitude = 0;

    for (let i = 0; i < BARS; i++) {
      const v = barValues[i];
      avgMagnitude += v;
      const smooth = 0.25;
      if (smoothedBars) smoothedBars[i] = smoothedBars[i] * (1 - smooth) + v * smooth;
    }
    avgMagnitude /= BARS;

    const now = performance.now();
    if (waveEnergy > 0.3 && avgMagnitude > RIPPLE_SPAWN_THRESHOLD && now - lastRippleTime > RIPPLE_SPAWN_INTERVAL_MS) {
      rippleRings.push({ radius: 0, opacity: 0.5 + avgMagnitude * 0.4 });
      lastRippleTime = now;
    }

    for (let r = rippleRings.length - 1; r >= 0; r--) {
      const ring = rippleRings[r];
      ring.radius += RIPPLE_EXPAND_SPEED;
      ring.opacity -= RIPPLE_FADE_SPEED;
      if (ring.opacity <= 0) {
        rippleRings.splice(r, 1);
        continue;
      }
      const rippleAlpha = bmoOpen ? ring.opacity * 0.42 : ring.opacity * 0.35;
      const rr = bmoOpen ? 8 : 255;
      const rg = bmoOpen ? 72 : 255;
      const rb = bmoOpen ? 46 : 255;
      waveCtx.strokeStyle = `rgba(${rr},${rg},${rb},${rippleAlpha})`;
      waveCtx.lineWidth = 1.5;
      waveCtx.beginPath();
      waveCtx.arc(centerX, centerY, ring.radius, 0, Math.PI * 2);
      waveCtx.stroke();
    }

    const boost = waveState === "speaking" ? 2.8 : waveState === "listening" ? 2.8 : 0;
    const minimumBarScale = waveState === "listening" ? 0.05 : 0.03;
    const mid = BARS / 2;
    if (bmoOpen) {
      waveCtx.fillStyle = "rgba(10, 68, 42, 0.98)";
      /* Lighter shadow than VERA: mint bar + heavy blur reads as muddy / soft. */
      waveCtx.shadowBlur = 3;
      waveCtx.shadowColor = "rgba(4, 42, 26, 0.35)";
    } else {
      waveCtx.fillStyle = "rgba(255,255,255,0.95)";
      waveCtx.shadowBlur = 14;
      waveCtx.shadowColor = "rgba(255,255,255,0.7)";
    }

    for (let i = 0; i < BARS; i++) {
      const raw = (smoothedBars && waveEnergy > 0) ? smoothedBars[i] : barValues[i];
      const distance = Math.abs(i - mid) / mid;
      const envelope = Math.pow(1 - distance, 2.0);
      const barHeight =
        Math.max(minimumBarScale, raw) * height * boost * envelope * waveEnergy;

      const x = i * barSpacing + (barSpacing - barWidth) / 2;
      waveCtx.beginPath();
      waveCtx.roundRect(x, centerY - barHeight, barWidth, barHeight * 2, barWidth / 2);
      waveCtx.fill();
    }
  }

  draw();
}

/* =========================
   BMO — TTS drives SVG mouth (same shaping as intro in index.html)
========================= */

/**
 * BMO TTS mouth: idle (stroke) / surprised (O) / happy (open).
 *
 * What drives it:
 * - **Instant level** ≈ waveform RMS + a little **FFT peak** (tallest bin in the voice band).
 *   We deliberately use almost no **band average**: that stays high for all vowels and was
 *   keeping you stuck on "happy".
 * - **Happy** when **loudness spikes above a slow baseline** (syllable edges), not when level
 *   sits flat high — flat TTS used to keep `instant ≈ peakHold` forever → stuck on happy.
 * - **Surprised** during steady voiced segments (baseline catches up, “excess” drops).
 * - **Idle** when instant + speech body are low (tiny pauses).
 */
const BMO_TTS_MOUTH_ENERGY_GAIN = 4.35;
/** Voice-ish bins for ~48 kHz / 2048 FFT: bin ~4 → ~94 Hz, cap ~3 kHz. */
const BMO_TTS_FREQ_BIN_START = 4;
const BMO_TTS_FREQ_BIN_END = 128;
/** Slow baseline under instant; higher = baseline lags more → more happy vs mostly surprised. */
const BMO_TTS_BASELINE_EMA = 0.946;
/** Decay on the spike memory of (instant − baseline); lower = snappier surprised between hits. */
const BMO_TTS_EXCESS_PEAK_DECAY = 0.73;
/** Excess must be this close to its decaying peak to count as a hit (higher = shorter happy). */
const BMO_TTS_EXCESS_NEAR_PEAK_FRAC = 0.75;
/** Minimum “bump” above baseline to open happy (noise gate on spikes). */
const BMO_TTS_MIN_EXCESS_HAPPY = 0.022;
/** Slow envelope mix: speech present vs gap (surprised vs idle). */
const BMO_TTS_SPEECH_BODY_EMA = 0.86;

const bmoPageForTts = document.getElementById("bmo-page");

let bmoTtsMouthRaf = null;
let bmoTtsMouthTime = null;
let bmoTtsMouthFreq = null;
let bmoTtsBaseline = 0;
let bmoTtsExcessPeak = 0;
let bmoTtsSpeechBody = 0;
let bmoTtsEmotion = "idle";

function bmoComputeTtsInstant01(ttsA, timeBuf, freqBuf) {
  ttsA.getByteTimeDomainData(timeBuf);
  let rms = 0;
  for (let i = 0; i < timeBuf.length; i++) {
    const v = (timeBuf[i] - 128) / 128;
    rms += v * v;
  }
  rms = Math.sqrt(rms / timeBuf.length);
  const rms01 = Math.min(1, rms * BMO_TTS_MOUTH_ENERGY_GAIN);

  ttsA.getByteFrequencyData(freqBuf);
  const i0 = Math.min(BMO_TTS_FREQ_BIN_START, freqBuf.length);
  const i1 = Math.min(BMO_TTS_FREQ_BIN_END, freqBuf.length);
  let peak = 0;
  for (let i = i0; i < i1; i++) {
    const b = freqBuf[i];
    if (b > peak) peak = b;
  }
  const bandPeak = peak / 255;

  /* RMS + FFT peak: tiny bit more peak helps happy fire on spectral hits without flattening prosody. */
  return Math.min(1, rms01 * 0.9 + bandPeak * 0.3);
}

/**
 * nearPeak: true when loudness is spiking above the slow baseline (not sustained flat).
 * speechBody: slow level for "still talking" vs tiny gaps → surprised vs idle.
 */
function bmoStepTtsEmotion(nearPeak, speechBody, instant, prev) {
  const idleCut = 0.052;
  const idleCutHyst = 0.062;

  if (prev === "happy") {
    if (speechBody < idleCut && instant < 0.06) return "idle";
    if (!nearPeak) return "surprised";
    return "happy";
  }
  if (prev === "surprised") {
    if (speechBody < idleCut && instant < 0.055) return "idle";
    if (nearPeak) return "happy";
    return "surprised";
  }
  if (speechBody > idleCutHyst || instant > 0.085) return "surprised";
  if (nearPeak) return "happy";
  return "idle";
}

function stopBmoTtsMouthAnimation() {
  if (bmoTtsMouthRaf) {
    cancelAnimationFrame(bmoTtsMouthRaf);
    bmoTtsMouthRaf = null;
  }
  bmoPageForTts?.classList.remove("bmo-tts-mouth");
  document.getElementById("bmo-smile-svg")?.removeAttribute("data-bmo-tts-emotion");
  document.getElementById("bmo-smile-svg")?.removeAttribute("data-bmo-tts-face-track");
  bmoTtsBaseline = 0;
  bmoTtsExcessPeak = 0;
  bmoTtsSpeechBody = 0;
  bmoTtsEmotion = "idle";
}

function tickBmoTtsMouth() {
  if (!bmoPageForTts?.classList.contains("bmo-tts-mouth")) {
    stopBmoTtsMouthAnimation();
    return;
  }
  if (!document.body.classList.contains("bmo-open")) {
    stopBmoTtsMouthAnimation();
    return;
  }
  const smileSvg = document.getElementById("bmo-smile-svg");
  const ttsA = ttsByMode.bmo.analyser;
  const bmoOut = document.getElementById("bmo-audio");
  if (!smileSvg || !ttsA) {
    stopBmoTtsMouthAnimation();
    return;
  }
  const webAudioTtsPlaying = activeMainTtsBufferSources.length > 0;
  if (
    !bmoOut ||
    (!webAudioTtsPlaying &&
      !mainTtsPlaybackActive &&
      (bmoOut.paused || bmoOut.ended))
  ) {
    stopBmoTtsMouthAnimation();
    return;
  }
  if (!bmoTtsMouthTime || bmoTtsMouthTime.length !== ttsA.fftSize) {
    bmoTtsMouthTime = new Uint8Array(ttsA.fftSize);
  }
  if (!bmoTtsMouthFreq || bmoTtsMouthFreq.length !== ttsA.frequencyBinCount) {
    bmoTtsMouthFreq = new Uint8Array(ttsA.frequencyBinCount);
  }

  const instant = bmoComputeTtsInstant01(ttsA, bmoTtsMouthTime, bmoTtsMouthFreq);
  bmoTtsBaseline =
    bmoTtsBaseline * BMO_TTS_BASELINE_EMA + instant * (1 - BMO_TTS_BASELINE_EMA);
  const excess = Math.max(0, instant - bmoTtsBaseline);
  bmoTtsExcessPeak = Math.max(excess, bmoTtsExcessPeak * BMO_TTS_EXCESS_PEAK_DECAY);
  const nearPeak =
    excess >= bmoTtsExcessPeak * BMO_TTS_EXCESS_NEAR_PEAK_FRAC &&
    excess >= BMO_TTS_MIN_EXCESS_HAPPY;
  bmoTtsSpeechBody =
    bmoTtsSpeechBody * BMO_TTS_SPEECH_BODY_EMA + instant * (1 - BMO_TTS_SPEECH_BODY_EMA);
  bmoTtsEmotion = bmoStepTtsEmotion(nearPeak, bmoTtsSpeechBody, instant, bmoTtsEmotion);
  smileSvg.setAttribute("data-bmo-tts-emotion", bmoTtsEmotion);

  bmoTtsMouthRaf = requestAnimationFrame(tickBmoTtsMouth);
}

async function startBmoTtsMouthAnimation() {
  if (!document.body.classList.contains("bmo-open") || !bmoPageForTts) return;
  try {
    await ensureMainAudioTtsGraph();
  } catch (e) {
    console.warn("BMO TTS graph", e);
    return;
  }
  if (!ttsByMode.bmo.analyser) return;
  bmoPageForTts.classList.add("bmo-tts-mouth");
  document.getElementById("bmo-smile-svg")?.setAttribute("data-bmo-tts-emotion", "idle");
  bmoTtsBaseline = 0;
  bmoTtsExcessPeak = 0;
  bmoTtsSpeechBody = 0;
  bmoTtsEmotion = "idle";
  if (bmoTtsMouthRaf) return;
  bmoTtsMouthRaf = requestAnimationFrame(tickBmoTtsMouth);
}

document.getElementById("bmo-audio")?.addEventListener("playing", () => {
  void startBmoTtsMouthAnimation();
});
document.getElementById("bmo-audio")?.addEventListener("pause", () => {
  /* Chunked TTS keeps <audio> paused while BufferSources play; do not kill the mouth on that pause. */
  if (activeMainTtsBufferSources.length > 0 || mainTtsPlaybackActive) return;
  stopBmoTtsMouthAnimation();
});
document.getElementById("bmo-audio")?.addEventListener("ended", () => {
  stopBmoTtsMouthAnimation();
});

/* =========================
   SPEECH DETECTION
========================= */

function detectSpeech() {
  if (!mediaRecorder || mediaRecorder.state !== "recording") return;
  if (inputMuted) {
    suppressNextUtterance = true;
    try {
      mediaRecorder.stop();
    } catch {}
    showMutedStatusIfIdle();
    return;
  }

  const buf = new Float32Array(analyser.fftSize);
  analyser.getFloatTimeDomainData(buf);

  let sum = 0;
  for (let i = 0; i < buf.length; i++) sum += buf[i] * buf[i];
  const rms = Math.sqrt(sum / buf.length);

  const now = performance.now();

  if (listeningFrameIsSpeechLike(buf, rms)) {
    if (!hasSpoken) {
      armVoiceMaxDurationTimer("vad_speech_frame");
    }
    hasSpoken = true;
    lastVoiceTime = now;
  }

  if (
    hasSpoken &&
    now - lastVoiceTime > SILENCE_MS + TRAILING_MS &&
    (getAudioEl()?.paused ?? true) // 🔑 only stop when not speaking
  ) {
    beginVoiceUxTurn();
    mediaRecorder.stop();
    return;
  }

  rafId = requestAnimationFrame(detectSpeech);
}

function clearSpeechWaitTimerAndDetectRaf() {
  if (speechWaitTimeoutId != null) {
    clearTimeout(speechWaitTimeoutId);
    speechWaitTimeoutId = null;
  }
  if (rafId != null) {
    cancelAnimationFrame(rafId);
    rafId = null;
  }
  /* Voice-duration cap is bound to an active recording session. When the
     session is torn down (silence stop, abort, pipeline reset, PTT switch,
     etc.) the timer must not survive into the next utterance. */
  clearVoiceMaxDurationTimer();
}

/**
 * End continuous capture without uploading (e.g. switching to PTT). Clears the no-speech
 * timer so it cannot fire on the next `mediaRecorder` instance.
 */
function stopActiveMicCaptureSilently() {
  clearSpeechWaitTimerAndDetectRaf();
  if (mediaRecorder && mediaRecorder.state === "recording") {
    suppressNextUtterance = true;
    mediaRecorder.stop();
  }
  stopAllBrowserSpeechRecognizers();
}

/** Stop Web Speech + timers; does not remove the live partial bubble (used before /infer so we can promote the same node). */
function abortBrowserSpeechRecognizers() {
  if (interruptDetectNoResultWatchdogTimer != null) {
    clearTimeout(interruptDetectNoResultWatchdogTimer);
    interruptDetectNoResultWatchdogTimer = null;
  }
  if (browserAsrMainEndRecoveryTimer != null) {
    clearTimeout(browserAsrMainEndRecoveryTimer);
    browserAsrMainEndRecoveryTimer = null;
  }
  if (browserAsrStuckDebugEnabled()) {
    logBrowserAsrStuckEvent("abortBrowserSpeechRecognizers");
  }
  stopBrowserAsrStuckWatchdog();
  if (mainBrowserSilenceTimer != null) {
    clearTimeout(mainBrowserSilenceTimer);
    mainBrowserSilenceTimer = null;
  }
  [mainBrowserRecognition, interruptDetectRecognition, postInterruptRecognition].forEach(
    (r) => {
      if (!r) return;
      try {
        r.onresult = null;
        r.onerror = null;
        r.onend = null;
        r.abort();
      } catch {
        try {
          r.stop();
        } catch {}
      }
    }
  );
  mainBrowserRecognition = null;
  interruptDetectRecognition = null;
  postInterruptRecognition = null;
  interruptBrowserDetectActive = false;
  interruptPartialAccumMs = 0;
  interruptPartialLastChangeAt = 0;
  interruptPartialLastText = "";
  interruptBargeInLatched = false;
  mainBrowserFinalTranscript = "";
  mainBrowserFinalizeKind = "main";
  mainBrowserLastInterim = "";
}

function stopAllBrowserSpeechRecognizers() {
  abortBrowserSpeechRecognizers();
  try {
    if (mainBrowserLiveBubble?.isConnected) {
      mainBrowserLiveBubble.remove();
    }
  } catch (_) {}
  mainBrowserLiveBubble = null;
  clearInterruptDetectionBubble();
}

/**
 * Two separate `SpeechRecognition` instances: `mainBrowserRecognition` (user turn) and
 * `interruptDetectRecognition` (barge-in while assistant speaks). Chrome only reliably allows
 * one active session at a time — they are sequenced (main aborted before /infer; interrupt starts
 * at TTS `onPlayStart`; main restarts after playback ends).
 *
 * Leaked interrupt-detect handles block main `onend` recovery; we abort stale ones only when the
 * assistant is not still in a reply (`waveState !== "speaking"` and `!isAssistantTtsPlaying()`).
 * Do not tear down between streamed TTS chunks: `waveState` stays `"speaking"` even when buffers
 * are momentarily empty.
 */
function tearDownLeakedInterruptDetectSpeechRecognitionIfIdle() {
  if (!interruptDetectRecognition || interruptBargeInLatched) return;
  if (waveState === "speaking") return;
  if (isAssistantTtsPlaying()) return;
  try {
    interruptDetectRecognition.abort();
  } catch {}
  interruptDetectRecognition = null;
  interruptBrowserDetectActive = false;
  clearInterruptDetectionBubble();
}

/** After main SR `onend` or tab visible: restart main capture if we still expect desktop browser ASR. */
function maybeResumeMainBrowserSpeechRecognition(reason) {
  if (!listening || processing || inputMuted) return;
  if (waveState === "speaking") return;
  if (isAssistantTtsPlaying()) return;
  if (listeningMode !== "continuous" || !browserAsrPreferred()) return;
  tearDownLeakedInterruptDetectSpeechRecognitionIfIdle();
  if (mainBrowserRecognition || interruptDetectRecognition || postInterruptRecognition) return;
  console.info(`[BrowserASR] resume main SpeechRecognition (${reason})`);
  startListening();
}

/* PART 11 — final-result settle delay.
 *
 * The browser SpeechRecognition silence timer (browserAsrMainSilenceMs)
 * decides "user has paused long enough — finalize". But Web Speech can
 * still emit one or two more `isFinal` results in the 200-400ms after
 * silence is observed, especially for long dictation. In hybrid/whisper
 * modes we want to capture those tail finals before freezing the
 * transcript and (for hybrid) dispatching a Whisper verification request,
 * because the difference between "remove first and third" and "remove
 * first and fifth" might be carried by that tail. Streaming mode keeps
 * its existing latency profile (no extra wait).
 */
function _finalResultSettleMs() {
  const mode = getVeraAsrMode();
  if (mode === "hybrid") return 300;
  if (mode === "whisper") return 280;
  return 0;
}

function scheduleMainBrowserEndOfUtterance() {
  if (inputMuted) return;
  if (mainBrowserSilenceTimer != null) {
    clearTimeout(mainBrowserSilenceTimer);
    mainBrowserSilenceTimer = null;
  }
  const snap = (mainBrowserFinalTranscript + "").trim();
  const settleMs = _finalResultSettleMs();
  const totalMs = browserAsrMainSilenceMs + settleMs;
  mainBrowserSilenceTimer = setTimeout(() => {
    mainBrowserSilenceTimer = null;
    const cur = (mainBrowserFinalTranscript + "").trim();
    if (cur !== snap || cur.length === 0) {
      if (browserAsrStuckDebugEnabled()) {
        logBrowserAsrStuckEvent("silence_timer_fired_no_finalize", {
          reason: cur.length === 0 ? "empty_final" : "final_transcript_changed_since_schedule",
          snapAtSchedule: snap.slice(0, 80),
          curFinalNow: cur.slice(0, 80),
          interimNow: (mainBrowserLastInterim || "").slice(0, 80),
          finalizeKind: mainBrowserFinalizeKind,
        });
      }
      return;
    }
    const finalizeNow = () => {
      const cur2 = (mainBrowserFinalTranscript + "").trim();
      if (cur2.length === 0) return;
      logPartialAsrUtteranceDone(cur2, {
        reason: "silence-timer",
        mode: mainBrowserFinalizeKind === "interrupt" ? "interrupt" : "main"
      });
      if (mainBrowserFinalizeKind === "interrupt") {
        void finalizeInterruptBrowserTranscript(cur2);
      } else {
        void finalizeMainBrowserTranscript(cur2);
      }
    };
    finalizeNow();
  }, totalMs);
  logVeraSettings("schedule_asr_silence_timer", {
    ms: browserAsrMainSilenceMs,
    settle_ms: settleMs,
    total_ms: totalMs,
    asr_mode: getVeraAsrMode()
  });
}

function updateMainBrowserLiveBubble(fullText, interim) {
  if (mainAsrPartialMinChars === Infinity) return;
  const convo = uiEl("conversation");
  if (!convo) return;
  const line = (fullText + interim).trim();
  const hasFinal = String(fullText || "").trim().length > 0;
  if (!hasFinal && line.length < mainAsrPartialMinChars) return;
  if (!line) return;
  if (!mainBrowserLiveBubble || !mainBrowserLiveBubble.isConnected) {
    mainBrowserLiveBubble = addBubble(line, "user", { path: "main-browser-partial" });
  } else {
    mainBrowserLiveBubble.textContent = line;
  }
  convo.scrollTop = convo.scrollHeight;
}

function removeMainBrowserLiveBubble() {
  if (mainBrowserLiveBubble?.isConnected) {
    mainBrowserLiveBubble.remove();
  }
  mainBrowserLiveBubble = null;
}

/** When partial min is Infinity: no live bubble during ASR; create/update once at finalize so the user sees text before /infer returns. */
function showDeferredMainBrowserUserBubbleIfNeeded(trimmed) {
  if (mainAsrPartialMinChars !== Infinity) return;
  const t = String(trimmed ?? "").trim();
  if (!t) return;
  const convo = uiEl("conversation");
  if (!convo) return;
  if (!mainBrowserLiveBubble?.isConnected) {
    mainBrowserLiveBubble = addBubble(t, "user", { path: "main-browser-partial" });
  } else {
    mainBrowserLiveBubble.textContent = t;
  }
  convo.scrollTop = convo.scrollHeight;
}

/**
 * Work-mode `/infer` after optional reasoning: infer starts once the reasoning summary (voice coach)
 * is ready, overlapping the markdown tail. Upload failures skip `/infer` after the gate opens.
 * @param {object} [inferOpts]
 * @param {boolean} [inferOpts.skipPreInferPlaybackReset] When true, do not stop ongoing stage‑1 / other reply audio
 *   before `/infer` (deferred stage‑2 after the user may already be in another response).
 * @param {boolean} [inferOpts.stage2AlsoPrefix] When true, server brief-completion prompt asks the model to begin with "Also,".
 */
async function runInferAfterWorkModeReasoningPrep(formData, prep, inferOpts = {}) {
  const p = prep || {};
  await p.inferGate;
  if (p.reasoningUploadState?.failed) return "reasoning-upload-failed";
  // Snapshot was taken before reasoning prep; after the summary gate the panel often has much more
  // markdown. Refresh so /infer grounding matches what the user sees (and Voice UI excerpts stay aligned).
  try {
    if (isVeraWorkModeOn() && formData instanceof FormData) {
      const pinned = String(p.turnContext?.turn_lane_id || "").trim();
      const snap = JSON.stringify(
        buildClientContextSnapshot({
          pinnedLaneId: pinned,
          weakVoiceOnly: Boolean(pinned),
          frozenTurnLaneId: pinned
        })
      );
      if (typeof formData.set === "function") formData.set("context_snapshot", snap);
      else {
        try {
          formData.delete("context_snapshot");
        } catch (_) {}
        formData.append("context_snapshot", snap);
      }
      attachWorkModeReasoningContextToInferFormData(formData, prep);
      attachWorkModeVoiceBriefCompletionFlag(formData, prep);
      if (inferOpts.stage2AlsoPrefix) {
        if (typeof formData.set === "function") formData.set("work_mode_stage2_also_prefix", "1");
        else formData.append("work_mode_stage2_also_prefix", "1");
      }
    }
  } catch (_) {}
  if (!inferOpts.skipPreInferPlaybackReset) {
    try {
      if (typeof window !== "undefined" && window.speechSynthesis) {
        window.speechSynthesis.cancel();
      }
    } catch (_) {}
    _veraTtsCancelSource = "pre_infer_playback_reset";
    cancelMainTtsPlayback();
    try {
      const a = getAudioEl();
      if (a) {
        a.pause();
        a.currentTime = 0;
      }
    } catch (_) {}
  }
  await runInferMainPipeline(formData, {
    ...inferOpts,
    ttsTurn: prep?.ttsTurn,
    prep,
    ttsStage: 2
  });
  await p.chain;
}

function maybePlayWorkModeReasoningStage1FromPrep(prep, abortSignal, userTranscript) {
  const vs = prep?.voiceTwoStage;
  if (!vs?.reasoningRouted || !vs.stage1AckText) return Promise.resolve();
  return maybePlayWorkModeReasoningStage1VeraTts(
    vs.stage1AckText,
    abortSignal,
    userTranscript,
    prep?.ttsTurn
  );
}

async function finalizeMainBrowserTranscript(text) {
  const trimmed = (text || "").trim();
  if (inputMuted) {
    stopAllBrowserSpeechRecognizers();
    processing = false;
    voiceUxTurn = null;
    showMutedStatusIfIdle();
    return;
  }
  if (!trimmed) {
    stopAllBrowserSpeechRecognizers();
    processing = false;
    voiceUxTurn = null;
    if (listeningMode === "continuous" && listening && !inputMuted) {
      startListening();
    }
    return;
  }
  /* PART 14 (2026-05-28): emit the frontend route log for voice turns too
     so the browser console shows our classification alongside backend
     [news_router_route]. The same call site existed for typed turns just
     before armPendingNewsStatusBubble; mirroring it here covers ASR. */
  try {
    if (typeof classifyVeraTurnRoute === "function" && typeof logNewsRouterRouteFrontend === "function") {
      const _veraTurnRouteClassification = classifyVeraTurnRoute(trimmed);
      logNewsRouterRouteFrontend(trimmed, _veraTurnRouteClassification);
    }
  } catch (_) {}
  if (
    await maybeHandleWorkChecklistSyncShortcut(trimmed, {
      source: "main-browser-asr",
      isVoice: true
    })
  ) {
    return;
  }
  if (await maybeHandleWorkChecklistPlanShortcut(trimmed)) {
    return;
  }
  /* PART 3: close-reasoning-panel client shortcut. Runs BEFORE /infer so
     "close panel 2" / "close the first two panels" / "undo close" feel
     instant. The shortcut already filters out checklist/news/music/settings
     phrases and only fires in Work Mode. */
  if (maybeHandleCloseReasoningPanelShortcut(trimmed, { reason: "main-browser-asr", isVoice: true })) {
    return;
  }
  if (
    await maybeHandleMoveLatestVoiceTaskToReasoning(trimmed, {
      path: "main-browser-asr-move-voice-task",
      isVoice: true,
      signal: activePipelineAbort?.signal
    })
  ) {
    processing = false;
    requestInFlight = false;
    voiceUxTurn = null;
    waveState = "idle";
    setStatus("Ready", "idle");
    updateMuteInputButton();
    return;
  }

  if (
    await maybeRunWorkModeMultiActionPlanner(trimmed, {
      path: "main-browser-asr",
      isVoice: true
    })
  ) {
    processing = false;
    requestInFlight = false;
    voiceUxTurn = null;
    waveState = "idle";
    setStatus("Ready", "idle");
    updateMuteInputButton();
    if (listeningMode === "continuous" && listening && !inputMuted) {
      startListening();
    }
    return;
  }

  /* PART 5+6+7 — hybrid finalization decision.
     For streaming mode this returns "browser_immediate"; for hybrid mode
     decideAsrFinalizationMode classifies the utterance and may upgrade us
     to "whisper_verify". We resolve the hybrid sidecar blob (if any)
     before mutating UX state so the recorder finalizes deterministically. */
  const asrMode = getVeraAsrMode();
  const finalization = decideAsrFinalizationMode({
    browserTranscript: trimmed,
    browserConfidence: null,
    isInterruption: false,
    recentUiContext: { active_panel_id: null },
  });
  let hybridAudio = null;
  if (asrMode === "hybrid" && isHybridSidecarRunning()) {
    if (finalization.mode === "whisper_verify") {
      hybridAudio = await _stopAndCollectHybridSidecar();
    } else {
      _discardHybridSidecar();
    }
  }
  try {
    console.info("[asr_finalization_debug]", {
      stage: "main_browser_finalize",
      asr_mode: asrMode,
      hybrid_policy: HYBRID_POLICY,
      browser_final_transcript: trimmed.slice(0, 200),
      finalization_mode: finalization.mode,
      finalization_reason: finalization.reason,
      hybrid_audio_chunks: hybridAudio?.chunkCount || 0,
      hybrid_audio_duration_ms: hybridAudio?.durationMs ? Math.round(hybridAudio.durationMs) : 0,
    });
  } catch (_) {}

  if (finalization.mode === "cancel_only_immediate") {
    /* No LLM round-trip — caller already stopped TTS (the cancel happened
       during a non-interrupt main turn, which is rare but possible). */
    _discardHybridSidecar();
    stopAllBrowserSpeechRecognizers();
    processing = false;
    voiceUxTurn = null;
    setStatus("Ready", "idle");
    updateMuteInputButton();
    if (listeningMode === "continuous" && listening && !inputMuted) {
      startListening();
    }
    return;
  }

  /* Set before stopAll so a sync SpeechRecognition "onend" cannot restart ASR while we're entering infer. */
  processing = true;
  requestInFlight = true;
  beginVoiceUxTurn();
  waveState = "idle";
  setStatus("Thinking", "thinking");

  /* Keep partial bubble in DOM; commitServerUserTranscriptBubble updates the same node when /infer returns. */
  abortBrowserSpeechRecognizers();
  showDeferredMainBrowserUserBubbleIfNeeded(trimmed);
  // Arm pending news bubble BEFORE POST /infer using the final browser-ASR
  // transcript — the bubble appears during the search round-trip, not after
  // it. For server-ASR (audio-upload) paths, runInferMainPipeline's
  // formData fallback below still arms when the transcript becomes known.
  armPendingNewsStatusBubble(trimmed);

  const formData = new FormData();
  formData.append("transcript", trimmed);
  formData.append("use_browser_asr", "1");
  formData.append("session_id", getSessionId());
  formData.append("client", appModePrefix());
  formData.append("context_snapshot", JSON.stringify(buildClientContextSnapshot()));
  // 2026-05-29 — multi-action planner: voice/mic path stays SHADOW only.
  formData.append("input_source", "continuous");
  formData.append("typed", "0");
  formData.append("asr_mode", asrMode);
  formData.append("asr_finalization_mode", finalization.mode);
  formData.append("asr_finalization_reason", String(finalization.reason || ""));
  if (finalization.mode === "whisper_verify" && hybridAudio?.blob) {
    /* PART 8: when the client decides this utterance warrants a Whisper
       pass, send the audio AND the browser transcript AND the
       request_whisper_verify=1 flag so the server runs Whisper, picks the
       best transcript via chooseBestTranscript(), and uses the selected
       transcript for routing. */
    formData.append("audio", hybridAudio.blob, "hybrid_utterance.webm");
    formData.append("request_whisper_verify", "1");
    formData.append("hybrid_browser_transcript", trimmed);
    try {
      console.info("[asr_mode_debug]", {
        stage: "hybrid_dispatch_with_whisper",
        bytes: hybridAudio.blob.size,
        mime_type: hybridAudio.mimeType,
      });
    } catch (_) {}
  }
  if (listeningMode === "ptt") {
    formData.append("mode", "ptt");
  }
  formData.append("stream_tts", shouldStreamTts() ? "1" : "0");

  const voiceFiles = getWorkModePendingAttachmentFiles();
  const voiceAttach = voiceFiles[0] || null;
  const turnContext = createWorkModeFrozenTurnContext({
    userText: trimmed,
    source: voiceFiles.length ? "upload" : "voice"
  });
  appendWorkModeSubmissionLaneToFormData(formData, turnContext?.turn_lane_id);

  for (const f of voiceFiles) {
    const forInfer = f.slice(0, f.size, f.type || undefined);
    formData.append("context_files", forInfer, f.name || "upload");
  }

  logVoiceTranscript("final", trimmed, { path: "main-browser-asr" });
  logFinalTranscriptSentToLlm("main-browser-asr", trimmed);
  /* Stage 1 stabilization: browser-ASR continuous turn integrity log. The
     `text` arg to finalizeMainBrowserTranscript is the raw SR transcript;
     `trimmed` is the normalized + router input + backend payload. */
  logTurnTextIntegrity({
    source: "browser_asr",
    raw_asr_text: text,
    normalized_text: trimmed,
    router_input_text: trimmed,
    backend_payload_text: inferTranscriptFromFormData(formData),
    request_id: null,
    path: "main-browser-asr",
  });
  attachPipelineAbortSignal();
  const pipelineSig = activePipelineAbort.signal;
  logComposerAttachmentsBeforeSubmit(voiceFiles, turnContext);
  const prepP = maybePrepareWorkModeReasoning(formData, trimmed, pipelineSig, {
    attachments: voiceFiles,
    turnContext
  });
  try {
    const runTurn = async () => {
      bumpWorkModeVoiceInferTurnSeq();
      const ttsTurn = workModeTtsMetaFromTurnContext(turnContext);
      const prep = attachWorkModeTtsTurnAfterPrep(await prepP, ttsTurn, trimmed);
      if (prep?.inferThreadAnchor) formData.append("thread_follow_up_anchor", prep.inferThreadAnchor);
      if (prep?.voiceTwoStage?.reasoningRouted) {
        const stage1P = maybePlayWorkModeReasoningStage1FromPrep(prep, pipelineSig, trimmed);
        await Promise.resolve(stage1P).catch(() => {});
        const seqAtStage1End = workModeVoiceInferTurnSeq;
        scheduleWorkModeDeferredReasoningStageTwoInfer({
          formData,
          prep,
          seqAtStage1End
        });
        resumeAfterAssistantReplyPlayback();
        return undefined;
      }
      const prepFail = await runInferAfterWorkModeReasoningPrep(formData, prep, { signal: pipelineSig });
      return prepFail;
    };
    if (isVeraWorkModeOn()) {
      await enqueueWorkModeVoiceInferPlaybackTurn(runTurn);
    } else {
      await runTurn();
    }
  } catch (voiceTurnErr) {
    if (voiceFiles.length) preserveComposerAttachments("voice_turn_throw", turnContext);
    throw voiceTurnErr;
  }
}

function startMainBrowserRecognitionContinuous() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) return;
  if (inputMuted) {
    stopAllBrowserSpeechRecognizers();
    showMutedStatusIfIdle();
    return;
  }

  stopAllBrowserSpeechRecognizers();
  mainBrowserFinalizeKind = "main";

  mainBrowserFinalTranscript = "";
  let interimBuf = "";
  const asrTurnSeq = ++mainBrowserAsrTurnSeq;

  mainBrowserRecognition = new SR();
  mainBrowserRecognition.continuous = true;
  mainBrowserRecognition.interimResults = true;
  mainBrowserRecognition.lang = getSpeechRecognitionLang();

  mainBrowserRecognition.onresult = (event) => {
    if (asrTurnSeq !== mainBrowserAsrTurnSeq) return;
    if (inputMuted) {
      stopAllBrowserSpeechRecognizers();
      showMutedStatusIfIdle();
      return;
    }
    browserAsrMainNetworkRetries = 0;
    markBrowserAsrResult("main");
    interimBuf = "";
    for (let i = event.resultIndex; i < event.results.length; i++) {
      const r = event.results[i];
      if (r.isFinal) {
        const piece = r[0].transcript;
        mainBrowserFinalTranscript += piece;
        logPartialAsrSegmentFinal(piece.trim(), { mode: "main" });
      } else {
        interimBuf += r[0].transcript;
      }
    }
    mainBrowserLastInterim = interimBuf;
    const wasSpoken = hasSpoken;
    hasSpoken = mainBrowserFinalTranscript.trim().length > 0 || interimBuf.trim().length > 0;
    if (hasSpoken && !wasSpoken) {
      armVoiceMaxDurationTimer("browser_asr_first_partial_main");
    }
    if (hasSpoken && speechWaitTimeoutId != null) {
      clearTimeout(speechWaitTimeoutId);
      speechWaitTimeoutId = null;
    }
    updateMainBrowserLiveBubble(mainBrowserFinalTranscript, interimBuf);
    scheduleMainBrowserEndOfUtterance();
  };

  mainBrowserRecognition.onerror = (ev) => {
    if (asrTurnSeq !== mainBrowserAsrTurnSeq) return;
    if (browserAsrStuckDebugEnabled()) {
      logBrowserAsrStuckEvent("main onerror", { error: ev.error, message: ev.message });
    }
    if (ev.error === "aborted" || ev.error === "no-speech") return;
    if (ev.error === "network") {
      if (browserAsrMainNetworkRetries < BROWSER_ASR_MAIN_NETWORK_RETRY_MAX) {
        browserAsrMainNetworkRetries++;
        console.warn("[BrowserASR] network — retrying SpeechRecognition", browserAsrMainNetworkRetries);
        window.setTimeout(() => {
          if (!listening || processing || inputMuted) return;
          if (listeningMode !== "continuous" || !browserAsrPreferred()) return;
          startListening();
        }, 750);
        return;
      }
    }
    console.warn("[BrowserASR]", ev.error);
    if (isFatalBrowserSpeechError(ev.error)) {
      disableBrowserAsrForSession(ev.error);
      stopAllBrowserSpeechRecognizers();
      processing = false;
      voiceUxTurn = null;
      if (listeningMode === "continuous" && listening && !inputMuted) {
        setStatus("Use http://localhost or HTTPS for live captions — using mic recording", "recording");
        startListening();
      }
    }
  };

  mainBrowserRecognition.onend = () => {
    if (asrTurnSeq !== mainBrowserAsrTurnSeq) return;
    logBrowserAsrStuckEvent(
      "main onend (session ended — if unexpected while listening, partial ASR may look stuck)",
      { note: "scheduling guarded recovery if still in continuous listen mode" }
    );
    mainBrowserRecognition = null;
    /* Intentionally no synchronous restart: abort/stop during infer must not recreate SR. After natural end
       (common after long TTS gaps), renew listening once if we still expect continuous browser ASR. */
    if (browserAsrMainEndRecoveryTimer != null) {
      clearTimeout(browserAsrMainEndRecoveryTimer);
      browserAsrMainEndRecoveryTimer = null;
    }
    browserAsrMainEndRecoveryTimer = window.setTimeout(() => {
      browserAsrMainEndRecoveryTimer = null;
      maybeResumeMainBrowserSpeechRecognition("main-onend");
    }, 420);
  };

  try {
    mainBrowserRecognition.start();
    beginBrowserAsrStuckSession("main");
  } catch (e) {
    console.warn("[BrowserASR] start failed", e);
    window.setTimeout(() => {
      if (!listening || processing || inputMuted) return;
      if (listeningMode !== "continuous" || !browserAsrPreferred()) return;
      startListening();
    }, 150);
  }

  if (MAX_WAIT_FOR_BROWSER_ASR_INITIAL_MS > 0) {
    speechWaitTimeoutId = setTimeout(() => {
      speechWaitTimeoutId = null;
      if (!hasSpoken) {
        stopAllBrowserSpeechRecognizers();
        processing = false;
        voiceUxTurn = null;
      }
    }, MAX_WAIT_FOR_BROWSER_ASR_INITIAL_MS);
  }
}

function startInterruptBrowserPartialDetection() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) return;
  if (inputMuted) {
    stopAllBrowserSpeechRecognizers();
    showMutedStatusIfIdle();
    return;
  }

  if (interruptDetectNoResultWatchdogTimer != null) {
    clearTimeout(interruptDetectNoResultWatchdogTimer);
    interruptDetectNoResultWatchdogTimer = null;
  }

  clearInterruptDetectionBubble();
  interruptBargeInLatched = false;

  try {
    if (interruptDetectRecognition) {
      interruptDetectRecognition.abort();
    }
  } catch {}

  interruptDetectRecognition = new SR();
  interruptDetectRecognition.continuous = true;
  interruptDetectRecognition.interimResults = true;
  interruptDetectRecognition.lang = getSpeechRecognitionLang();

  let lastCombined = "";
  interruptPartialAccumMs = 0;
  interruptPartialLastChangeAt = 0;
  interruptPartialLastText = "";
  interruptPartialRafTime = performance.now();
  interruptBrowserDetectActive = true;

  let hadAnyResult = false;

  interruptDetectRecognition.onresult = (event) => {
    if (inputMuted) {
      stopAllBrowserSpeechRecognizers();
      showMutedStatusIfIdle();
      return;
    }
    if (!interruptBrowserDetectActive) return;
    hadAnyResult = true;

    if (interruptBargeInLatched) {
      markBrowserAsrResult("interrupt-live");
      let interimBuf = "";
      for (let i = event.resultIndex; i < event.results.length; i++) {
        const r = event.results[i];
        if (r.isFinal) {
          const piece = r[0].transcript;
          mainBrowserFinalTranscript += piece;
          logPartialAsrSegmentFinal(piece.trim(), { mode: "interrupt-live" });
        } else {
          interimBuf += r[0].transcript;
        }
      }
      mainBrowserLastInterim = interimBuf;
      const _wasSpokenPostInterrupt = hasSpoken;
      hasSpoken =
        mainBrowserFinalTranscript.trim().length > 0 || interimBuf.trim().length > 0;
      if (hasSpoken && !_wasSpokenPostInterrupt) {
        armVoiceMaxDurationTimer("browser_asr_first_partial_post_interrupt");
      }
      if (hasSpoken && speechWaitTimeoutId != null) {
        clearTimeout(speechWaitTimeoutId);
        speechWaitTimeoutId = null;
      }
      updateMainBrowserLiveBubble(mainBrowserFinalTranscript, interimBuf);
      interruptPartialLastText = (mainBrowserFinalTranscript + interimBuf).trim();
      scheduleMainBrowserEndOfUtterance();
      return;
    }

    let finalP = "";
    let interim = "";
    for (let i = 0; i < event.results.length; i++) {
      const r = event.results[i];
      if (r.isFinal) {
        finalP += r[0].transcript;
      } else {
        interim += r[0].transcript;
      }
    }
    const combined = (finalP + interim).trim();
    const now = performance.now();
    if (combined.length < 1) {
      if (
        interruptPartialLastChangeAt &&
        now - interruptPartialLastChangeAt > browserAsrInterruptGapMs
      ) {
        interruptPartialAccumMs = 0;
        interruptPartialLastText = "";
      }
      interruptPartialRafTime = now;
      return;
    }

    if (combined !== lastCombined) {
      const _wasFirstInterim = !lastCombined;
      if (interruptPartialLastChangeAt > 0) {
        const d = Math.min(Math.max(now - interruptPartialLastChangeAt, 0), 250);
        interruptPartialAccumMs += d;
      } else {
        interruptPartialAccumMs = 0;
      }
      interruptPartialLastChangeAt = now;
      lastCombined = combined;
      interruptPartialLastText = combined;
      markBrowserAsrResult("interrupt-detect");

      /* PART 1 — t1: first non-empty interim transcript starts the
         transcription leg of the timeline. t2 is refreshed on every
         subsequent interim so we can measure how long the user kept
         talking before TTS finally stopped. */
      if (_wasFirstInterim) {
        _recordInterruptTimingPoint("t1_interim_transcript_started", {
          autoStart: true,
          extra: { firstInterim: combined.slice(0, 64) },
        });
      }
      _recordInterruptTimingPoint("t2_interim_transcript_updated", {
        extra: { latestLen: combined.length },
      });

      updateInterruptDetectionBubble(combined);

      const wc = countSpeechWords(combined);
      lastInterruptProbe = {
        interruptGate: "browser_partial_asr_words",
        interruptReason: "browser_partial_asr_words",
        wordCount: wc,
        minWords: interruptBrowserMinWords,
        partialAccumMs: interruptPartialAccumMs,
        sustainMs: browserAsrInterruptSustainMs,
        partialText: combined,
      };

      const shortInterruptGate =
        wc >= 1 &&
        /\b(stop|pause|wait|hold|actually|cancel|no|explain|mute|quiet|listen)\b/i.test(
          combined
        );
      const wordGate = wc >= interruptBrowserMinWords || shortInterruptGate;
      const sustainGate = wc >= 1 && interruptPartialAccumMs >= browserAsrInterruptSustainMs;
      if (wordGate || sustainGate) {
        /* PART 1 — t4: gate passed via browser ASR partials. */
        _recordInterruptTimingPoint("t4_interrupt_intent_detected", {
          autoStart: true,
          extra: {
            gate: shortInterruptGate
              ? "browser_asr_short_interrupt_word"
              : wordGate
                ? "browser_asr_word"
                : "browser_asr_sustain",
            word_count: wc,
          },
        });
        logInterruptTranscriptDebug("speech_detected", {
          tts_id: interruptPrearmTtsId || null,
          time_since_tts_start_ms: Number((now - (audioStartedAt || now)).toFixed(1)),
          speech_confirm_delay_ms: Number((interruptPartialAccumMs || 0).toFixed(1)),
          rms: null,
          vad_score: null,
          preroll_available_ms: 0,
          gate: shortInterruptGate
            ? "browser_asr_short_interrupt_word"
            : wordGate
              ? "browser_asr_word"
              : "browser_asr_sustain",
          word_count: wc
        });
        onBrowserInterruptBargeInFromDetect(event);
        interruptPartialRafTime = now;
        return;
      }
    } else if (
      interruptPartialLastChangeAt &&
      now - interruptPartialLastChangeAt > browserAsrInterruptGapMs
    ) {
      interruptPartialAccumMs = 0;
    }
    interruptPartialRafTime = now;
  };

  interruptDetectRecognition.onend = () => {
    if (interruptDetectNoResultWatchdogTimer != null) {
      clearTimeout(interruptDetectNoResultWatchdogTimer);
      interruptDetectNoResultWatchdogTimer = null;
    }
    logBrowserAsrStuckEvent("interrupt_detect onend", {
      note: "detector SR ended; barge-in live stream uses same object until abort",
    });
    interruptBrowserDetectActive = false;
    interruptDetectRecognition = null;
  };

  interruptDetectRecognition.onerror = (ev) => {
    if (browserAsrStuckDebugEnabled()) {
      logBrowserAsrStuckEvent("interrupt_detect onerror", {
        error: ev.error,
        message: ev.message,
      });
    }
    if (isFatalBrowserSpeechError(ev.error)) {
      disableBrowserAsrForSession(ev.error);
      try {
        interruptDetectRecognition?.abort();
      } catch {}
      interruptDetectRecognition = null;
      interruptBrowserDetectActive = false;
    }
  };

  try {
    interruptDetectRecognition.start();
    beginBrowserAsrStuckSession("interrupt-detect");
    interruptDetectNoResultWatchdogTimer = window.setTimeout(() => {
      interruptDetectNoResultWatchdogTimer = null;
      if (hadAnyResult || interruptBargeInLatched) return;
      if (!isAssistantTtsPlaying()) return;
      if (!interruptDetectRecognition) return;
      try {
        interruptDetectRecognition.abort();
      } catch {}
      interruptBrowserDetectActive = false;
      interruptDetectRecognition = null;
    }, 4000);
  } catch (e) {
    interruptBrowserDetectActive = false;
    try {
      interruptDetectRecognition?.abort();
    } catch {}
    interruptDetectRecognition = null;
  }
}

function startPostInterruptBrowserRecognition() {
  const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SR) return;
  if (inputMuted) {
    stopAllBrowserSpeechRecognizers();
    showMutedStatusIfIdle();
    return;
  }

  const seedTranscript = (interruptPartialLastText || "").trim();
  abortBrowserSpeechRecognizers();
  mainBrowserFinalTranscript = seedTranscript;
  mainBrowserFinalizeKind = "interrupt";

  let interimBuf = "";

  postInterruptRecognition = new SR();
  postInterruptRecognition.continuous = true;
  postInterruptRecognition.interimResults = true;
  postInterruptRecognition.lang = getSpeechRecognitionLang();

  postInterruptRecognition.onresult = (event) => {
    if (inputMuted) {
      stopAllBrowserSpeechRecognizers();
      showMutedStatusIfIdle();
      return;
    }
    markBrowserAsrResult("post-interrupt");
    interimBuf = "";
    for (let i = event.resultIndex; i < event.results.length; i++) {
      const r = event.results[i];
      if (r.isFinal) {
        const piece = r[0].transcript;
        mainBrowserFinalTranscript += piece;
        logPartialAsrSegmentFinal(piece.trim(), { mode: "post-interrupt" });
      } else {
        interimBuf += r[0].transcript;
      }
    }
    mainBrowserLastInterim = interimBuf;
    updateMainBrowserLiveBubble(mainBrowserFinalTranscript, interimBuf);
    scheduleMainBrowserEndOfUtterance();
  };

  postInterruptRecognition.onerror = (ev) => {
    if (browserAsrStuckDebugEnabled()) {
      logBrowserAsrStuckEvent("post-interrupt onerror", {
        error: ev.error,
        message: ev.message,
      });
    }
    if (isFatalBrowserSpeechError(ev.error)) {
      disableBrowserAsrForSession(ev.error);
      stopAllBrowserSpeechRecognizers();
      listening = true;
      startListening();
    }
  };

  postInterruptRecognition.onend = () => {
    logBrowserAsrStuckEvent("post-interrupt onend", {});
    postInterruptRecognition = null;
    mainBrowserRecognition = null;
  };

  mainBrowserRecognition = postInterruptRecognition;

  try {
    postInterruptRecognition.start();
    beginBrowserAsrStuckSession("post-interrupt");
  } catch (e) {
    listening = true;
    startListening();
  }
}

/**
 * Run the same client-side shortcuts the normal voice / typed pipelines use
 * (sync plan, plan shortcut, move latest Voice UI answer to reasoning).
 * Returns true if any shortcut handled the request, in which case the
 * caller must NOT POST to /infer.
 *
 * The shortcut handlers themselves take care of committing the mutation,
 * showing the user bubble, queueing the short confirmation, and resuming
 * listening — exactly as they do on the normal path — so a sync request
 * that arrives as a barge-in produces the same client-side effect as the
 * same words spoken outside an interruption.
 */
async function maybeRunInterruptionClientShortcuts(routedText, originalText) {
  if (!routedText) return false;
  if (!isVeraWorkModeOn() || appModePrefix() !== "vera") return false;
  const baseCtx = (() => {
    try {
      return describePlanSyncActiveContext();
    } catch (_) {
      return { active_panel_id: null, active_panel_title: "", active_lane_id: null };
    }
  })();
  const hasReasoningOutput = (() => {
    try {
      return Boolean((getLatestWorkModeReasoningMarkdown() || "").trim());
    } catch (_) {
      return false;
    }
  })();
  const checklistState = (() => {
    try { return _checklistDomState(); } catch (_) { return { exists: false, visible: false }; }
  })();

  try {
    if (
      await maybeHandleWorkChecklistSyncShortcut(routedText, {
        source: "voice_interruption",
        isVoice: true
      })
    ) {
      logInterruptTranscriptDebug("routed_to_normal_user_turn", {
        original_transcript: String(originalText || "").slice(0, 120),
        normalized_command_text: routedText.slice(0, 120),
        shortcut: "checklist_sync",
        checklist_sync_intent_detected: true,
        sync_action_started: true,
        sync_source: "voice_interruption",
        active_panel_id_at_interruption: baseCtx.active_panel_id,
        latest_reasoning_output_available: hasReasoningOutput,
        checklist_state_available: Boolean(checklistState.exists),
        handled: true
      });
      return true;
    }
    if (await maybeHandleWorkChecklistPlanShortcut(routedText)) {
      logInterruptTranscriptDebug("routed_to_normal_user_turn", {
        original_transcript: String(originalText || "").slice(0, 120),
        normalized_command_text: routedText.slice(0, 120),
        shortcut: "checklist_plan",
        checklist_sync_intent_detected: false,
        sync_action_started: false,
        sync_source: "voice_interruption",
        active_panel_id_at_interruption: baseCtx.active_panel_id,
        latest_reasoning_output_available: hasReasoningOutput,
        checklist_state_available: Boolean(checklistState.exists),
        handled: true
      });
      return true;
    }
    if (
      await maybeHandleMoveLatestVoiceTaskToReasoning(routedText, {
        path: "voice-interruption-move-voice-task",
        isVoice: true
      })
    ) {
      logInterruptTranscriptDebug("routed_to_normal_user_turn", {
        original_transcript: String(originalText || "").slice(0, 120),
        normalized_command_text: routedText.slice(0, 120),
        shortcut: "move_voice_task_to_reasoning",
        checklist_sync_intent_detected: false,
        sync_action_started: false,
        sync_source: "voice_interruption",
        active_panel_id_at_interruption: baseCtx.active_panel_id,
        latest_reasoning_output_available: hasReasoningOutput,
        checklist_state_available: Boolean(checklistState.exists),
        handled: true
      });
      return true;
    }
    if (maybeHandleCloseReasoningPanelShortcut(routedText, { reason: "voice_interruption", isVoice: true })) {
      logInterruptTranscriptDebug("routed_to_normal_user_turn", {
        original_transcript: String(originalText || "").slice(0, 120),
        normalized_command_text: routedText.slice(0, 120),
        shortcut: "close_reasoning_panel",
        checklist_sync_intent_detected: false,
        sync_action_started: false,
        sync_source: "voice_interruption",
        active_panel_id_at_interruption: baseCtx.active_panel_id,
        latest_reasoning_output_available: hasReasoningOutput,
        checklist_state_available: Boolean(checklistState.exists),
        handled: true
      });
      return true;
    }
  } catch (err) {
    logInterruptTranscriptDebug("shortcut_error", {
      normalized_command_text: routedText.slice(0, 120),
      error_message: String(err?.message || err || "").slice(0, 200),
      handled: false
    });
  }
  return false;
}

async function finalizeInterruptBrowserTranscript(text) {
  const trimmed = (text || "").trim();
  if (inputMuted) {
    stopAllBrowserSpeechRecognizers();
    processing = false;
    requestInFlight = false;
    showMutedStatusIfIdle();
    return;
  }
  if (!trimmed) {
    stopAllBrowserSpeechRecognizers();
    listening = true;
    startListening();
    return;
  }

  /* Classify the interruption BEFORE talking to the server so:
       - pure cancel phrases ("stop") never spend a /infer round trip,
       - leading cancel prefixes ("stop, sync the plan") are stripped so
         the routing layer sees the actionable command,
       - regular interruption commands go through the same client-side
         shortcuts the normal voice path uses (sync plan, move-to-panel,
         …), so a barge-in cannot swallow an actionable command. */
  const classification = classifyInterruptionTranscript(trimmed);
  const routedText = classification.normalizedCommandText || trimmed;
  logInterruptTranscriptDebug("classification", {
    transcript: trimmed.slice(0, 120),
    is_cancel_only: classification.isCancelOnly,
    has_action_intent: classification.hasActionIntent,
    normalized_command_text: routedText.slice(0, 120),
    leading_cancel_stripped: classification.leadingCancelStripped,
    classification: classification.isCancelOnly
      ? "cancel_only"
      : classification.hasActionIntent
        ? "action_command"
        : "ignored_noise",
    reason: classification.reason
  });

  if (classification.isCancelOnly) {
    /* TTS already stopped on the barge-in detector path. Just resume
       listening — do NOT POST to /infer. */
    try { showDeferredMainBrowserUserBubbleIfNeeded(trimmed); } catch (_) {}
    stopAllBrowserSpeechRecognizers();
    processing = false;
    requestInFlight = false;
    voiceUxTurn = null;
    listening = true;
    setStatus("Listening…", "recording");
    logInterruptTranscriptDebug("cancel_only_completed", {
      transcript: trimmed.slice(0, 120),
      routed_to_normal_user_turn: false,
      normal_router_called: false,
      reason: "cancel_only_no_action"
    });
    startListening();
    return;
  }

  /* Show the user's actual bubble (what they said, including any "stop,"
     prefix) before any shortcut runs, so the chat history mirrors reality. */
  try { showDeferredMainBrowserUserBubbleIfNeeded(trimmed); } catch (_) {}

  /* Run the same client-side shortcuts the normal voice path uses. If a
     shortcut handled the command it has already committed the mutation,
     queued the confirmation, and resumed listening — return early. */
  const handledByShortcut = await maybeRunInterruptionClientShortcuts(
    routedText,
    trimmed
  );
  if (handledByShortcut) return;

  /* Fall through: route to the /infer interrupt pipeline. Use the
     normalized command text so the server sees the actionable part of
     "stop, sync the plan" rather than the cancel prefix. */
  processing = true;
  requestInFlight = true;
  waveState = "idle";
  setStatus("Thinking", "thinking");

  abortBrowserSpeechRecognizers();

  const formData = new FormData();
  formData.append("transcript", routedText);
  formData.append("use_browser_asr", "1");
  formData.append("session_id", getSessionId());
  formData.append("client", appModePrefix());
  formData.append("context_snapshot", JSON.stringify(buildClientContextSnapshot()));
  formData.append("mode", "interrupt");
  // 2026-05-29 — multi-action planner: interruptions stay SHADOW only.
  formData.append("input_source", "interruption");
  formData.append("typed", "0");
  /* PART 14 — hybrid barge-in: when the user opted into Hybrid and the
     pre-armed recorder captured this utterance, send the audio + browser
     transcript + request_whisper_verify=1 so the server picks the best
     transcript. The cancel-only case was already short-circuited above
     (no /infer round-trip), so reaching here means the interruption is
     state-changing. */
  const _interruptAsrMode = getVeraAsrMode();
  formData.append("asr_mode", _interruptAsrMode);
  const _interruptDecision = decideAsrFinalizationMode({
    browserTranscript: routedText,
    isInterruption: true,
    browserConfidence: null,
  });
  formData.append("asr_finalization_mode", _interruptDecision.mode);
  formData.append("asr_finalization_reason", String(_interruptDecision.reason || ""));
  if (
    _interruptAsrMode === "hybrid"
    && _interruptDecision.mode === "whisper_verify"
    && Array.isArray(interruptChunks)
    && interruptChunks.length > 0
  ) {
    try {
      const _ttype = interruptChunks[0]?.type || "audio/webm";
      const _ibloop = new Blob(interruptChunks, { type: _ttype });
      if (_ibloop && _ibloop.size > 0) {
        formData.append("audio", _ibloop, "hybrid_interrupt.webm");
        formData.append("request_whisper_verify", "1");
        formData.append("hybrid_browser_transcript", routedText);
        try {
          console.info("[asr_mode_debug]", {
            stage: "hybrid_interrupt_dispatch_with_whisper",
            bytes: _ibloop.size,
            mime_type: _ttype,
          });
        } catch (_) {}
      }
    } catch (_) {}
  }
  formData.append(
    "interrupt_debug",
    JSON.stringify({
      probe: lastInterruptProbe,
      browser_partial_asr: true,
      thresholds: {
        INTERRUPT_BROWSER_MIN_WORDS: interruptBrowserMinWords,
        BROWSER_ASR_INTERRUPT_SUSTAIN_MS: browserAsrInterruptSustainMs,
        BROWSER_ASR_INTERRUPT_GAP_MS: browserAsrInterruptGapMs,
      },
    })
  );
  formData.append("stream_tts", shouldStreamTts() ? "1" : "0");

  logVoiceTranscript("final", routedText, { path: "interrupt-browser-asr" });
  logFinalTranscriptSentToLlm("interrupt-browser-asr", routedText);
  /* Stage 1 stabilization: interrupt browser-ASR. `trimmed` is the raw SR
     transcript (may include a leading "stop," prefix); `routedText` is the
     normalized router input that gets sent to the server. */
  logTurnTextIntegrity({
    source: "browser_asr",
    raw_asr_text: trimmed,
    normalized_text: routedText,
    router_input_text: routedText,
    backend_payload_text: inferTranscriptFromFormData(formData),
    request_id: null,
    path: "interrupt-browser-asr",
  });
  logInterruptTranscriptDebug("asr_result", {
    transcript: routedText.slice(0, 120),
    transcript_char_count: routedText.length,
    leading_cancel_stripped: classification.leadingCancelStripped,
    original_transcript: trimmed.slice(0, 120),
    routed_to_normal_user_turn: true,
    normal_router_called: true,
    sync_source: "voice_interruption",
    possibly_cutoff: /^(explain|second|part|music)\b/i.test(routedText)
  });
  await runInferInterruptPipeline(formData);
}

/* =========================
   START LISTENING
========================= */

function startListening() {
  if (!listening || processing) return;
  if (listeningMode === "continuous" && inputMuted) {
    showMutedStatusIfIdle();
    updateMuteInputButton();
    return;
  }
  clearSpeechWaitTimerAndDetectRaf();

  if (listeningMode === "continuous" && browserAsrPreferred()) {
    waveState = "listening";
    audioChunks = [];
    hasSpoken = false;
    lastVoiceTime = 0;
    setStatus("Listening…", "recording");
    const stBrowser = uiEl("status");
    if (stBrowser) stBrowser.title = "";
    updateMuteInputButton();
    /* PART 5+7: hybrid mode runs MediaRecorder alongside browser ASR so a
       Whisper verification pass on the same audio is available later for
       risky/state-changing commands — without paying single-Whisper
       latency on every utterance. Streaming mode skips this entirely. */
    startHybridSidecarRecorderIfNeeded(micStream);
    startMainBrowserRecognitionContinuous();
    return;
  }

  waveState = "listening";
  audioChunks = [];
  hasSpoken = false;
  lastVoiceTime = 0;

  /* PART 12 helper. */
  mediaRecorder = createVeraMediaRecorder(micStream);
  mediaRecorder.ondataavailable = e => audioChunks.push(e.data);
  mediaRecorder.onstop = handleUtterance;

  mediaRecorder.start();
  detectSpeech();

  if (MAX_WAIT_FOR_MEDIA_RECORDER_INITIAL_MS > 0) {
    speechWaitTimeoutId = setTimeout(() => {
      speechWaitTimeoutId = null;
      if (!hasSpoken && mediaRecorder.state === "recording") {
        mediaRecorder.stop();
      }
    }, MAX_WAIT_FOR_MEDIA_RECORDER_INITIAL_MS);
  }

  updateMuteInputButton();
  setStatus("Listening…", "recording");
  const stEl = uiEl("status");
  if (stEl) {
    stEl.title =
      "Partial text needs Web Speech (HTTPS + a supported browser). Otherwise audio is sent after you pause speaking.";
  }
}

/* =========================
   INFER PIPELINE (shared: recorded audio or browser transcript)
========================= */

/** Completed non-NDJSON `/infer` JSON body for the main (non-interrupt) voice pipeline. */
async function processInferMainJsonPayload(data, inferTtfbMs, opts = {}) {
  const awaitStreamingPlayback = opts.awaitStreamingPlayback !== false;
  const serializeTtsPlayback = opts.serializeTtsPlayback !== false;
  const ttsTurn = opts.ttsTurn;
  const inferPrep = opts.prep;
  const inferSignal = opts.signal;
  const ttsStage = opts.ttsStage ?? 2;
  logInferLatency(data, "main", inferTtfbMs);
  requestInFlight = false;

  if (data.skip) {
    hideSidePanel();
    processing = false;
    getAudioEl()?.pause();

    if (listeningMode === "ptt") {
      setStatus("No voice detected", "idle");
    } else if (listeningMode === "continuous") {
      startListening();
    }

    return;
  }

  if (data.client_action === "mute_input") {
    hideSidePanel();
    voiceUxTurn = null;
    getAudioEl()?.pause();
    processing = false;
    setContinuousInputMuted(true);
    return;
  }
  applyClientUiAction(data.client_action);

  commitServerUserTranscriptBubble(data.transcript, "main-json");
  if (data.work_mode_timer) {
    applyWorkModeTimerPayload(data.work_mode_timer);
  }
  let playData =
    data && typeof data === "object"
      ? data
      : { reply: "", transcript: "", audio_url: "", audio_urls: [] };
  let stage2EffectivePack = null;
  if (
    inferPrep?.voiceTwoStage?.reasoningRouted &&
    ttsStage === 2 &&
    playData &&
    typeof playData === "object"
  ) {
    stage2EffectivePack = storeEffectiveStage2ReplyOnPrep(
      inferPrep,
      resolveEffectiveStage2Reply(inferPrep, playData.reply, ttsStage)
    );
    logStage2EffectiveReply(
      inferPrep,
      stage2EffectivePack,
      stage2EffectivePack.effective_stage2_reply,
      stage2EffectivePack.effective_stage2_reply
    );
    playData = { ...playData, reply: stage2EffectivePack.effective_stage2_reply };
    const stage2ReplyBack = buildWorkModeVoiceReplyBack({
      prep: inferPrep,
      userText: String(inferPrep?.turnContext?.user_text || playData?.transcript || "").trim()
    });
    ensureStage2VoiceBubble(
      inferPrep,
      stage2EffectivePack.effective_stage2_reply,
      stage2ReplyBack
    );
  }
  const isJsonWmStage2Voice = Boolean(inferPrep?.voiceTwoStage?.reasoningRouted && ttsStage === 2);
  if (isJsonWmStage2Voice) {
    const decision = getWorkModeStage2TtsDecision(playData?.reply || "");
    logStage2TtsDecision(inferPrep, decision);
    if (!decision.should_enqueue_tts) {
      logStage2Debug(inferPrep, {
        transcript: String(inferPrep?.turnContext?.user_text || playData?.transcript || "").trim(),
        reasoning_completed: true,
        reasoning_success: true,
        stage2_payload_valid: true,
        stage2_text: playData?.reply || "",
        stage2_tts_requested: false,
        stage2_tts_suppressed_due_to_mute: Boolean(decision.tts_muted),
        fallback_reason: decision.suppression_reason
      });
      if (!(inferPrep?.stage2VoiceBubble instanceof HTMLElement && inferPrep.stage2VoiceBubble.isConnected)) {
        applyAssistantReplyAndPanels(playData);
      }
      resumeAfterAssistantReplyPlayback();
      return;
    }
  }
  const playMainAnswerPromise = (async () => {
    resetAudioHandlers();
    try {
      const playTask = async () => {
        const playbackEnd = await waitForAssistantPlaybackEnd(() => {
          resumeAfterAssistantReplyPlayback();
        });
        const onPlayStart = () => {
          logVoiceFirstAudio("main-reply");
          logVoiceMainReplyAudio();
          waveState = "speaking";
          audioStartedAt = performance.now();
          resetVadFastStopState("voice_tts_start");
          const interruptTtsId = interruptTranscriptNewTtsId();
          interruptPrearmTtsId = interruptTtsId;
          if (micStream?.active) startInterruptCapture();
          void prearmInterruptCaptureForTts({ ttsId: interruptTtsId });
          if (!(inferPrep?.stage2VoiceBubble instanceof HTMLElement && inferPrep.stage2VoiceBubble.isConnected)) {
            applyAssistantReplyAndPanels(playData);
          }
          setStatus(
            listeningMode === "ptt" ? "Speaking" : "Speaking… (Interruptible)",
            "speaking"
          );
        };
        await playTtsFromApi(playData, {
          onPlayStart,
          onPlayEnd: () => {
            playbackEnd.wrappedOnFinish();
          }
        });
        await playbackEnd.donePromise;
      };
      const textPreview = String(playData?.reply || "").slice(0, 80);
      if (serializeTtsPlayback) {
        await enqueueWorkModeAssistantTtsPlayback(playTask, ttsTurn, {
          stage: opts.ttsStage ?? 2,
          text: textPreview,
          prep: inferPrep,
          abortSignal: inferSignal
        });
      } else await playTask();
    } catch (e) {
      console.warn(e);
    }
  })();

  if (awaitStreamingPlayback) await playMainAnswerPromise;
  else void playMainAnswerPromise;
}

/** Pull the user transcript from /infer FormData, if present, so the pending
 *  news bubble can be armed at pipeline entry without waiting for NDJSON
 *  `meta.transcript`. Safe on FormData-less callers (returns ""). */
function _readInferFormDataTranscript(formData) {
  try {
    if (formData && typeof formData.get === "function") {
      const t = formData.get("transcript");
      if (typeof t === "string") return t;
    }
  } catch (_) {}
  return "";
}

async function runInferMainPipeline(formData, opts = {}) {
  // Earliest possible point inside the pipeline — fires BEFORE the network
  // round-trip when the caller pushed a transcript into FormData (browser
  // ASR + typed work-mode + interrupt voice). For server-ASR audio uploads
  // there is no transcript yet; the onMeta callback below still arms when
  // the server returns `meta.transcript`. armPendingNewsStatusBubble is
  // idempotent (dedupe via dataset.pendingForText), so a later arm with the
  // same text is a no-op.
  armPendingNewsStatusBubble(_readInferFormDataTranscript(formData));
  try {
    await flushWorkChecklistSyncBeforeCommand();
    logVoicePipe("POST /infer starting (main, upload in flight)");
    const inferFetchStart = performance.now();
    const inferSignal = opts.signal ?? attachPipelineAbortSignal();
    const ttsTurn = opts.ttsTurn;
    const inferPrep = opts.prep;
    const inferUserText = inferTranscriptFromFormData(formData);
    const stage2ReplyBack =
      isVeraWorkModeOn() &&
      appModePrefix() === "vera" &&
      inferPrep?.voiceTwoStage?.reasoningRouted &&
      opts.ttsStage === 2
        ? buildWorkModeVoiceReplyBack({ prep: inferPrep, userText: inferUserText })
        : null;
    const isWmStage2Voice =
      (opts.ttsStage ?? 2) === 2 && inferPrep?.voiceTwoStage?.reasoningRouted;
    /* Default on: wait for NDJSON / sentence TTS to finish so the next infer cannot start playback on top (pass false to opt out). */
    const awaitStreamingPlayback = opts.awaitStreamingPlayback !== false;
    /* Default true: consecutive voice/work-mode turns must not start NDJSON TTS until the prior reply finishes. */
    const serializeTtsPlayback = opts.serializeTtsPlayback !== false;
    /* PART 10/11: per-request client-side id propagated as headers + form
       field. Server still generates its own request_id (returned in JSON
       response or NDJSON done line); this one is used by
       window.veraConcurrencyDebug() to show what THIS tab last fired. */
    const _inferClientRequestId = recordVeraRequestId("infer", newVeraRequestId());
    try { formData.set("client_request_id", _inferClientRequestId); } catch (_) {
      try { formData.append("client_request_id", _inferClientRequestId); } catch (_) {}
    }
    const res = await fetch(`${API_URL}/infer`, {
      method: "POST",
      headers: {
        "X-Vera-Request-Id": _inferClientRequestId,
        "X-Vera-Session-Id": getSessionId(),
      },
      body: formData,
      signal: inferSignal
    });
    const inferTtfbMs = performance.now() - inferFetchStart;
    logVoicePipe("POST /infer response headers (main — TTFB)");

    const responseIsNdjson = res.ok && isNdjsonTtsResponse(res);
    const ttsSuppressedDueToMute =
      isWmStage2Voice
        ? getWorkModeStage2TtsDecision("").tts_muted
        : appModePrefix() === "vera" &&
          isVeraWorkModeOn() &&
          (isWorkModeMuteEnabled() || Boolean(inputMuted));
    if (responseIsNdjson) {
      requestInFlight = false;

      let ndjsonMeta = null;
          const streamReplyState = createNdjsonStreamingReplyState(stage2ReplyBack, {
            suppressReplyProgress: isWmStage2Voice
          });
          let wmStage2EffectivePack = null;
          const ndjsonPlaybackPromise = (async () => {
            try {
              console.log("[UX][TTS] NDJSON streaming (main)");
              await tryPeekApplyWorkModeTimerFromNdjsonClone(res);
              const ndjsonOpts = {
                onMeta: (meta) => {
                  ndjsonMeta = { ...ndjsonMeta, ...meta };
                  if (
                    !streamReplyState.pendingReplyBack &&
                    meta.work_mode_voice_brief_completion === true &&
                    meta.work_mode_voice_quote != null &&
                    String(meta.work_mode_voice_quote).trim()
                  ) {
                    const q = String(meta.work_mode_voice_quote).trim();
                    streamReplyState.pendingVoiceQuote = q;
                    streamReplyState.pendingReplyBack = {
                      reply_to_user_text: q,
                      reply_to_turn_id: "",
                      reply_to_lane_id: "",
                      reply_to_lane_title: "",
                      stage: 2
                    };
                  }
                  if (meta.work_mode_timer) {
                    applyWorkModeTimerPayload(meta.work_mode_timer);
                  }
                  applyWorkModeLaneDebugFromInferMeta(meta);
                  if (meta.transcript) {
                    applyNdjsonUserTranscriptBubble(meta.transcript, "main-ndjson");
                    // Arm pending news bubble for voice — we only know the
                    // utterance once the server returns the ASR transcript.
                    // Cancelled by applyNdjsonStreamingReplySoFar /
                    // finalizeNdjsonStreamingReply when the real reply hits.
                    armPendingNewsStatusBubble(meta.transcript);
                    /* Stage 1 stabilization: pure-whisper NDJSON path. Only
                       fire if formData carried NO client-side transcript —
                       browser-ASR / typed / work-mode-preflight cases were
                       already logged at the fetch site. */
                    try {
                      const _clientTranscript = inferTranscriptFromFormData(formData);
                      if (!_clientTranscript) {
                        logTurnTextIntegrity({
                          source: "whisper",
                          raw_asr_text: null,
                          normalized_text: meta.transcript,
                          router_input_text: meta.transcript,
                          backend_payload_text: "",
                          request_id: _inferClientRequestId,
                          path: "main-ndjson-whisper",
                        });
                      }
                    } catch (_) {}
                  }
                },
                onReplyProgress: (replySoFar) => {
                  applyNdjsonStreamingReplySoFar(replySoFar, streamReplyState);
                },
                onDone: (done) => {
                  logInferLatency(done, "main", inferTtfbMs);
                  let effectiveReply = String(done?.reply || "").trim();
                  if (isWmStage2Voice) {
                    wmStage2EffectivePack = storeEffectiveStage2ReplyOnPrep(
                      inferPrep,
                      resolveEffectiveStage2Reply(inferPrep, done?.reply, opts.ttsStage ?? 2)
                    );
                    effectiveReply = wmStage2EffectivePack.effective_stage2_reply;
                    streamReplyState.stage2EffectiveLocked = true;
                    logStage2EffectiveReply(
                      inferPrep,
                      wmStage2EffectivePack,
                      effectiveReply,
                      effectiveReply
                    );
                  }
                  if (inferPrep?.voiceTwoStage?.reasoningRouted && inferPrep?.turnContext) {
                    const tc = inferPrep.turnContext;
                    const wm = getWorkModeLaneHandoff(String(tc.turn_lane_id || "").trim());
                    console.info("[stage2_voice_generation]", {
                      turn_id: tc.turn_id || null,
                      lane_id: tc.turn_lane_id || null,
                      lane_title: String(tc.turn_lane_title || "").trim() || null,
                      current_user_text: String(tc.user_text || "").trim(),
                      turn_intent: tc.turn_intent || null,
                      main_context_type: wm?.main_context_type || null,
                      reasoning_summary_preview: previewWorkModeRegistryText(
                        wm?.latest_reasoning_summary || ""
                      ),
                      generated_stage2_text: String(
                        wmStage2EffectivePack?.generated_stage2_text ?? done?.reply ?? ""
                      ).slice(0, 500),
                      effective_stage2_reply: effectiveReply,
                      used_tts_fallback: Boolean(wmStage2EffectivePack?.used_override),
                      tts_override_reason: wmStage2EffectivePack?.override_reason ?? null
                    });
                    logStage2Debug(inferPrep, {
                      transcript: inferUserText,
                      reasoning_completed: true,
                      reasoning_success: true,
                      stage2_payload_valid: true,
                      stage2_text: effectiveReply,
                      stage2_tts_requested: !ttsSuppressedDueToMute,
                      stage2_tts_suppressed_due_to_mute: ttsSuppressedDueToMute
                    });
                    try {
                      console.table([
                        {
                          turn_id: tc.turn_id,
                          lane_id: tc.turn_lane_id,
                          lane_title: String(tc.turn_lane_title || "").trim(),
                          turn_intent: tc.turn_intent,
                          main_context_type: wm?.main_context_type,
                          preview: previewWorkModeRegistryText(String(effectiveReply || ""))
                        }
                      ]);
                    } catch (_) {}
                  }
                  const replyBackForBubble =
                    streamReplyState.pendingReplyBack ||
                    stage2ReplyBack ||
                    buildWorkModeVoiceReplyBack({ prep: inferPrep, userText: inferUserText });
                  finalizeNdjsonStreamingReply(
                    ndjsonMeta,
                    { ...done, reply: effectiveReply },
                    streamReplyState
                  );
                  applyNdjsonActionPayloadEvent({ ...done, reply: effectiveReply }, "done");
                  if (isWmStage2Voice && effectiveReply) {
                    const bubble = ensureStage2VoiceBubble(
                      inferPrep,
                      effectiveReply,
                      replyBackForBubble
                    );
                    if (bubble) streamReplyState.bubble = bubble;
                  }
                },
                onPlayStart: () => {
                  logVoiceFirstAudio("main-reply");
                  logVoiceMainReplyAudio();
                  waveState = "speaking";
                  audioStartedAt = performance.now();
                  resetVadFastStopState("voice_tts_start_ndjson");
                  const interruptTtsId = interruptTranscriptNewTtsId();
                  interruptPrearmTtsId = interruptTtsId;
                  if (micStream?.active) startInterruptCapture();
                  void prearmInterruptCaptureForTts({ ttsId: interruptTtsId });
                  applyNdjsonActionPayloadEvent(ndjsonMeta, "meta");
                  setStatus(
                    listeningMode === "ptt" ? "Speaking" : "Speaking… (Interruptible)",
                    "speaking"
                  );
                }
              };
              const consumeNdjsonTextOnly = async () => {
                await runNdjsonTtsPlayback(res, {
                  ...ndjsonOpts,
                  skipAudio: true,
                  suppressReplyProgress: isWmStage2Voice
                });
              };
              const playTask = async () => {
                const playbackEnd = await waitForAssistantPlaybackEnd(() => {
                  resumeAfterAssistantReplyPlayback();
                });
                resetAudioHandlers();
                if (isWmStage2Voice) {
                  await runNdjsonTtsPlayback(res, {
                    ...ndjsonOpts,
                    skipAudio: true,
                    suppressReplyProgress: true
                  });
                  const phrase = String(
                    wmStage2EffectivePack?.effective_stage2_reply ||
                      inferPrep?.effectiveStage2Reply?.effective_stage2_reply ||
                      ""
                  ).trim();
                  const liveStage2TtsDecision = getWorkModeStage2TtsDecision(phrase);
                  logStage2TtsDecision(inferPrep, liveStage2TtsDecision);
                  if (phrase && liveStage2TtsDecision.should_enqueue_tts) {
                    await playWorkModeTtsOnlyPhrase(phrase, inferSignal);
                  } else if (phrase && liveStage2TtsDecision.tts_muted) {
                    logStage2Debug(inferPrep, {
                      transcript: inferUserText,
                      reasoning_completed: true,
                      reasoning_success: true,
                      stage2_payload_valid: true,
                      stage2_text: phrase,
                      stage2_tts_requested: false,
                      stage2_tts_suppressed_due_to_mute: true,
                      fallback_reason: liveStage2TtsDecision.suppression_reason
                    });
                  }
                  playbackEnd.wrappedOnFinish();
                } else if (ttsSuppressedDueToMute) {
                  await runNdjsonTtsPlayback(res, {
                    ...ndjsonOpts,
                    skipAudio: true
                  });
                  playbackEnd.wrappedOnFinish();
                } else {
                  await runNdjsonTtsPlayback(res, {
                    ...ndjsonOpts,
                    onPlayEnd: () => {
                      playbackEnd.wrappedOnFinish();
                    }
                  });
                }
                await playbackEnd.donePromise;
              };
              const textPreview = isWmStage2Voice ? "(wm-stage2)" : "";
              if (isWmStage2Voice) {
                const preDecision = getWorkModeStage2TtsDecision("(pending-stage2-text)");
                if (preDecision.tts_muted) {
                  logStage2TtsDecision(inferPrep, {
                    ...preDecision,
                    stage2_text_present: true,
                    should_enqueue_tts: false
                  });
                  await consumeNdjsonTextOnly();
                  resumeAfterAssistantReplyPlayback();
                } else if (serializeTtsPlayback) {
                  await enqueueWorkModeAssistantTtsPlayback(playTask, ttsTurn, {
                    stage: opts.ttsStage ?? 2,
                    text: textPreview,
                    prep: inferPrep,
                    onDrop: consumeNdjsonTextOnly,
                    abortSignal: inferSignal
                  });
                } else await playTask();
              } else if (serializeTtsPlayback) {
                await enqueueWorkModeAssistantTtsPlayback(playTask, ttsTurn, {
                  stage: opts.ttsStage ?? 2,
                  text: textPreview,
                  prep: inferPrep,
                  onDrop: consumeNdjsonTextOnly,
                  abortSignal: inferSignal
                });
              } else await playTask();
        } catch (e) {
          if (e?.name !== "AbortError") {
            console.warn("[UX][TTS] NDJSON main playback failed", e);
            processing = false;
            requestInFlight = false;
            voiceUxTurn = null;
            if (listeningMode === "continuous" && listening && !inputMuted) {
              setStatus("Reply playback failed — try again", "offline");
              startListening();
            } else {
              setStatus("Ready", "idle");
            }
            updateMuteInputButton();
          }
        }
      })();
      if (awaitStreamingPlayback) await ndjsonPlaybackPromise;
      else void ndjsonPlaybackPromise;
      return;
    }

    const data = await res.json();
    await processInferMainJsonPayload(data, inferTtfbMs, {
      awaitStreamingPlayback,
      serializeTtsPlayback,
      ttsTurn,
      prep: inferPrep,
      ttsStage: opts.ttsStage ?? 2,
      signal: inferSignal
    });
  } catch (e) {
    if (e?.name === "AbortError") {
      hideSidePanel();
      processing = false;
      requestInFlight = false;
      cancelPendingNewsStatusBubble("abort");
      return;
    }
    hideSidePanel();
    processing = false;
    requestInFlight = false;
    setStatus("Server error", "offline");
    if (isWmStage2Voice) {
      logStage2Debug(inferPrep, {
        transcript: inferUserText,
        reasoning_completed: true,
        reasoning_success: false,
        stage2_payload_valid: false,
        stage2_error: e?.message || e,
        fallback_reason: "infer_main_error"
      });
    }
    if (!failPendingNewsStatusBubble("infer_main_error")) {
      void veraSurfaceLlmFetchFailure({ feature: "infer_main", error: e });
    }
  }
}

async function runInferInterruptPipeline(formData) {
  // Same early-arm policy as runInferMainPipeline so the placeholder appears
  // during the interrupt search/thinking window.
  armPendingNewsStatusBubble(_readInferFormDataTranscript(formData));
  try {
    logVoicePipe("POST /infer starting (interrupt, upload in flight)");
    const inferFetchStart = performance.now();
    const res = await fetch(`${API_URL}/infer`, {
      method: "POST",
      body: formData,
      signal: attachPipelineAbortSignal()
    });
    const inferTtfbMs = performance.now() - inferFetchStart;
    logVoicePipe("POST /infer response headers (interrupt)");

    if (shouldStreamTts() && res.ok && isNdjsonTtsResponse(res)) {
      requestInFlight = false;

      const runStream = async () => {
        let ndjsonMeta = null;
        const streamReplyState = createNdjsonStreamingReplyState();
        resetAudioHandlers();
        try {
          await runNdjsonTtsPlayback(res, {
            onMeta: (meta) => {
              ndjsonMeta = { ...ndjsonMeta, ...meta };
              if (
                !streamReplyState.pendingReplyBack &&
                meta.work_mode_voice_brief_completion === true &&
                meta.work_mode_voice_quote != null &&
                String(meta.work_mode_voice_quote).trim()
              ) {
                const q = String(meta.work_mode_voice_quote).trim();
                streamReplyState.pendingVoiceQuote = q;
                streamReplyState.pendingReplyBack = {
                  reply_to_user_text: q,
                  reply_to_turn_id: "",
                  reply_to_lane_id: "",
                  reply_to_lane_title: "",
                  stage: 2
                };
              }
              if (meta.work_mode_timer) {
                applyWorkModeTimerPayload(meta.work_mode_timer);
              }
              if (meta.transcript) {
                applyNdjsonUserTranscriptBubble(meta.transcript, "interrupt-ndjson");
                armPendingNewsStatusBubble(meta.transcript);
                const tr = String(meta.transcript || "").trim();
                logInterruptTranscriptDebug("asr_result", {
                  transcript: tr.slice(0, 120),
                  transcript_char_count: tr.length,
                  possibly_cutoff: /^(explain|second|part|music)\b/i.test(tr)
                });
                /* Stage 1 stabilization: pure-whisper interrupt path. Skip
                   when the client already sent a transcript (browser-ASR
                   interrupt path logs at its own fetch site). */
                try {
                  const _clientTranscript = inferTranscriptFromFormData(formData);
                  if (!_clientTranscript) {
                    logTurnTextIntegrity({
                      source: "whisper",
                      raw_asr_text: null,
                      normalized_text: meta.transcript,
                      router_input_text: meta.transcript,
                      backend_payload_text: "",
                      request_id: null,
                      path: "interrupt-ndjson-whisper",
                    });
                  }
                } catch (_) {}
              }
            },
            onReplyProgress: (replySoFar) => {
              applyNdjsonStreamingReplySoFar(replySoFar, streamReplyState);
            },
            onDone: (done) => {
              logInferLatency(done, "interrupt", inferTtfbMs);
              finalizeNdjsonStreamingReply(ndjsonMeta, done, streamReplyState);
              applyNdjsonActionPayloadEvent(done, "done");
            },
            onPlayStart: () => {
              logVoiceFirstAudio("main-reply");
              logVoiceMainReplyAudio();
              applyNdjsonActionPayloadEvent(ndjsonMeta, "meta");
              waveState = "speaking";
              audioStartedAt = performance.now();
              resetVadFastStopState("voice_tts_start_action");
              setStatus("Speaking… (can only be interrupted once)", "speaking");
              processing = false;
            },
            onPlayEnd: () => {
              resumeListeningAfterInterruptPlayback();
            }
          });
        } catch (e) {
          if (e?.name !== "AbortError") console.warn(e);
        }
      };

      await runStream();
      return;
    }

    const data = await res.json();
    logInferLatency(data, "interrupt", inferTtfbMs);

    requestInFlight = false;

    if (data.skip) {
      hideSidePanel();
      processing = false;
      getAudioEl()?.pause();
      if (listeningMode === "ptt") {
        listening = false;
        waveState = "idle";
        setStatus("Ready", "idle");
        updateMuteInputButton();
        return;
      }
      listening = true;
      startListening();
      return;
    }

    if (data.client_action === "mute_input") {
      hideSidePanel();
      getAudioEl()?.pause();
      processing = false;
      listening = true;
      setContinuousInputMuted(true);
      return;
    }
    applyClientUiAction(data.client_action);

    commitServerUserTranscriptBubble(data.transcript, "interrupt-json");
    {
      const tr = String(data.transcript || "").trim();
      logInterruptTranscriptDebug("asr_result", {
        transcript: tr.slice(0, 120),
        transcript_char_count: tr.length,
        possibly_cutoff: /^(explain|second|part|music)\b/i.test(tr)
      });
    }
    if (data.work_mode_timer) {
      applyWorkModeTimerPayload(data.work_mode_timer);
    }

    await playInterruptAnswer(data);
  } catch (e) {
    if (e?.name === "AbortError") {
      hideSidePanel();
      requestInFlight = false;
      processing = false;
      cancelPendingNewsStatusBubble("abort");
      return;
    }
    hideSidePanel();
    requestInFlight = false;
    setStatus("Server error", "offline");
    listening = true;
    if (!failPendingNewsStatusBubble("infer_interrupt_error")) {
      void veraSurfaceLlmFetchFailure({ feature: "infer_interrupt", error: e });
    }
  }
}

/* =========================
   HANDLE UTTERANCE
========================= */

async function handleUtterance() {
  if (suppressNextUtterance) {
    suppressNextUtterance = false;
    processing = false;
    audioChunks = [];
    hasSpoken = false;
    clearVoiceMaxDurationTimer();
    voiceUxTurn = null;
    showMutedStatusIfIdle();
    return;
  }
  /* Utterance is being handled now (uploaded or sent to /infer). Cap timer
     is bound to the recording session — clear it so it cannot fire
     mid-upload and double-stop. */
  clearVoiceMaxDurationTimer();

  if (listeningMode === "continuous" && inputMuted) {
    processing = false;
    audioChunks = [];
    hasSpoken = false;
    voiceUxTurn = null;
    showMutedStatusIfIdle();
    return;
  }

  if (listeningMode === "continuous" && !hasSpoken) {
    processing = false;
    voiceUxTurn = null;
    startListening();
    return;
  }

  const blob = new Blob(audioChunks, { type: "audio/webm" });

  if (blob.size < MIN_AUDIO_BYTES) {
    processing = false;
    voiceUxTurn = null;

    if (listeningMode === "continuous") {
      startListening();
    }

    return;
  }
  requestInFlight = true;
  processing = true;
  waveState = "idle";

  setStatus("Thinking", "thinking");

  const formData = new FormData();
  formData.append("audio", blob);
  formData.append("session_id", getSessionId());
  formData.append("client", appModePrefix());
  formData.append("context_snapshot", JSON.stringify(buildClientContextSnapshot()));

  if (listeningMode === "ptt") {
    formData.append("mode", "ptt");
  }
  formData.append("stream_tts", shouldStreamTts() ? "1" : "0");

  appendWorkModeSubmissionLaneToFormData(formData);

  /* Server ASR (MediaRecorder) path had no transcript before `/infer`, so work-mode reasoning prep
     never ran. Preflight ASR (transcribe_only), then reuse the browser-transcript + reasoning pipeline. */
  const useWorkModeServerAsrPreflight = isVeraWorkModeOn() && appModePrefix() === "vera";
  if (useWorkModeServerAsrPreflight) {
    try {
      attachPipelineAbortSignal();
      const pipelineSig = activePipelineAbort.signal;

      const preForm = new FormData();
      preForm.append("audio", blob);
      preForm.append("session_id", getSessionId());
      preForm.append("client", appModePrefix());
      preForm.append("context_snapshot", JSON.stringify(buildClientContextSnapshot()));
      if (listeningMode === "ptt") {
        preForm.append("mode", "ptt");
      }
      preForm.append("stream_tts", "0");
      preForm.append("transcribe_only", "1");

      const preFetchStart = performance.now();
      const preRes = await fetch(`${API_URL}/infer`, {
        method: "POST",
        body: preForm,
        signal: pipelineSig
      });
      const preTtfbMs = performance.now() - preFetchStart;

      if (!preRes.ok) {
        hideSidePanel();
        processing = false;
        requestInFlight = false;
        voiceUxTurn = null;
        setStatus("Server error", "offline");
        void veraSurfaceLlmFetchFailure({
          feature: "infer_preflight",
          response: preRes
        });
        if (listeningMode === "continuous" && listening && !inputMuted) {
          startListening();
        }
        return;
      }

      const ct = (preRes.headers.get("content-type") || "").toLowerCase();
      if (ct.includes("ndjson") || ct.includes("x-ndjson")) {
        try {
          await preRes.body?.cancel?.();
        } catch (_) {}
        await runInferMainPipeline(formData, { signal: pipelineSig });
        return;
      }

      let preData;
      try {
        preData = await preRes.json();
      } catch (parseErr) {
        hideSidePanel();
        processing = false;
        requestInFlight = false;
        voiceUxTurn = null;
        setStatus("Server error", "offline");
        void veraSurfaceLlmFetchFailure({
          feature: "infer_preflight_parse",
          error: parseErr
        });
        if (listeningMode === "continuous" && listening && !inputMuted) {
          startListening();
        }
        return;
      }

      if (!preData.preflight_only) {
        await processInferMainJsonPayload(preData, preTtfbMs);
        return;
      }

      const trimmed = String(preData.transcript || "").trim();
      if (!trimmed) {
        requestInFlight = false;
        processing = false;
        voiceUxTurn = null;
        if (listeningMode === "continuous" && listening && !inputMuted) {
          startListening();
        } else {
          setStatus("Ready", "idle");
        }
        return;
      }

      if (
        await maybeHandleWorkChecklistSyncShortcut(trimmed, {
          source: "server-asr-preflight",
          isVoice: true
        })
      ) {
        requestInFlight = false;
        processing = false;
        voiceUxTurn = null;
        setStatus("Ready", "idle");
        updateMuteInputButton();
        return;
      }
      if (await maybeHandleWorkChecklistPlanShortcut(trimmed)) {
        requestInFlight = false;
        processing = false;
        voiceUxTurn = null;
        setStatus("Ready", "idle");
        updateMuteInputButton();
        return;
      }
      if (maybeHandleCloseReasoningPanelShortcut(trimmed, { reason: "server-asr-preflight", isVoice: true })) {
        return;
      }
      if (
        await maybeHandleMoveLatestVoiceTaskToReasoning(trimmed, {
          path: "work-mode-server-asr-move-voice-task",
          isVoice: true,
          signal: pipelineSig
        })
      ) {
        requestInFlight = false;
        processing = false;
        voiceUxTurn = null;
        waveState = "idle";
        setStatus("Ready", "idle");
        updateMuteInputButton();
        return;
      }

      if (
        await maybeRunWorkModeMultiActionPlanner(trimmed, {
          path: "server-asr-preflight",
          isVoice: true
        })
      ) {
        requestInFlight = false;
        processing = false;
        voiceUxTurn = null;
        waveState = "idle";
        setStatus("Ready", "idle");
        updateMuteInputButton();
        if (listeningMode === "continuous" && listening && !inputMuted) {
          startListening();
        }
        return;
      }

      ensureChatStartedLayout();
      beginVoiceUxTurn();

      const voiceAttach2Files = getWorkModePendingAttachmentFiles();
      const turnContext = createWorkModeFrozenTurnContext({
        userText: trimmed,
        source: voiceAttach2Files.length ? "upload" : "voice"
      });

      const formData2 = new FormData();
      formData2.append("transcript", trimmed);
      formData2.append("use_browser_asr", "1");
      formData2.append("session_id", getSessionId());
      formData2.append("client", appModePrefix());
      formData2.append("context_snapshot", JSON.stringify(buildClientContextSnapshot()));
      formData2.append("stream_tts", shouldStreamTts() ? "1" : "0");
      // 2026-05-29 — multi-action planner: voice followup stays SHADOW only.
      formData2.append("input_source", listeningMode === "ptt" ? "ptt" : "voice");
      formData2.append("typed", "0");
      if (listeningMode === "ptt") {
        formData2.append("mode", "ptt");
      }

      appendWorkModeSubmissionLaneToFormData(formData2, turnContext?.turn_lane_id);

      if (voiceAttach2Files.length) {
        for (const f of voiceAttach2Files) {
          const forInfer2 = f.slice(0, f.size, f.type || undefined);
          formData2.append("context_files", forInfer2, f.name || "upload");
        }
      }

      logVoiceTranscript("final", trimmed, { path: "work-mode-server-asr" });
      logFinalTranscriptSentToLlm("work-mode-server-asr", trimmed);
      /* Stage 1 stabilization: whisper-preflight work-mode. `trimmed` is
         the server-returned transcript from the transcribe_only preflight;
         raw_asr_text is null because Whisper does not expose a "pre-norm"
         form to the client. */
      logTurnTextIntegrity({
        source: "whisper",
        raw_asr_text: null,
        normalized_text: trimmed,
        router_input_text: trimmed,
        backend_payload_text: inferTranscriptFromFormData(formData2),
        request_id: null,
        path: "work-mode-server-asr",
      });
      logComposerAttachmentsBeforeSubmit(voiceAttach2Files, turnContext);
      const prepP = maybePrepareWorkModeReasoning(formData2, trimmed, pipelineSig, {
        attachments: voiceAttach2Files,
        turnContext
      });
      try {
        const runTurn = async () => {
          bumpWorkModeVoiceInferTurnSeq();
          const ttsTurn = workModeTtsMetaFromTurnContext(turnContext);
          const prepWrap = attachWorkModeTtsTurnAfterPrep(await prepP, ttsTurn, trimmed);
          if (prepWrap?.inferThreadAnchor) {
            formData2.append("thread_follow_up_anchor", prepWrap.inferThreadAnchor);
          }
          if (prepWrap?.voiceTwoStage?.reasoningRouted) {
            const stage1P = maybePlayWorkModeReasoningStage1FromPrep(prepWrap, pipelineSig, trimmed);
            await Promise.resolve(stage1P).catch(() => {});
            const seqAtStage1End = workModeVoiceInferTurnSeq;
            scheduleWorkModeDeferredReasoningStageTwoInfer({
              formData: formData2,
              prep: prepWrap,
              seqAtStage1End
            });
            resumeAfterAssistantReplyPlayback();
            return undefined;
          }
          const prepFail = await runInferAfterWorkModeReasoningPrep(formData2, prepWrap, {
            signal: pipelineSig
          });
          return prepFail;
        };
        const prepFail = isVeraWorkModeOn()
          ? await enqueueWorkModeVoiceInferPlaybackTurn(runTurn)
          : await runTurn();
        if (prepFail === "reasoning-upload-failed") {
          processing = false;
          requestInFlight = false;
          voiceUxTurn = null;
          setStatus("Ready", "idle");
          return;
        }
      } catch (serverAsrPrepErr) {
        if (voiceAttach2Files.length) {
          preserveComposerAttachments("server_asr_prep_throw", turnContext);
        }
        throw serverAsrPrepErr;
      }
    } catch (err) {
      if (err?.name === "AbortError") {
        hideSidePanel();
        processing = false;
        requestInFlight = false;
        voiceUxTurn = null;
        return;
      }
      console.warn("[WorkMode] server-asr preflight", err);
      hideSidePanel();
      processing = false;
      requestInFlight = false;
      voiceUxTurn = null;
      setStatus("Server error", "offline");
      void veraSurfaceLlmFetchFailure({
        feature: "infer_preflight_workmode",
        error: err
      });
      if (listeningMode === "continuous" && listening && !inputMuted) {
        startListening();
      }
    }
    return;
  }

  await runInferMainPipeline(formData);
}

/* =========================
   WORK MODE MULTI-ACTION PLANNER
   ----------------------------------------------------------------------
   Spec: compound commands like "go to panel 2 and explain the Vietnam
   War" used to lose the second action because the panel-navigation
   route in the backend action router would match first and return,
   dropping the reasoning generation. The planner runs BEFORE the
   existing Work Mode single-action shortcuts and the backend /infer
   router so it can split a compound request into ordered actions and
   dispatch each one through the existing handlers.

   Scope is intentionally narrow:
     - Only fires inside Work Mode (sendVeraWorkModeTypedInferTurn).
     - Only fires when planUserCommand returns isMultiAction:true.
     - Recursive calls from the executor pass __skipMultiActionPlanner
       so a segment never re-enters the planner.

   Design choices:
     - Pure regex / heuristic split (no LLM): preserves latency budget
       and avoids a new network hop for what is fundamentally a
       client-side dispatch problem.
     - The executor reuses existing single-action handlers
       (activateReasoningTab, addReasoningTab, sendVeraWorkModeTypedInferTurn
       with planner bypass). It does NOT re-implement checklist /
       music / news / reasoning routes — each segment goes through the
       existing pipeline so behaviour stays consistent.
     - Per PART 4 ordering rules, target/navigation actions
       (panel.select/open/close, news.open_panel) run before content
       actions (reasoning.generate, news.search), and dependsOn is
       added from the content action to the latest target action.
========================= */

const WORK_MODE_PLANNER_ORDINAL_TO_NUM = {
  first: 1,
  second: 2,
  third: 3,
  fourth: 4,
  fifth: 5,
  sixth: 6,
  seventh: 7,
  eighth: 8,
};

const WORK_MODE_PLANNER_ORDINAL_KEYS = Object.keys(WORK_MODE_PLANNER_ORDINAL_TO_NUM).join("|");

/* Connector regex used to split a compound command into ordered segments.
   Conservative on purpose — bare commas are NOT treated as connectors
   unless a second-segment verb is present (see _wmpSplitOnConnectors). */
const WORK_MODE_PLANNER_CONNECTOR_RE = new RegExp(
  "\\s*\\b(?:and(?:\\s+then)?|then|after(?:\\s+that)?|also|while\\s+you'?re\\s+at\\s+it|plus|next)\\b\\s*",
  "i"
);

const WORK_MODE_PLANNER_CONNECTOR_GLOBAL_RE = new RegExp(
  WORK_MODE_PLANNER_CONNECTOR_RE.source,
  "gi"
);

/* "in panel 2" / "in the reasoning panel 2" / "in the second panel" — the
   implicit target preposition that turns a single segment like
   "explain the Vietnam War in panel 2" into a multi-action plan. */
const WORK_MODE_PLANNER_IN_PANEL_RE = new RegExp(
  "\\bin\\s+(?:the\\s+)?(?:reasoning\\s+)?(?:panel|space|tab|page)\\s*#?\\s*(\\d+|" +
    WORK_MODE_PLANNER_ORDINAL_KEYS +
    ")\\b",
  "i"
);

const WORK_MODE_PLANNER_IN_ORDINAL_PANEL_RE = new RegExp(
  "\\bin\\s+(?:the\\s+)?(" +
    WORK_MODE_PLANNER_ORDINAL_KEYS +
    ")\\s+(?:reasoning\\s+)?(?:panel|space|tab|page)\\b",
  "i"
);

const WORK_MODE_PLANNER_PANEL_NUMBER_RE = new RegExp(
  "\\b(?:reasoning\\s+)?(?:panel|space|tab|page)\\s*#?\\s*(\\d+|" +
    WORK_MODE_PLANNER_ORDINAL_KEYS +
    ")\\b",
  "i"
);

const WORK_MODE_PLANNER_ORDINAL_PANEL_RE = new RegExp(
  "\\b(" +
    WORK_MODE_PLANNER_ORDINAL_KEYS +
    ")\\s+(?:reasoning\\s+)?(?:panel|space|tab|page)\\b",
  "i"
);

function _wmpResolveOrdinalOrNum(token) {
  const s = String(token || "").toLowerCase().trim();
  if (!s) return null;
  if (/^\d+$/.test(s)) return Number(s);
  return WORK_MODE_PLANNER_ORDINAL_TO_NUM[s] || null;
}

/** Returns 1-based panel index parsed from "panel 2" / "second panel" / "panel #3". */
function _wmpExtractPanelTarget(text) {
  const s = String(text || "");
  let m = s.match(WORK_MODE_PLANNER_PANEL_NUMBER_RE);
  if (m) {
    const n = _wmpResolveOrdinalOrNum(m[1]);
    if (n) return n;
  }
  m = s.match(WORK_MODE_PLANNER_ORDINAL_PANEL_RE);
  if (m) {
    const n = _wmpResolveOrdinalOrNum(m[1]);
    if (n) return n;
  }
  return null;
}

/** Remove the trailing "in panel 2" / "in the second panel" phrase so the residual
 *  text becomes a clean content prompt for reasoning.generate. */
function _wmpStripImplicitTargetPhrase(text) {
  return String(text || "")
    .replace(WORK_MODE_PLANNER_IN_PANEL_RE, "")
    .replace(WORK_MODE_PLANNER_IN_ORDINAL_PANEL_RE, "")
    .replace(/\s{2,}/g, " ")
    .replace(/\s+([?.!,;:])/g, "$1")
    .replace(/^[\s'".,;:!?]+|[\s'".,;:!?]+$/g, "")
    .trim();
}

/** Strip leading politeness ("can you", "could you", "would you", "please")
 *  so the verb classifier can see the actual command word. Mirrors the
 *  same pattern app.py uses for its router shortcuts. */
function _wmpStripLeadingPoliteness(text) {
  let s = String(text || "").trim();
  if (!s) return "";
  /* Run twice — handles "please can you" or "would you please". */
  for (let i = 0; i < 2; i++) {
    s = s
      .replace(/^\s*(?:please|kindly)\b[\s,]+/i, "")
      .replace(/^\s*(?:can|could|would|will)\s+you\b[\s,]+/i, "")
      .replace(/^\s*(?:hey\s+vera|hey|ok|okay|alright)\b[\s,]+/i, "");
  }
  return s.trim();
}

/** Classify a single segment into a PlannedAction.type using verb prefixes.
 *  Returns "unknown" / "general.reply" for non-actionable segments so the
 *  caller can decide whether to abort multi-action planning. */
function _wmpDetectActionType(segment) {
  const raw = String(segment || "").trim();
  if (!raw) return "unknown";
  const s = _wmpStripLeadingPoliteness(raw);
  if (!s) return "unknown";
  const t = s.toLowerCase();

  if (
    /^(?:go\s+(?:back\s+)?to|jump\s+to|switch\s+to|change\s+to|show|select|use)\s+(?:the\s+|a\s+|my\s+)?(?:reasoning\s+)?(?:panel|space|tab|page)\b/i.test(s) ||
    /^(?:go\s+(?:back\s+)?to|jump\s+to|switch\s+to|change\s+to|show|select|use)\s+(?:the\s+|a\s+|my\s+)?(?:first|second|third|fourth|fifth|sixth|seventh|eighth)\s+(?:reasoning\s+)?(?:panel|space|tab|page)\b/i.test(s)
  ) {
    return "panel.select";
  }
  if (/^(?:open|create|make|add|new)\s+(?:a\s+)?(?:new\s+)?(?:reasoning\s+)?(?:panel|space|tab|page)\b/i.test(s)) {
    return "panel.open";
  }
  if (
    /^(?:close|hide|dismiss|get\s+rid\s+of)\s+(?:the\s+|a\s+|my\s+|all\s+)?(?:first|second|third|fourth|fifth|sixth|seventh|eighth|current|active|last|this)?\s*(?:reasoning\s+)?(?:panel|space|tab|page)s?\b/i.test(s)
  ) {
    return "panel.close";
  }
  if (/^(?:open|show|bring\s+up|pull\s+up)\s+(?:the\s+)?news\s+(?:panel|tab|page|results)\b/i.test(s)) {
    return "news.open_panel";
  }
  if (/^(?:search|look\s+up|find|google)\s+(?:for\s+)?(?:news\s+(?:about|on|for)\s+)?/i.test(s)) {
    return "news.search";
  }
  if (/^(?:pause|stop|mute)\s+(?:the\s+)?music\b/i.test(s)) {
    return "music.pause";
  }
  if (/^(?:play|resume|start|unpause)\s+(?:the\s+|some\s+)?music\b/i.test(s)) {
    return "music.play";
  }
  if (/^add\s+.+?\s+(?:to\s+(?:the\s+|my\s+)?)?(?:checklist|plan|todo|to-do|to\s+do|list)\b/i.test(s)) {
    return "checklist.add";
  }
  if (/^(?:remove|delete|cross\s+off|check\s+off)\s+/i.test(s) && /\b(?:checklist|plan|todo|to-do|to\s+do|list|item|task|first|second|third|fourth|fifth)\b/i.test(t)) {
    return "checklist.remove";
  }
  if (/^(?:sync|update|push|refresh)\s+(?:the\s+|my\s+)?(?:plan|checklist|reasoning\s+plan)\b/i.test(s)) {
    return "checklist.sync";
  }
  if (/^(?:put|move|drop)\s+(?:that|this|it|the\s+(?:answer|last|latest|previous))\s+(?:in|into|to)\s+/i.test(s)) {
    return "reasoning.move_latest_voice_answer";
  }
  if (
    /^(?:explain|describe|tell\s+me\s+about|summari[sz]e|write|draft|compose|outline|analy[sz]e|compare|derive|prove|walk\s+me\s+through|break\s+down|teach\s+me)\b/i.test(s)
  ) {
    return "reasoning.generate";
  }
  return "general.reply";
}

/** Conservative connector split. Splits on " and "/" then "/etc., but only
 *  when the resulting right-hand side starts with a recognized action verb
 *  — avoids slicing "the cat and the dog" into two segments. */
function _wmpSplitOnConnectors(text) {
  const s = String(text || "").trim();
  if (!s) return [];
  const parts = [];
  let cursor = 0;
  WORK_MODE_PLANNER_CONNECTOR_GLOBAL_RE.lastIndex = 0;
  let match;
  while ((match = WORK_MODE_PLANNER_CONNECTOR_GLOBAL_RE.exec(s)) != null) {
    const before = s.slice(cursor, match.index).trim();
    const after = s.slice(match.index + match[0].length).trim();
    if (!before || !after) continue;
    /* Only treat this connector as a real split if the right-hand side
       starts with a recognizable Work Mode action verb. Otherwise leave
       it joined so phrasings like "the rise and fall of Rome" do not
       fragment unrelated noun phrases. */
    const rhsType = _wmpDetectActionType(after);
    if (rhsType === "unknown") continue;
    parts.push(before);
    cursor = match.index + match[0].length;
  }
  const tail = s.slice(cursor).trim();
  if (tail) parts.push(tail);
  if (!parts.length) return [s];
  return parts.map((p) => p.replace(/^[\s'".,;:!?]+|[\s'".,;:!?]+$/g, "").trim()).filter(Boolean);
}

/** Apply PART 4 ordering rules. Stable: target/navigation actions go first,
 *  then content actions; within each bucket text order is preserved. */
function _wmpOrderActionsByDependency(actions) {
  const TARGET_FIRST = new Set([
    "panel.close",
    "panel.open",
    "panel.select",
    "news.open_panel",
  ]);
  const CONTENT = new Set([
    "reasoning.generate",
    "reasoning.move_latest_voice_answer",
    "news.search",
    "general.reply",
  ]);

  const targets = [];
  const content = [];
  const other = [];
  for (const a of actions) {
    if (TARGET_FIRST.has(a.type)) targets.push(a);
    else if (CONTENT.has(a.type)) content.push(a);
    else other.push(a);
  }

  /* Within target bucket: close before select before open. This handles
     "close panel 1 and open a new one" cleanly. */
  const targetOrder = (t) =>
    t === "panel.close" ? 0 : t === "panel.select" ? 1 : t === "panel.open" ? 2 : 3;
  targets.sort((a, b) => {
    const da = targetOrder(a.type);
    const db = targetOrder(b.type);
    if (da !== db) return da - db;
    return 0; // stable
  });

  const ordered = [...targets, ...content, ...other];

  /* Add dependsOn from content actions to the LAST target action so the
     executor can stop content if navigation fails. Independent app
     actions (checklist+music) get no dependsOn — they execute in
     text order without blocking each other. */
  if (targets.length && content.length) {
    const lastTargetId = targets[targets.length - 1].id;
    for (const c of content) {
      if (!Array.isArray(c.dependsOn)) c.dependsOn = [];
      if (!c.dependsOn.includes(lastTargetId)) c.dependsOn.push(lastTargetId);
    }
  }

  return ordered;
}

/** PART 10: risk classification for an action type. */
function _wmpRiskLevelForType(actionType) {
  if (actionType === "panel.close" || actionType === "checklist.remove") return "medium";
  return "low";
}

/**
 * planUserCommand({ text, context }) — see PART 2/3 of the spec.
 *
 * Returns null when the request is single-action (or empty) so the
 * caller can fall through to the existing single-action router.
 * Returns a plan object otherwise.
 */
function planWorkModeMultiAction(text, context = {}) {
  const raw = String(text || "").trim();
  if (!raw) return null;

  const segments = _wmpSplitOnConnectors(raw);

  /* Build a flat action list from segments. Each segment can produce
     one action, or two when it carries an implicit panel target
     ("explain X in panel 2" -> panel.select + reasoning.generate). */
  const built = [];
  let counter = 1;
  for (const seg of segments) {
    if (!seg) continue;
    const implicitTarget = _wmpExtractPanelTarget(seg);
    const baseType = _wmpDetectActionType(seg);
    if (
      implicitTarget != null &&
      baseType === "reasoning.generate" &&
      /\bin\s+/i.test(seg)
    ) {
      built.push({
        id: `a${counter++}`,
        type: "panel.select",
        target: { panelIndex: implicitTarget },
        segmentText: `go to panel ${implicitTarget}`,
        riskLevel: _wmpRiskLevelForType("panel.select"),
      });
      const promptText = _wmpStripImplicitTargetPhrase(seg) || seg;
      built.push({
        id: `a${counter++}`,
        type: "reasoning.generate",
        payload: { prompt: promptText },
        segmentText: promptText,
        riskLevel: _wmpRiskLevelForType("reasoning.generate"),
      });
    } else {
      built.push({
        id: `a${counter++}`,
        type: baseType,
        target: implicitTarget != null ? { panelIndex: implicitTarget } : undefined,
        segmentText: seg,
        riskLevel: _wmpRiskLevelForType(baseType),
      });
    }
  }

  /* If every segment we built is "general.reply" / "unknown", this is not
     really a multi-action request — bail and let the normal router handle
     the original text as a single intent. */
  const actionable = built.filter(
    (a) => a.type !== "general.reply" && a.type !== "unknown"
  );
  if (actionable.length < 2) return null;

  const ordered = _wmpOrderActionsByDependency(built);

  /* Drop trailing "general.reply" tails — they're typically noise from a
     comma or trailing pleasantry. Keep them if they're the only content. */
  const finalActions = ordered.filter(
    (a) => a.type !== "general.reply" && a.type !== "unknown"
  );
  if (finalActions.length < 2) return null;

  const triggerReason =
    segments.length === 1 ? "implicit_target_panel" : "explicit_connector";

  return {
    isMultiAction: true,
    confidence: triggerReason === "implicit_target_panel" ? 0.9 : 0.85,
    triggerReason,
    executionMode: "sequential",
    actions: finalActions,
    userFacingSummary: null, // executor builds the final confirmation
  };
}

/** Gate per PART 1 — Work Mode only, recursive bypass aware. */
function shouldUseWorkModeMultiActionPlanner(text, opts = {}) {
  if (opts && opts.__skipMultiActionPlanner === true) return false;
  if (typeof isVeraWorkModeOn !== "function" || !isVeraWorkModeOn()) return false;
  if (typeof appModePrefix !== "function" || appModePrefix() !== "vera") return false;
  /* Future extension: when called from normal-mode chat with explicit
     Work Mode references (PART 11), we'd return true and surface a
     prompt to enable Work Mode. Out of scope for this pass. */
  return true;
}

/** Structured log helper. Stable schema for grep + future analyzers. */
function logWorkModeMultiActionPlannerDecision(payload) {
  try {
    console.info("[wm_multi_action_planner]", {
      tag: payload?.tag || "plan_decision",
      ts: new Date().toISOString(),
      ...payload,
    });
  } catch (_) {}
}

async function maybeRunWorkModeMultiActionPlanner(text, opts = {}) {
  const trimmed = String(text || "").trim();
  if (!shouldUseWorkModeMultiActionPlanner(trimmed, opts)) return false;

  const path = opts.path || opts.source || "work-mode";
  let plan = null;
  try {
    plan = planWorkModeMultiAction(trimmed, { source: path, isVoice: Boolean(opts.isVoice) });
  } catch (e) {
    try {
      console.warn("[wm_multi_action_planner]", {
        tag: "planner_exception",
        error: String(e?.message || e || "").slice(0, 200),
        text_preview: String(trimmed || "").slice(0, 120),
        path,
        is_voice: Boolean(opts.isVoice),
      });
    } catch (_) {}
    plan = null;
  }

  logWorkModeMultiActionPlannerDecision({
    tag: "plan_decision",
    latest_user_text: String(trimmed || "").slice(0, 200),
    work_mode_active: true,
    work_mode_multi_action_planner_allowed: true,
    work_mode_scope_reason: "active_work_mode",
    multi_action_candidate: Boolean(plan && plan.isMultiAction),
    planner_used: Boolean(plan && Array.isArray(plan.actions) && plan.actions.length > 1),
    planner_confidence: plan?.confidence ?? null,
    actions_detected: Array.isArray(plan?.actions) ? plan.actions.map((a) => a.type) : [],
    action_order: Array.isArray(plan?.actions) ? plan.actions.map((a) => a.type) : [],
    dependency_edges: Array.isArray(plan?.actions)
      ? plan.actions.flatMap((a) =>
          Array.isArray(a.dependsOn) ? a.dependsOn.map((d) => [d, a.id]) : []
        )
      : [],
    single_router_bypassed: Boolean(
      plan && Array.isArray(plan.actions) && plan.actions.length > 1
    ),
    trigger_reason: plan?.triggerReason || null,
    path,
    is_voice: Boolean(opts.isVoice),
  });

  if (!plan || !Array.isArray(plan.actions) || plan.actions.length <= 1) return false;

  /* Preserve the original full-command bubble BEFORE the executor runs.
   * For voice turns, `finalizeMainBrowserTranscript` (and friends) have
   * already mounted a live partial bubble showing the full original text.
   * We tag that row if it still matches; otherwise create a fresh bubble.
   * The hold flag prevents each sub-action's cleaned segment text from
   * overwriting the bubble via `commitServerUserTranscriptBubble`. */
  const originalFullUserText = trimmed;
  const cleanedExecutionTexts = _wmCleanedExecutionTextsFromPlan(plan);
  let bubbleAlreadyMatched = false;
  try {
    const latestBubbleText = _readLatestUserBubbleText();
    if (
      latestBubbleText
      && _wmNormalizeForSegmentMatch(latestBubbleText) === _wmNormalizeForSegmentMatch(originalFullUserText)
    ) {
      bubbleAlreadyMatched = true;
      try {
        const conv = document.getElementById("conversation")
          || document.getElementById("bmo-conversation");
        const rows = conv?.querySelectorAll(".message-row.user");
        if (rows && rows.length) {
          const row = rows[rows.length - 1];
          if (row instanceof HTMLElement) {
            row.dataset.veraWorkModePreservedOriginal = "1";
            const b = row.querySelector(".bubble");
            if (b instanceof HTMLElement) {
              try { b.dataset.originalFullUserText = originalFullUserText; } catch (_) {}
            }
          }
        }
      } catch (_) {}
    }
  } catch (_) {}
  if (!bubbleAlreadyMatched) {
    try {
      ensureChatStartedLayout();
      const b = addBubble(originalFullUserText, "user", {
        path: `wm-multi-action-original-${opts.isVoice ? "voice" : "typed"}`,
      });
      if (b) {
        const row = b.closest(".message-row");
        if (row instanceof HTMLElement) row.dataset.veraWorkModePreservedOriginal = "1";
        try { b.dataset.originalFullUserText = originalFullUserText; } catch (_) {}
      }
    } catch (_) {}
  }
  _wmMarkOriginalUserBubbleRendered(
    originalFullUserText,
    cleanedExecutionTexts,
    `wm-multi-action-pre-execute:${opts.isVoice ? "voice" : "typed"}`
  );

  try {
    logWorkModeCommandDisplayText({
      originalFullUserText,
      cleanedExecutionText: cleanedExecutionTexts.join(" | ") || null,
      renderedUserBubbleText: _readLatestUserBubbleText(),
      duplicateUserBubbleSuppressed: false,
      usedCleanedTextAsInternalPromptOnly: true,
      commandLooksMultiAction: true,
      source: `wm-multi-action-pre-execute:${opts.isVoice ? "voice" : "typed"}`,
    });
  } catch (_) {}

  _wmHoldOriginalUserBubble(originalFullUserText);
  try {
    await executeWorkModeActionPlan(plan, { source: path, isVoice: Boolean(opts.isVoice) });
    return true;
  } catch (e) {
    console.warn("[wm_multi_action_planner]", {
      tag: "execution_exception",
      error: String(e?.message || e || "").slice(0, 200),
      path,
      is_voice: Boolean(opts.isVoice),
    });
    return true;
  } finally {
    _wmReleaseOriginalUserBubbleHold();
  }
}

/**
 * executeActionPlan(plan, context) — see PART 7.
 *
 * Runs actions sequentially. For panel.select / panel.open we call
 * existing in-process handlers directly (no bubble). For every other
 * action type we re-enter sendVeraWorkModeTypedInferTurn with
 * __skipMultiActionPlanner so the existing shortcuts and /infer route
 * handle the segment exactly the way they would for a single command.
 */
async function executeWorkModeActionPlan(plan, context = {}) {
  if (!plan || !Array.isArray(plan.actions) || plan.actions.length < 1) {
    return { ok: false, results: [], reason: "empty_plan" };
  }

  logWorkModeMultiActionPlannerDecision({
    tag: "execution_started",
    action_count: plan.actions.length,
    actions: plan.actions.map((a) => a.type),
    trigger_reason: plan.triggerReason || null,
    confidence: plan.confidence ?? null,
  });

  const results = [];
  const lookupResult = (id) => results.find((r) => r.id === id);

  for (const action of plan.actions) {
    /* Dependency check (PART 4 F + PART 7). */
    if (Array.isArray(action.dependsOn) && action.dependsOn.length) {
      const failedDep = action.dependsOn.find((depId) => {
        const dep = lookupResult(depId);
        return dep && dep.ok === false;
      });
      if (failedDep) {
        const skipResult = {
          id: action.id,
          type: action.type,
          ok: false,
          skipped_due_to_dependency: true,
          error: `dep_failed:${failedDep}`,
        };
        results.push(skipResult);
        logWorkModeMultiActionPlannerDecision({
          tag: "action_result",
          action_id: action.id,
          action_type: action.type,
          ok: false,
          skipped_due_to_dependency: true,
          dep_failed: failedDep,
        });
        continue;
      }
    }

    let ok = false;
    let error = null;
    const extra = {};

    try {
      switch (action.type) {
        case "panel.select": {
          const oneBased = Number(action?.target?.panelIndex);
          if (!Number.isFinite(oneBased) || oneBased < 1) {
            error = "invalid_panel_index";
            break;
          }
          const idx = oneBased - 1;
          const panelEl = document.querySelector(
            `#vera-reasoning-tab-panels .vera-reasoning-tab-panel[data-tab-index="${idx}"]`
          );
          if (!panelEl) {
            error = "panel_not_found_or_closed";
            break;
          }
          if (typeof activateReasoningTab !== "function") {
            error = "activateReasoningTab_unavailable";
            break;
          }
          activateReasoningTab(idx, {
            commandText: action.segmentText || "",
            requestedIndex: oneBased,
            resolvedFrom: "wm_multi_action_planner",
          });
          extra.target_panel_id =
            panelEl.dataset.laneId || `panel_${oneBased}`;
          extra.reasoning_generation_started = false;
          ok = true;
          break;
        }

        case "panel.open": {
          if (typeof addReasoningTab !== "function") {
            error = "addReasoningTab_unavailable";
            break;
          }
          /* PART 5+6 (2026-05-28): pass the voice/typed source so the
             new panel is tracked as "recently opened" and any next
             reasoning request biases to it. */
          addReasoningTab({ source: "multi_action_planner_open_command" });
          ok = true;
          break;
        }

        case "reasoning.generate": {
          /* Reasoning generation MUST go through the normal Work Mode
             infer pipeline so the active panel context (just selected
             by an earlier action.select) is honored. */
          const promptText =
            String(action?.payload?.prompt || action.segmentText || "").trim();
          if (!promptText) {
            error = "empty_reasoning_prompt";
            break;
          }
          try {
            await sendVeraWorkModeTypedInferTurn(promptText, {
              path: `wm-multi-action:reasoning.generate`,
              __skipMultiActionPlanner: true,
            });
            extra.dispatched_via = "sendVeraWorkModeTypedInferTurn";
            extra.reasoning_generation_started = true;
            ok = true;
          } catch (e) {
            error = String(e?.message || e || "dispatch_error").slice(0, 200);
          }
          break;
        }

        case "panel.close":
        case "checklist.add":
        case "checklist.remove":
        case "checklist.sync":
        case "music.pause":
        case "music.play":
        case "news.open_panel":
        case "news.search":
        case "reasoning.move_latest_voice_answer":
        default: {
          /* All remaining action types are forwarded through the normal
             Work Mode entry. Each will hit its corresponding existing
             frontend shortcut (close panel, sync plan, move-latest)
             or fall through to backend /infer (checklist mutations,
             music control, news ops). The planner bypass flag prevents
             re-entry. */
          try {
            await sendVeraWorkModeTypedInferTurn(action.segmentText || "", {
              path: `wm-multi-action:${action.type}`,
              __skipMultiActionPlanner: true,
            });
            extra.dispatched_via = "sendVeraWorkModeTypedInferTurn";
            ok = true;
          } catch (e) {
            error = String(e?.message || e || "dispatch_error").slice(0, 200);
          }
          break;
        }
      }
    } catch (e) {
      error = String(e?.message || e || "executor_exception").slice(0, 200);
    }

    const result = { id: action.id, type: action.type, ok, error, ...extra };
    results.push(result);
    logWorkModeMultiActionPlannerDecision({
      tag: "action_result",
      action_id: action.id,
      action_type: action.type,
      ok,
      error,
      ...extra,
    });
  }

  logWorkModeMultiActionPlannerDecision({
    tag: "execution_complete",
    results_summary: results.map((r) => ({
      id: r.id,
      type: r.type,
      ok: r.ok,
      skipped: Boolean(r.skipped_due_to_dependency),
    })),
  });

  return { ok: results.every((r) => r.ok), results };
}

/* =========================
   TEXT INPUT PIPELINE
========================= */

/**
 * Work mode: typed lines use the same `/infer` path as browser-ASR voice (including optional
 * reasoning-stream prep via maybePrepareWorkModeReasoning), not the separate `/text` handler.
 */
async function sendVeraWorkModeTypedInferTurn(text, opts = {}) {
  const rawText = String(text ?? "");
  const trimmed = rawText.trim();
  const path = opts.path || "work-typed";
  const fromQueue = Boolean(opts.__fromQueue);
  const fromPanelQueue = Boolean(opts.__fromReasoningPanelQueue);
  const queuedFiles =
    Array.isArray(opts.reasoningAttachments) && opts.reasoningAttachments.length
      ? opts.reasoningAttachments.filter((f) => f instanceof File && f.size)
      : [];
  const pendingFiles =
    fromQueue || fromPanelQueue ? queuedFiles : getWorkModePendingAttachmentFiles();
  if ((!trimmed && !pendingFiles.length) || !isVeraWorkModeOn() || appModePrefix() !== "vera") return;

  const modeBeforeSubmit = appModePrefix();
  const workModeBeforeSubmit = isVeraWorkModeOn();
  const hardWorkLimit = VERA_SAFETY_LIMITS.charLimits.workReasoning;
  if (!fromQueue && !fromPanelQueue && rawText.length > hardWorkLimit) {
    logInputLimitDebug({
      raw_char_count: rawText.length,
      estimated_tokens: Math.ceil(rawText.length / 4),
      input_surface: path || "work-typed",
      active_mode_before_submit: modeBeforeSubmit,
      work_mode_enabled_before_submit: workModeBeforeSubmit,
      selected_limit: hardWorkLimit,
      blocked: true,
      block_reason: "work_mode_typed_char_limit",
      route_attempted: false,
      backend_call_attempted: false,
      reasoning_panel_started: false,
      work_mode_enabled_after_submit: isVeraWorkModeOn(),
      did_toggle_work_mode: workModeBeforeSubmit !== isVeraWorkModeOn(),
      function_that_changed_work_mode: ""
    });
    veraShowSafetyFailureBubble(VERA_SAFETY_LIMITS.messages.inputTooLongKeyboard);
    veraSetSafetyStatus("Message too long — shorten or upload as a file");
    preserveComposerAttachments("typed_length_cap_reached", null);
    return;
  }

  const statusLine = uiEl("status");
  if (statusLine?.classList.contains("offline")) {
    requestInFlight = false;
    processing = false;
    listening = false;
    setStatus("Ready", "idle");
  }

  /* Local UI actions must be claimed before the Work Mode multi-action
     planner, reasoning classifier, or /infer fallback. A bare "close panel"
     is not a reasoning request; if we let it fall through, the user can see
     the generic "Reasoning is temporarily unavailable" bubble. */
  if (!fromQueue && !fromPanelQueue &&
      maybeHandleCloseReasoningPanelShortcut(trimmed, {
        reason: path || "work-typed-preflight",
        isVoice: Boolean(opts?.isVoice)
      })) {
    return;
  }

  /* =========================
     WORK MODE MULTI-ACTION PLANNER GATE (legacy frontend planner)
     ----------------------------------------------------------------------
     2026-05-29 structural route fix:
     typed Work Mode commands now defer compound app-action planning to
     the backend /infer planner. The older frontend planner is intentionally
     bypassed here because it can partially recognize app actions (for
     example checklist.remove) while missing arbitrary music.play payloads,
     which prevents the backend from returning one aggregated multi_action
     response. Recursive segment dispatches still pass
     __skipMultiActionPlanner and fall through to the normal single-action
     pipeline below.
  ========================= */
  const deferTypedCompoundPlanningToBackend =
    !(opts && opts.__skipMultiActionPlanner === true);
  if (deferTypedCompoundPlanningToBackend) {
    logWorkModeMultiActionPlannerDecision({
      tag: "frontend_planner_deferred_to_backend",
      latest_user_text: String(trimmed || "").slice(0, 200),
      work_mode_active:
        typeof isVeraWorkModeOn === "function" ? isVeraWorkModeOn() : null,
      work_mode_multi_action_planner_allowed: false,
      work_mode_scope_reason: "typed_backend_planner_source_of_truth",
      planner_used: false,
      backend_input_source: "keyboard",
      backend_typed: true,
      path: path || null,
    });
  } else if (shouldUseWorkModeMultiActionPlanner(trimmed, opts)) {
    let plan = null;
    try {
      plan = planWorkModeMultiAction(trimmed, { source: path });
    } catch (e) {
      try {
        console.warn("[wm_multi_action_planner]", {
          tag: "planner_exception",
          error: String(e?.message || e || "").slice(0, 200),
          text_preview: String(trimmed || "").slice(0, 120),
        });
      } catch (_) {}
      plan = null;
    }

    logWorkModeMultiActionPlannerDecision({
      tag: "plan_decision",
      latest_user_text: String(trimmed || "").slice(0, 200),
      work_mode_active: true,
      work_mode_multi_action_planner_allowed: true,
      work_mode_scope_reason: "active_work_mode",
      multi_action_candidate: Boolean(plan && plan.isMultiAction),
      planner_used: Boolean(plan && Array.isArray(plan.actions) && plan.actions.length > 1),
      planner_confidence: plan?.confidence ?? null,
      actions_detected: Array.isArray(plan?.actions) ? plan.actions.map((a) => a.type) : [],
      action_order: Array.isArray(plan?.actions) ? plan.actions.map((a) => a.type) : [],
      dependency_edges: Array.isArray(plan?.actions)
        ? plan.actions.flatMap((a) =>
            Array.isArray(a.dependsOn) ? a.dependsOn.map((d) => [d, a.id]) : []
          )
        : [],
      single_router_bypassed: Boolean(
        plan && Array.isArray(plan.actions) && plan.actions.length > 1
      ),
      trigger_reason: plan?.triggerReason || null,
      path: path || null,
    });

    if (plan && Array.isArray(plan.actions) && plan.actions.length > 1) {
      /* Preserve the original full-command bubble BEFORE the executor runs.
       * For typed Work Mode turns, the bubble normally appears only after
       * the server NDJSON echoes a transcript — pre-create one here showing
       * the FULL ORIGINAL text. The hold flag prevents each sub-action's
       * cleaned segment text from overwriting it. */
      const originalFullUserText = trimmed;
      const cleanedExecutionTexts = _wmCleanedExecutionTextsFromPlan(plan);
      let originalBubble = null;
      try {
        ensureChatStartedLayout();
        originalBubble = addBubble(originalFullUserText, "user", {
          path: "wm-multi-action-original-typed",
        });
        if (originalBubble) {
          const row = originalBubble.closest(".message-row");
          if (row instanceof HTMLElement) {
            row.dataset.veraWorkModePreservedOriginal = "1";
          }
          try { originalBubble.dataset.originalFullUserText = originalFullUserText; } catch (_) {}
        }
      } catch (_) {}
      _wmMarkOriginalUserBubbleRendered(
        originalFullUserText,
        cleanedExecutionTexts,
        "wm-multi-action-pre-execute-typed"
      );

      try {
        logWorkModeCommandDisplayText({
          originalFullUserText,
          cleanedExecutionText: cleanedExecutionTexts.join(" | ") || null,
          renderedUserBubbleText: originalBubble?.textContent ?? _readLatestUserBubbleText(),
          duplicateUserBubbleSuppressed: false,
          usedCleanedTextAsInternalPromptOnly: true,
          commandLooksMultiAction: true,
          source: "wm-multi-action-pre-execute-typed",
        });
      } catch (_) {}

      _wmHoldOriginalUserBubble(originalFullUserText);
      try {
        await executeWorkModeActionPlan(plan, { source: path });
      } catch (e) {
        logWorkModeMultiActionPlannerDecision({
          tag: "executor_exception",
          error: String(e?.message || e || "").slice(0, 200),
        });
      } finally {
        _wmReleaseOriginalUserBubbleHold();
      }
      return;
    }
  } else {
    logWorkModeMultiActionPlannerDecision({
      tag: "plan_decision",
      latest_user_text: String(trimmed || "").slice(0, 200),
      work_mode_active:
        typeof isVeraWorkModeOn === "function" ? isVeraWorkModeOn() : null,
      work_mode_multi_action_planner_allowed: false,
      work_mode_scope_reason: opts && opts.__skipMultiActionPlanner
        ? "planner_bypass_recursive"
        : "not_allowed_normal_mode",
      planner_used: false,
      path: path || null,
    });
  }

  if (
    await maybeHandleWorkChecklistSyncShortcut(trimmed, {
      source: path || "work-typed",
      isVoice: false
    })
  ) {
    return;
  }
  if (await maybeHandleWorkChecklistPlanShortcut(trimmed)) {
    return;
  }
  if (maybeHandleCloseReasoningPanelShortcut(trimmed, { reason: path || "work-typed", isVoice: false })) {
    return;
  }
  if (
    await maybeHandleMoveLatestVoiceTaskToReasoning(trimmed, {
      path: path || "work-typed-move-voice-task",
      isVoice: false
    })
  ) {
    return;
  }

  /* If the user typed a follow-up while the panel they are looking at is
     still generating, queue it visibly inside that panel instead of racing
     for the next idle panel. The user keeps full control: they can edit or
     delete the queued item before it runs, and once the panel finishes,
     `releaseWorkModeReasoningLane` triggers the drain via
     `scheduleReasoningPanelFollowUpQueueDrain`. */
  if (!fromQueue && !fromPanelQueue && trimmed) {
    const activeIdx = getActiveReasoningLaneIndex();
    if (
      activeIdx != null &&
      Number.isFinite(Number(activeIdx)) &&
      workModeReasoningLaneBusy.get(Number(activeIdx)) === true &&
      shouldQueueFollowUpForBusyReasoningPanel(trimmed)
    ) {
      const queued = enqueueReasoningPanelFollowUp(Number(activeIdx), trimmed, {
        ...opts,
        path,
        reasoningAttachments: pendingFiles
      });
      if (queued) {
        clearComposerAttachmentsAfterSubmit(null, "reasoning_panel_followup_queue");
        const panelEl = getReasoningPanelElementByLaneIdx(Number(activeIdx));
        const labelForStatus =
          (panelEl instanceof HTMLElement && getReasoningTabTopicLabel(panelEl)) ||
          getWorkModeReasoningLaneLabel(Number(activeIdx)) ||
          `panel ${Number(activeIdx) + 1}`;
        setStatus(`Queued for ${labelForStatus}`, "idle");
        return;
      }
    }
  }

  /* Safety length cap (defense in depth for any caller that bypasses the
     UI-side guard). Use the reasoning limit when the path indicates the
     prompt is heading into a reasoning panel, otherwise the chat limit. */
  if (!fromQueue && !fromPanelQueue && trimmed) {
    const intent = "work_reasoning";
    const lenBlock = veraCheckTypedInputLength(trimmed, intent, "keyboard");
    if (lenBlock) {
      logInputLimitDebug({
        raw_char_count: rawText.length,
        estimated_tokens: lenBlock.estimated_tokens,
        input_surface: path || "work-typed",
        active_mode_before_submit: modeBeforeSubmit,
        work_mode_enabled_before_submit: workModeBeforeSubmit,
        selected_limit: lenBlock.char_limit,
        blocked: true,
        block_reason: lenBlock.reason,
        route_attempted: false,
        backend_call_attempted: false,
        reasoning_panel_started: false,
        work_mode_enabled_after_submit: isVeraWorkModeOn(),
        did_toggle_work_mode: workModeBeforeSubmit !== isVeraWorkModeOn(),
        function_that_changed_work_mode: ""
      });
      veraShowSafetyFailureBubble(lenBlock.message);
      veraSetSafetyStatus("Message too long — shorten or upload as a file");
      preserveComposerAttachments("typed_length_cap_reached", null);
      try {
        console.info("[reasoning_queue_omitted]", {
          turn_id: null,
          lane_id: null,
          reason: "typed_length_cap_reached",
          char_count: trimmed.length,
          char_limit: lenBlock.char_limit,
          intent
        });
      } catch (_) {}
      return;
    }
  }

  /* Hard cap: at most WORK_MODE_TYPED_PENDING_MAX typed turns in flight or queued.
     Matches the non-work-mode "3 user turns before VERA replies" guard. Refuse
     instead of queueing the 4th so the user gets the same clear feedback. */
  if (!fromQueue && isWorkModeTypedTurnAtHardCap()) {
    setStatus("Wait for VERA response before sending more", "idle");
    preserveComposerAttachments("typed_hard_cap_reached", null);
    try {
      console.warn("[WorkMode] typed hard cap reached — refusing input", {
        pending: countPendingWorkModeTypedTurns(),
        max: WORK_MODE_TYPED_PENDING_MAX,
        depth: workModeTypedVoiceInferDepth,
        queued: workModeTypedTurnQueue.length
      });
      console.info("[reasoning_queue_omitted]", {
        turn_id: null,
        lane_id: null,
        reason: "typed_hard_cap_reached"
      });
    } catch (_) {}
    return;
  }

  if (isWorkModeTypedTurnBlocked()) {
    if (!fromQueue) {
      const queueSnap = getWorkModePendingAttachmentFiles();
      logComposerAttachmentsBeforeSubmit(queueSnap, null);
      const queued = enqueueWorkModeTypedTurn(trimmed, {
        ...opts,
        path,
        reasoningAttachments: queueSnap
      });
      if (queued) {
        clearComposerAttachmentsAfterSubmit(null, "typed_turn_queue_enqueue");
      } else {
        setStatus(`Work queue full (max ${WORK_MODE_TYPED_TURN_QUEUE_MAX})`, "idle");
        preserveComposerAttachments("typed_turn_queue_full", null);
        try {
          console.info("[reasoning_queue_omitted]", {
            turn_id: null,
            lane_id: null,
            reason: "typed_turn_queue_full_while_voice_infer_busy"
          });
        } catch (_) {}
      }
    }
    return;
  }

  /* User bubble: do not addBubble here — /infer NDJSON first `asr` line calls commitServerUserTranscriptBubble
     (same as voice). A prior addBubble would duplicate the row in Voice UI. */
  ensureChatStartedLayout();
  // Arm pending news bubble BEFORE POST /infer so the placeholder appears
  // during the thinking/searching window, not right before the final answer.
  // Idempotent — duplicate calls for the same transcript are no-ops.
  armPendingNewsStatusBubble(trimmed);

  const transcriptLine =
    trimmed || (pendingFiles.length ? "[Uploaded attachment(s)] — see attached file(s)." : "");
  const formData = new FormData();
  formData.append("transcript", transcriptLine);
  formData.append("use_browser_asr", "1");
  formData.append("session_id", getSessionId());
  formData.append("client", appModePrefix());
  formData.append("context_snapshot", JSON.stringify(buildClientContextSnapshot()));
  formData.append("stream_tts", shouldStreamTts() ? "1" : "0");
  for (const f of pendingFiles) {
    const forInfer = f.slice(0, f.size, f.type || undefined);
    formData.append("context_files", forInfer, f.name || "upload");
  }
  if (listeningMode === "ptt") {
    formData.append("mode", "ptt");
  }

  const hasUpload = pendingFiles.length > 0;
  const turnContext = createWorkModeFrozenTurnContext({
    userText: trimmed || transcriptLine,
    source: workModeInferTurnSourceFromPath(path, hasUpload),
    hasFiles: hasUpload
  });
  // 2026-05-29 — multi-action planner gate (typed-only).
  // The Voice UI input box submits via /infer, so the backend's planner
  // execution gate needs an explicit signal that this turn was typed.
  // workModeInferTurnSourceFromPath() already classifies path strings
  // containing "browser-asr" / "voice" / "ptt" / "asr" as "voice", so
  // keyboard submits naturally fall through as "keyboard". When the
  // user actually uploads a file, source="upload" — we still report
  // input_source=keyboard so the planner can run on the typed prompt
  // accompanying the upload.
  const _veraInputSource = (turnContext && turnContext.source) === "voice" ? "voice" : "keyboard";
  formData.append("input_source", _veraInputSource);
  formData.append("typed", _veraInputSource === "keyboard" ? "1" : "0");
  appendWorkModeSubmissionLaneToFormData(formData, turnContext?.turn_lane_id);

  logFinalTranscriptSentToLlm(path, trimmed || transcriptLine);
  /* Stage 1 stabilization: emit before /infer so we can verify the work-mode
     typed payload matches what the user typed AND the bubble (the bubble is
     created later by commitServerUserTranscriptBubble — DOM may be null
     here, which the helper records). request_id will be filled by
     runInferMainPipeline; correlate by turn_id + the next [REQ start]. */
  logTurnTextIntegrity({
    source: "typed",
    raw_asr_text: null,
    normalized_text: rawText,
    router_input_text: trimmed,
    backend_payload_text: transcriptLine,
    request_id: null,
    path: path || "work-typed",
  });
  logComposerAttachmentsBeforeSubmit(pendingFiles, turnContext);

  try {
    if (hasUpload) {
      console.info("[attachment_turn_submit]", {
        turn_id: turnContext?.turn_id ?? null,
        lane_id: turnContext?.turn_lane_id ?? null,
        text_len: trimmed.length,
        file_count: pendingFiles.length,
        file_names: pendingFiles.map((f) => f.name || "file"),
        path,
        from_queue: fromQueue
      });
    }
  } catch (_) {}

  /* Reasoning: parallel across panels (lane chains); voice `/infer`: one chain, does not wait on other lanes' reasoning. */
  const reasoningPrepP = maybePrepareWorkModeReasoning(formData, trimmed || transcriptLine, undefined, {
    attachments: pendingFiles,
    turnContext
  });

  const enqueued = enqueueWorkModeTypedVoiceInfer(async () => {
    try {
      listening = false;
      waveState = "idle";
      processing = true;
      requestInFlight = true;
      setStatus("Thinking", "thinking");
      beginVoiceUxTurn();

      const inferSig = attachPipelineAbortSignal();
      const runPlayback = async () => {
        bumpWorkModeVoiceInferTurnSeq();
        const ttsTurn = workModeTtsMetaFromTurnContext(turnContext);
        const prepWrap = attachWorkModeTtsTurnAfterPrep(await reasoningPrepP, ttsTurn, trimmed);
        if (prepWrap?.inferThreadAnchor) formData.append("thread_follow_up_anchor", prepWrap.inferThreadAnchor);
        if (prepWrap?.voiceTwoStage?.reasoningRouted) {
          const stage1P = maybePlayWorkModeReasoningStage1FromPrep(prepWrap, inferSig, trimmed);
          await Promise.resolve(stage1P).catch(() => {});
          const seqAtStage1End = workModeVoiceInferTurnSeq;
          scheduleWorkModeDeferredReasoningStageTwoInfer({
            formData,
            prep: prepWrap,
            seqAtStage1End
          });
          resumeAfterAssistantReplyPlayback();
          return;
        }
        const prepFail = await runInferAfterWorkModeReasoningPrep(formData, prepWrap, { signal: inferSig });
        if (prepFail === "reasoning-upload-failed") {
          processing = false;
          requestInFlight = false;
          voiceUxTurn = null;
          setStatus("Ready", "idle");
          return;
        }
      };
      if (isVeraWorkModeOn()) {
        await enqueueWorkModeVoiceInferPlaybackTurn(runPlayback);
      } else {
        await runPlayback();
      }
    } catch (err) {
      if (err?.name === "AbortError") {
        processing = false;
        requestInFlight = false;
        voiceUxTurn = null;
        return;
      }
      console.warn("[WorkMode] typed infer", err);
      hideSidePanel();
      processing = false;
      requestInFlight = false;
      voiceUxTurn = null;
      setStatus("Server error", "offline");
      void veraSurfaceLlmFetchFailure({
        feature: "infer_workmode_typed",
        error: err
      });
    }
  });

  if (!enqueued) {
    if (!fromQueue) {
      const reQ = enqueueWorkModeTypedTurn(trimmed, {
        ...opts,
        path,
        reasoningAttachments: pendingFiles
      });
      if (!reQ) {
        try {
          console.info("[reasoning_queue_omitted]", {
            turn_id: turnContext?.turn_id ?? null,
            lane_id: turnContext?.turn_lane_id ?? null,
            reason: "typed_queue_full_after_voice_infer_full",
            file_count: pendingFiles.length
          });
        } catch (_) {}
      }
    }
    if (!fromQueue) {
      setStatus(`Voice queue full (max ${WORK_MODE_TYPED_VOICE_CHAIN_MAX}) — try again shortly`, "idle");
    }
  }
}

async function sendTextMessage() {
  const textInput = uiEl("text-input");
  const statusLine = uiEl("status");
  const rawText = textInput?.value ?? "";
  const text = rawText.trim();
  const inVeraWorkMode = isVeraWorkModeOn() && appModePrefix() === "vera";

  // 🔑 recover from offline
  if (statusLine?.classList.contains("offline")) {
    requestInFlight = false;
    processing = false;
    listening = false;
    setStatus("Ready", "idle");
  }

  if (!text) return;
  if (inVeraWorkMode) {
    if (
      await maybeHandleWorkChecklistSyncShortcut(text, {
        source: "main-work-text-input",
        isVoice: false
      })
    ) {
      if (textInput) textInput.value = "";
      setStatus("Ready", "idle");
      updateMuteInputButton();
      return;
    }
    if (maybeHandleCloseReasoningPanelShortcut(text, { reason: "main-work-text-input", isVoice: false })) {
      if (textInput) textInput.value = "";
      setStatus("Ready", "idle");
      updateMuteInputButton();
      return;
    }
    /* Safety: length cap BEFORE any state mutation so the user can edit + retry. */
    const modeBeforeSubmit = appModePrefix();
    const workModeBeforeSubmit = isVeraWorkModeOn();
    const lenBlock = veraCheckTypedInputLength(rawText, "work_reasoning", "keyboard");
    if (lenBlock) {
      logInputLimitDebug({
        raw_char_count: rawText.length,
        estimated_tokens: lenBlock.estimated_tokens,
        input_surface: "main_work_mode_text_input",
        active_mode_before_submit: modeBeforeSubmit,
        work_mode_enabled_before_submit: workModeBeforeSubmit,
        selected_limit: lenBlock.char_limit,
        blocked: true,
        block_reason: lenBlock.reason,
        route_attempted: false,
        backend_call_attempted: false,
        reasoning_panel_started: false,
        work_mode_enabled_after_submit: isVeraWorkModeOn(),
        did_toggle_work_mode: workModeBeforeSubmit !== isVeraWorkModeOn(),
        function_that_changed_work_mode: ""
      });
      veraShowSafetyFailureBubble(lenBlock.message);
      veraSetSafetyStatus("Message too long — shorten or upload as a file");
      return;
    }
    if (isWorkModeTypedTurnAtHardCap()) {
      setStatus("Wait for VERA response before sending more", "idle");
      try {
        console.warn("[WorkMode] keyboard blocked at hard cap (typed-text)", {
          pending: countPendingWorkModeTypedTurns(),
          max: WORK_MODE_TYPED_PENDING_MAX
        });
      } catch (_) {}
      return;
    }
    if (textInput) textInput.value = "";
    await sendVeraWorkModeTypedInferTurn(text, { path: "typed-text" });
    return;
  }
  /* Non-work-mode keyboard: chat length cap. Bubble shows the same copy as
     the backend 413 so the UX is identical for FE-block vs BE-block. */
  const lenBlockChat = veraCheckTypedInputLength(text, "normal_chat", "keyboard");
  if (lenBlockChat) {
    veraShowSafetyFailureBubble(lenBlockChat.message);
    veraSetSafetyStatus("Message too long — shorten or upload as a file");
    return;
  }
  const consecutiveUserTail = (() => {
    const convo = uiEl("conversation");
    if (!convo) return 0;
    const rows = [...convo.querySelectorAll(".message-row")];
    let count = 0;
    for (let i = rows.length - 1; i >= 0; i -= 1) {
      const row = rows[i];
      if (!(row instanceof HTMLElement)) continue;
      const bubble = row.querySelector(".bubble");
      if (bubble instanceof HTMLElement && bubble.classList.contains("interrupt-preview")) continue;
      if (row.classList.contains("user")) {
        count += 1;
        continue;
      }
      break;
    }
    return count;
  })();
  if (consecutiveUserTail >= 3) {
    setStatus("Wait for VERA response before sending more", "idle");
    console.warn("[Keyboard] blocked after 3 pending user turns");
    return;
  }
  if (isServerPipelineBusy() && isFlowModeKeyboardInterruptAllowed()) {
    interruptAssistantPipelineForTypedMessage();
  }

  if (isServerPipelineBusy()) return;
  if (textInput) textInput.value = "";

  beginTextUxTurn();
  listening = false;
  processing = true;
  requestInFlight = true;
  waveState = "idle";

  setStatus("Thinking", "thinking");

  addBubble(text, "user", { path: "typed-text" });
  ensureChatStartedLayout();
  // PART 14 (2026-05-28): emit the structured frontend route log on every
  // typed turn so the browser console shows our route classification side
  // by side with the backend's matching [news_router_route] line. Pure
  // instrumentation; backend remains the authoritative router.
  try {
    if (typeof classifyVeraTurnRoute === "function" && typeof logNewsRouterRouteFrontend === "function") {
      const _veraTurnRouteClassification = classifyVeraTurnRoute(text);
      logNewsRouterRouteFrontend(text, _veraTurnRouteClassification);
    }
  } catch (_) {}
  // 2026-05-28 PART 1 — emit the info-tool router classification too. The
  // backend is the authoritative router; this is purely instrumentation so
  // the browser console shows our intended dispatch side by side with the
  // backend's matching [info_tool_route] line.
  try {
    if (typeof classifyInfoTool === "function" && typeof logInfoToolRouteFrontend === "function") {
      const _infoToolClassification = classifyInfoTool(text);
      logInfoToolRouteFrontend(text, _infoToolClassification);
    }
  } catch (_) {}
  // Show "Searching news…" immediately for likely Serper-backed requests.
  // Cancelled when a real reply arrives via applyAssistantReplyAndPanels /
  // applyNdjsonStreamingReplySoFar / finalizeNdjsonStreamingReply, and
  // replaced with the failure message on network/server errors or timeout.
  armPendingNewsStatusBubble(text);
  try {
    await flushWorkChecklistSyncBeforeCommand();
    const textFetchStart = performance.now();
    /* PART 10/11: attach a client-side request_id so the dev console can
       pair frontend logs with backend [REQ start]/[REQ end] lines. Server
       still generates its own (returned in `request_id` on the response). */
    const _textClientRequestId = recordVeraRequestId("text", newVeraRequestId());
    logTurnTextIntegrity({
      source: "typed",
      raw_asr_text: null,
      normalized_text: text,
      router_input_text: text,
      backend_payload_text: text,
      request_id: _textClientRequestId,
      path: "typed-text",
    });
    const res = await fetch(`${API_URL}/text`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "X-Vera-Request-Id": _textClientRequestId,
        "X-Vera-Session-Id": getSessionId(),
      },
      body: JSON.stringify({
        text,
        session_id: getSessionId(),
        client: appModePrefix(),
        stream_tts: shouldStreamTts(),
        context_snapshot: buildClientContextSnapshot(),
        client_request_id: _textClientRequestId
      }),
      signal: attachPipelineAbortSignal()
    });
    const textTtfbMs = performance.now() - textFetchStart;

    if (shouldStreamTts() && res.ok && isNdjsonTtsResponse(res)) {
      requestInFlight = false;

      let ndjsonMeta = null;
      const streamReplyState = createNdjsonStreamingReplyState();
      void (async () => {
        try {
          console.log("[UX][TTS] NDJSON streaming (text)");
          resetAudioHandlers();
          await runNdjsonTtsPlayback(res, {
            onMeta: (meta) => {
              ndjsonMeta = { ...ndjsonMeta, ...meta };
              if (
                !streamReplyState.pendingReplyBack &&
                meta.work_mode_voice_brief_completion === true &&
                meta.work_mode_voice_quote != null &&
                String(meta.work_mode_voice_quote).trim()
              ) {
                const q = String(meta.work_mode_voice_quote).trim();
                streamReplyState.pendingVoiceQuote = q;
                streamReplyState.pendingReplyBack = {
                  reply_to_user_text: q,
                  reply_to_turn_id: "",
                  reply_to_lane_id: "",
                  reply_to_lane_title: "",
                  stage: 2
                };
              }
              if (meta.work_mode_timer) {
                applyWorkModeTimerPayload(meta.work_mode_timer);
              }
            },
            onReplyProgress: (replySoFar) => {
              applyNdjsonStreamingReplySoFar(replySoFar, streamReplyState);
            },
            onDone: (done) => {
              logInferLatency(done, "text", textTtfbMs);
              finalizeNdjsonStreamingReply(ndjsonMeta, done, streamReplyState);
              applyNdjsonActionPayloadEvent(done, "done");
            },
            onPlayStart: () => {
              logTextFirstAudio("main-reply");
              logTextMainReplyAudio();
              applyNdjsonActionPayloadEvent(ndjsonMeta, "meta");
              waveState = "speaking";
              audioStartedAt = performance.now();
              resetVadFastStopState("text_tts_start_action");
              setStatus(
                listeningMode === "ptt" ? "Speaking" : "Speaking…",
                "speaking"
              );
            },
            onPlayEnd: () => {
              resumeAfterAssistantReplyPlayback();
            }
          });
        } catch (e) {
          if (e?.name !== "AbortError") console.warn(e);
        }
      })();
      return;
    }

    const data = await res.json();
    logInferLatency(data, "text", textTtfbMs);

    requestInFlight = false;
    applyClientUiAction(data.client_action);

    const playReply = () => {
      resetAudioHandlers();
      void (async () => {
        try {
          await playTtsFromApi(data, {
            onPlayStart: () => {
              logTextFirstAudio("main-reply");
              logTextMainReplyAudio();
              applyAssistantReplyAndPanels(data);
              waveState = "speaking";
              audioStartedAt = performance.now();
              resetVadFastStopState("text_tts_start");
              setStatus(
                listeningMode === "ptt" ? "Speaking" : "Speaking…",
                "speaking"
              );
            },
            onPlayEnd: () => {
              resumeAfterAssistantReplyPlayback();
            }
          });
        } catch (e) {
          console.warn(e);
        }
      })();
    };

    playReply();

  } catch (err) {
    if (err?.name === "AbortError") {
      requestInFlight = false;
      processing = false;
      textUxTurn = null;
      cancelPendingNewsStatusBubble("abort");
      return;
    }
    console.error(err);
    hideSidePanel();
    requestInFlight = false;
    processing = false;
    textUxTurn = null;
    setStatus("Server error", "offline");
    // If we had armed a "Searching news…" bubble, swap it for the standard
    // search/news failure copy (one specific bubble is better than two).
    // If no pending bubble was armed, fall back to the generic LLM-failure
    // bubble so the user still sees something.
    if (!failPendingNewsStatusBubble("text_endpoint_error")) {
      void veraSurfaceLlmFetchFailure({ feature: "text_endpoint", error: err });
    }
  }
}

